  };

  const getNotificationIcon = (type: string) => {
    const iconMap = {
      post_created: '≡ƒô¥',
      post_liked: '≡ƒæì',
      post_disliked: '≡ƒæÄ',
      post_commented: '≡ƒÆ¼',
      comment_liked: '≡ƒæì',
      comment_disliked: '≡ƒæÄ',
      user_joined_group: '≡ƒæÑ',
      group_created: '≡ƒÅù∩╕Å',
    };
    return iconMap[type as keyof typeof iconMap] || '≡ƒöö';
  };

  const getNotificationColor = (type: string) => {
    const colorMap = {
      post_created: 'text-blue-600',
      post_liked: 'text-green-600',
      post_disliked: 'text-red-600',
      post_commented: 'text-purple-600',
      comment_liked: 'text-green-600',
      comment_disliked: 'text-red-600',
      user_joined_group: 'text-blue-600',
      group_created: 'text-indigo-600',
    };
    return colorMap[type as keyof typeof colorMap] || 'text-gray-600';
  };

  const formatTime = (timestamp: number) => {
    const now = Date.now();
    const diffInSeconds = Math.floor((now - timestamp) / 1000);

    if (diffInSeconds < 60) {
      return 'Just now';
    } else if (diffInSeconds < 3600) {
      const minutes = Math.floor(diffInSeconds / 60);
      return `${minutes}m ago`;
    } else if (diffInSeconds < 86400) {
      const hours = Math.floor(diffInSeconds / 3600);
      return `${hours}h ago`;
    } else if (diffInSeconds < 604800) {
      const days = Math.floor(diffInSeconds / 86400);
      return `${days}d ago`;
    } else {
      return new Date(timestamp).toLocaleDateString();
    }
  };

  if (!isOpen) return null;

