import React, { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { Loader2 } from 'lucide-react';
import type { Tables, TablesInsert } from '@/integrations/supabase/types';

type Faculty = Tables<'faculty'>;
type FacultyInsert = TablesInsert<'faculty'>;

interface FacultyFormProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  faculty?: Faculty | null;
  onSave: () => void;
}

const FacultyForm: React.FC<FacultyFormProps> = ({
  open,
  onOpenChange,
  faculty,
  onSave,
}) => {
  const [formData, setFormData] = useState<FacultyInsert>({
    name: '',
    email: '',
    department: '',
    designation: '',
    faculty_code: '',
    phone: '',
    specialization: '',
    is_verified: false,
  });
  const [loading, setLoading] = useState(false);
  const { toast } = useToast();

  const departments = [
    'Computer Science',
    'Information Technology',
    'Electrical Engineering',
    'Mechanical Engineering',
    'Civil Engineering',
    'Chemical Engineering',
    'Mathematics',
    'Physics',
    'Chemistry',
    'Biology',
    'Business Administration',
    'Economics',
    'Psychology',
    'English',
    'History',
  ];

  const designations = [
    'Professor',
    'Associate Professor',
    'Assistant Professor',
    'Lecturer',
    'Senior Lecturer',
    'Visiting Professor',
    'Adjunct Professor',
  ];

  useEffect(() => {
    if (faculty) {
      setFormData({
        name: faculty.name,
        email: faculty.email,
        department: faculty.department,
        designation: faculty.designation,
        is_verified: faculty.is_verified,
      });
    } else {
      setFormData({
        name: '',
        email: '',
        department: '',
        designation: '',
        is_verified: false,
      });
    }
  }, [faculty, open]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      if (faculty) {
        // Update existing faculty
        const { error } = await supabase
          .from('faculty')
          .update(formData)
          .eq('id', faculty.id);

        if (error) throw error;

        toast({
          title: 'Success',
          description: 'Faculty member updated successfully',
        });
      } else {
        // Create new faculty
        const { error } = await supabase.from('faculty').insert([formData]);

        if (error) throw error;

        toast({
          title: 'Success',
          description: 'Faculty member added successfully',
        });
      }

      onSave();
      onOpenChange(false);
    } catch (error: any) {
      console.error('Error saving faculty:', error);
      toast({
        title: 'Error',
        description: error.message || 'Failed to save faculty member',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (
    field: keyof FacultyInsert,
    value: string | boolean
  ) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className='sm:max-w-md'>
        <DialogHeader>
          <DialogTitle>
            {faculty ? 'Edit Faculty Member' : 'Add New Faculty Member'}
          </DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit} className='space-y-4'>
          <div className='space-y-2'>
            <Label htmlFor='name'>Full Name</Label>
            <Input
              id='name'
              value={formData.name}
              onChange={e => handleChange('name', e.target.value)}
              placeholder='Enter full name'
              required
            />
          </div>

          <div className='space-y-2'>
            <Label htmlFor='email'>Email Address</Label>
            <Input
              id='email'
              type='email'
              value={formData.email}
              onChange={e => handleChange('email', e.target.value)}
              placeholder='Enter email address'
              required
            />
          </div>

          <div className='space-y-2'>
            <Label htmlFor='department'>Department</Label>
            <Select
              value={formData.department}
              onValueChange={value => handleChange('department', value)}
              required
            >
              <SelectTrigger>
                <SelectValue placeholder='Select department' />
              </SelectTrigger>
              <SelectContent>
                {departments.map(dept => (
                  <SelectItem key={dept} value={dept}>
                    {dept}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className='space-y-2'>
            <Label htmlFor='designation'>Designation</Label>
            <Select
              value={formData.designation}
              onValueChange={value => handleChange('designation', value)}
              required
            >
              <SelectTrigger>
                <SelectValue placeholder='Select designation' />
              </SelectTrigger>
              <SelectContent>
                {designations.map(designation => (
                  <SelectItem key={designation} value={designation}>
                    {designation}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className='space-y-2'>
            <Label htmlFor='faculty_code'>Faculty Code</Label>
            <Input
              id='faculty_code'
              value={formData.faculty_code}
              onChange={e => handleChange('faculty_code', e.target.value)}
              placeholder='e.g., CS001, IT002'
              required
            />
          </div>

          <div className='space-y-2'>
            <Label htmlFor='phone'>Phone Number</Label>
            <Input
              id='phone'
              value={formData.phone}
              onChange={e => handleChange('phone', e.target.value)}
              placeholder='Enter phone number'
            />
          </div>

          <div className='space-y-2'>
            <Label htmlFor='specialization'>Specialization</Label>
            <Textarea
              id='specialization'
              value={formData.specialization}
              onChange={e => handleChange('specialization', e.target.value)}
              placeholder='Enter areas of specialization'
              rows={3}
            />
          </div>

          <DialogFooter>
            <Button
              type='button'
              variant='outline'
              onClick={() => onOpenChange(false)}
              disabled={loading}
            >
              Cancel
            </Button>
            <Button type='submit' disabled={loading}>
              {loading ? (
                <>
                  <Loader2 className='h-4 w-4 mr-2 animate-spin' />
                  {faculty ? 'Updating...' : 'Adding...'}
                </>
              ) : faculty ? (
                'Update Faculty'
              ) : (
                'Add Faculty'
              )}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
};

export default FacultyForm;

import React, { useState, useRef, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
  MessageCircle,
  Send,
  Bot,
  User,
  X,
  Minimize2,
  Maximize2,
  Loader2,
  AlertCircle,
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';

interface Message {
  id: string;
  type: 'user' | 'bot';
  content: string;
  timestamp: Date;
}

interface ProjectChatbotProps {
  isOpen: boolean;
  onToggle: () => void;
  isMinimized: boolean;
  onMinimize: () => void;
}

const ProjectChatbot: React.FC<ProjectChatbotProps> = ({
  isOpen,
  onToggle,
  isMinimized,
  onMinimize,
}) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      type: 'bot',
      content:
        "Hi! I'm your Student Achievement Platform assistant. I can help you with questions about uploading certificates, tracking achievements, understanding the point system, and using the platform features. How can I help you today?",
      timestamp: new Date(),
    },
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const { toast } = useToast();

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const systemPrompt = `You are a helpful assistant for a Student Achievement Platform. This platform helps students:

1. Upload and track academic certificates, course completions, and achievements
2. Earn points and level up based on their activities
3. Build a comprehensive digital portfolio
4. Connect with peers and see their achievements
5. Get faculty approval for uploaded documents

ONLY answer questions related to:
- How to upload certificates and documents
- Understanding the point system and levels
- Using the achievement tracking features
- Platform navigation and features
- Student dashboard functionality
- Profile management
- Social features and peer connections
- Faculty approval process
- Portfolio building
- Goal setting and tracking

DO NOT answer questions about:
- General programming or coding
- Other platforms or services
- Personal advice unrelated to the platform
- Technical support for other software
- General knowledge questions

If asked about something unrelated to the Student Achievement Platform, politely redirect them back to platform-related questions.

Keep responses concise, helpful, and focused on the platform features.`;

  const sendMessage = async () => {
    if (!inputMessage.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      type: 'user',
      content: inputMessage,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInputMessage('');
    setIsLoading(true);
    setError(null);

    try {
      const response = await fetch(
        'https://openrouter.ai/api/v1/chat/completions',
        {
          method: 'POST',
          headers: {
            Authorization:
              'Bearer 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',
            'Content-Type': 'application/json',
            'HTTP-Referer': window.location.origin,
            'X-Title': 'Student Achievement Platform',
          },
          body: JSON.stringify({
            model: 'microsoft/wizardlm-2-8x22b',
            messages: [
              { role: 'system', content: systemPrompt },
              ...messages.map(msg => ({
                role: msg.type === 'user' ? 'user' : 'assistant',
                content: msg.content,
              })),
              { role: 'user', content: inputMessage },
            ],
            max_tokens: 500,
            temperature: 0.7,
          }),
        }
      );

      if (!response.ok) {
        throw new Error(`API Error: ${response.status}`);
      }

      const data = await response.json();
      const botMessage: Message = {
        id: (Date.now() + 1).toString(),
        type: 'bot',
        content:
          data.choices[0]?.message?.content ||
          'Sorry, I could not process your request.',
        timestamp: new Date(),
      };

      setMessages(prev => [...prev, botMessage]);
    } catch (err) {
      console.error('Chatbot error:', err);
      setError('Failed to get response. Please try again.');

      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        type: 'bot',
        content:
          'Sorry, I encountered an error. Please try again or contact support if the issue persists.',
        timestamp: new Date(),
      };

      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const clearChat = () => {
    setMessages([
      {
        id: '1',
        type: 'bot',
        content:
          "Hi! I'm your Student Achievement Platform assistant. I can help you with questions about uploading certificates, tracking achievements, understanding the point system, and using the platform features. How can I help you today?",
        timestamp: new Date(),
      },
    ]);
  };

  if (!isOpen) return null;

  return (
    <div
      className={`fixed bottom-4 right-4 z-50 ${isMinimized ? 'w-80' : 'w-96'} transition-all duration-300`}
    >
      <Card className='shadow-2xl border-2'>
        <CardHeader className='pb-3'>
          <div className='flex items-center justify-between'>
            <div className='flex items-center gap-2'>
              <div className='p-2 bg-blue-500 rounded-full'>
                <Bot className='h-4 w-4 text-white' />
              </div>
              <div>
                <CardTitle className='text-sm'>Platform Assistant</CardTitle>
                <Badge variant='secondary' className='text-xs'>
                  Student Achievement Platform
                </Badge>
              </div>
            </div>
            <div className='flex items-center gap-1'>
              <Button
                variant='ghost'
                size='sm'
                onClick={onMinimize}
                className='h-6 w-6 p-0'
              >
                {isMinimized ? (
                  <Maximize2 className='h-3 w-3' />
                ) : (
                  <Minimize2 className='h-3 w-3' />
                )}
              </Button>
              <Button
                variant='ghost'
                size='sm'
                onClick={onToggle}
                className='h-6 w-6 p-0'
              >
                <X className='h-3 w-3' />
              </Button>
            </div>
          </div>
        </CardHeader>

        {!isMinimized && (
          <CardContent className='p-0'>
            <ScrollArea className='h-80 px-4'>
              <div className='space-y-4 py-2'>
                {messages.map(message => (
                  <div
                    key={message.id}
                    className={`flex gap-2 ${message.type === 'user' ? 'justify-end' : 'justify-start'}`}
                  >
                    {message.type === 'bot' && (
                      <div className='p-1 bg-blue-100 rounded-full'>
                        <Bot className='h-3 w-3 text-blue-600' />
                      </div>
                    )}
                    <div
                      className={`max-w-[80%] p-3 rounded-lg text-sm ${
                        message.type === 'user'
                          ? 'bg-blue-500 text-white'
                          : 'bg-gray-100 text-gray-900'
                      }`}
                    >
                      <p className='whitespace-pre-wrap'>{message.content}</p>
                      <p
                        className={`text-xs mt-1 ${
                          message.type === 'user'
                            ? 'text-blue-100'
                            : 'text-gray-500'
                        }`}
                      >
                        {message.timestamp.toLocaleTimeString()}
                      </p>
                    </div>
                    {message.type === 'user' && (
                      <div className='p-1 bg-gray-100 rounded-full'>
                        <User className='h-3 w-3 text-gray-600' />
                      </div>
                    )}
                  </div>
                ))}

                {isLoading && (
                  <div className='flex gap-2 justify-start'>
                    <div className='p-1 bg-blue-100 rounded-full'>
                      <Bot className='h-3 w-3 text-blue-600' />
                    </div>
                    <div className='bg-gray-100 p-3 rounded-lg'>
                      <Loader2 className='h-4 w-4 animate-spin' />
                    </div>
                  </div>
                )}

                {error && (
                  <div className='flex gap-2 justify-start'>
                    <div className='p-1 bg-red-100 rounded-full'>
                      <AlertCircle className='h-3 w-3 text-red-600' />
                    </div>
                    <div className='bg-red-50 p-3 rounded-lg text-red-700 text-sm'>
                      {error}
                    </div>
                  </div>
                )}

                <div ref={messagesEndRef} />
              </div>
            </ScrollArea>

            <div className='p-4 border-t'>
              <div className='flex gap-2'>
                <Input
                  value={inputMessage}
                  onChange={e => setInputMessage(e.target.value)}
                  onKeyPress={handleKeyPress}
                  placeholder='Ask about the platform...'
                  disabled={isLoading}
                  className='flex-1'
                />
                <Button
                  onClick={sendMessage}
                  disabled={!inputMessage.trim() || isLoading}
                  size='sm'
                >
                  <Send className='h-4 w-4' />
                </Button>
              </div>
              <div className='flex justify-between items-center mt-2'>
                <p className='text-xs text-gray-500'>
                  Ask about certificates, achievements, points, or platform
                  features
                </p>
                <Button
                  variant='ghost'
                  size='sm'
                  onClick={clearChat}
                  className='text-xs h-6 px-2'
                >
                  Clear Chat
                </Button>
              </div>
            </div>
          </CardContent>
        )}
      </Card>
    </div>
  );
};

export default ProjectChatbot;

import React, { useState } from 'react';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Upload, X } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';

interface UploadCertificateFormProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (certificateData: any) => void;
}

const UploadCertificateForm: React.FC<UploadCertificateFormProps> = ({
  isOpen,
  onClose,
  onSubmit,
}) => {
  const { toast } = useToast();
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: '',
    subcategory: '',
    issuingCompany: '',
    customReviewer: '',
    file: null as File | null,
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  // Main categories
  const mainCategories = [
    'Academic',
    'Co-Curricular',
    'Verified Professional Certificates',
  ];

  // Subcategories based on main category
  const getSubcategories = (category: string) => {
    switch (category) {
      case 'Academic':
        return [
          'Professional',
          'National',
          'State',
          'International',
          'Co-Curricular',
          'Volunteer / Social Work',
          'Workshops / Training',
          'Others',
        ];
      case 'Co-Curricular':
        return [
          'National',
          'State',
          'International',
          'Volunteer / Social Work',
          'Workshops / Training',
          'Others',
        ];
      case 'Verified Professional Certificates':
        return []; // No subcategories for this
      default:
        return [];
    }
  };

  // Issuing companies for Verified Professional Certificates
  const issuingCompanies = [
    'Google',
    'Microsoft',
    'LinkedIn',
    'AWS',
    'Coursera',
    'Udemy',
  ];

  // Reviewer assignment logic
  const getReviewers = (subcategory: string) => {
    switch (subcategory) {
      case 'Professional':
        return ['Dr. Ramesh Sharma', 'Prof. Anjali Mehta', 'Dr. Suresh Iyer'];
      case 'National':
        return ['Dr. A.K. Singh', 'Prof. Neha Kapoor'];
      case 'State':
        return ['Dr. Vijay Deshmukh', 'Prof. Meera Rathi'];
      case 'International':
        return ['Dr. Sanjay Malhotra', 'Prof. Priya Bansal'];
      case 'Co-Curricular':
        return ['Nikhil Joshi', 'Pooja Menon'];
      case 'Volunteer / Social Work':
        return ['Amit Tiwari', 'Ritu Sinha'];
      case 'Workshops / Training':
        return ['Deepak Kumar', 'Shalini Pandey'];
      case 'Others':
        return []; // Custom input
      default:
        return [];
    }
  };

  const handleCategoryChange = (category: string) => {
    setFormData(prev => ({
      ...prev,
      category,
      subcategory: '',
      issuingCompany: '',
      customReviewer: '',
    }));
    setErrors(prev => ({ ...prev, category: '' }));
  };

  const handleSubcategoryChange = (subcategory: string) => {
    setFormData(prev => ({
      ...prev,
      subcategory,
      customReviewer: '',
    }));
    setErrors(prev => ({ ...prev, subcategory: '' }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Validate file type
      const allowedTypes = [
        'application/pdf',
        'image/jpeg',
        'image/jpg',
        'image/png',
      ];
      if (!allowedTypes.includes(file.type)) {
        setErrors(prev => ({
          ...prev,
          file: 'Please upload a PDF or image file (JPEG, PNG)',
        }));
        return;
      }
      // Validate file size (5MB max)
      if (file.size > 5 * 1024 * 1024) {
        setErrors(prev => ({
          ...prev,
          file: 'File size must be less than 5MB',
        }));
        return;
      }
      setFormData(prev => ({ ...prev, file }));
      setErrors(prev => ({ ...prev, file: '' }));
    }
  };

  const validateForm = () => {
    const newErrors: Record<string, string> = {};

    if (!formData.title.trim())
      newErrors.title = 'Certificate title is required';
    if (!formData.category) newErrors.category = 'Please select a category';
    if (
      formData.category !== 'Verified Professional Certificates' &&
      !formData.subcategory
    ) {
      newErrors.subcategory = 'Please select a subcategory';
    }
    if (
      formData.category === 'Verified Professional Certificates' &&
      !formData.issuingCompany
    ) {
      newErrors.issuingCompany = 'Please select an issuing company';
    }
    if (formData.subcategory === 'Others' && !formData.customReviewer.trim()) {
      newErrors.customReviewer = 'Please enter a reviewer name';
    }
    if (!formData.file) newErrors.file = 'Please upload a certificate file';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      toast({
        title: 'Validation Error',
        description: 'Please fill in all required fields correctly.',
        variant: 'destructive',
      });
      return;
    }

    // Determine reviewer
    let reviewer = '';
    if (formData.subcategory === 'Others') {
      reviewer = formData.customReviewer;
    } else {
      const reviewers = getReviewers(formData.subcategory);
      reviewer = reviewers.length > 0 ? reviewers[0] : 'Pending Assignment';
    }

    const certificateData = {
      ...formData,
      reviewer,
      status: 'Pending' as const,
      uploadedAt: new Date().toISOString(),
    };

    onSubmit(certificateData);

    // Reset form
    setFormData({
      title: '',
      description: '',
      category: '',
      subcategory: '',
      issuingCompany: '',
      customReviewer: '',
      file: null,
    });
    setErrors({});

    toast({
      title: 'Success',
      description: 'Certificate uploaded successfully!',
    });

    onClose();
  };

  const currentSubcategories = getSubcategories(formData.category);
  const currentReviewers = formData.subcategory
    ? getReviewers(formData.subcategory)
    : [];

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className='max-w-2xl max-h-[90vh] overflow-y-auto'>
        <DialogHeader>
          <DialogTitle className='text-xl font-semibold text-blue-900'>
            Upload New Certificate
          </DialogTitle>
          <DialogDescription>
            Fill in the details below to upload your certificate for review.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className='space-y-6'>
          {/* Certificate Title */}
          <div className='space-y-2'>
            <Label
              htmlFor='title'
              className='text-sm font-medium text-gray-700'
            >
              Certificate Title *
            </Label>
            <Input
              id='title'
              value={formData.title}
              onChange={e =>
                setFormData(prev => ({ ...prev, title: e.target.value }))
              }
              placeholder='Enter certificate title'
              className={errors.title ? 'border-red-500' : ''}
            />
            {errors.title && (
              <p className='text-sm text-red-600'>{errors.title}</p>
            )}
          </div>

          {/* Description */}
          <div className='space-y-2'>
            <Label
              htmlFor='description'
              className='text-sm font-medium text-gray-700'
            >
              Description
            </Label>
            <Textarea
              id='description'
              value={formData.description}
              onChange={e =>
                setFormData(prev => ({ ...prev, description: e.target.value }))
              }
              placeholder='Brief description of the certificate (optional)'
              rows={3}
            />
          </div>

          {/* Main Category */}
          <div className='space-y-2'>
            <Label className='text-sm font-medium text-gray-700'>
              Category *
            </Label>
            <Select
              value={formData.category}
              onValueChange={handleCategoryChange}
            >
              <SelectTrigger
                className={errors.category ? 'border-red-500' : ''}
              >
                <SelectValue placeholder='Select a category' />
              </SelectTrigger>
              <SelectContent>
                {mainCategories.map(category => (
                  <SelectItem key={category} value={category}>
                    {category}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            {errors.category && (
              <p className='text-sm text-red-600'>{errors.category}</p>
            )}
          </div>

          {/* Subcategory or Issuing Company */}
          {formData.category === 'Verified Professional Certificates' ? (
            <div className='space-y-2'>
              <Label className='text-sm font-medium text-gray-700'>
                Issuing Company *
              </Label>
              <Select
                value={formData.issuingCompany}
                onValueChange={value =>
                  setFormData(prev => ({ ...prev, issuingCompany: value }))
                }
              >
                <SelectTrigger
                  className={errors.issuingCompany ? 'border-red-500' : ''}
                >
                  <SelectValue placeholder='Select issuing company' />
                </SelectTrigger>
                <SelectContent>
                  {issuingCompanies.map(company => (
                    <SelectItem key={company} value={company}>
                      {company}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {errors.issuingCompany && (
                <p className='text-sm text-red-600'>{errors.issuingCompany}</p>
              )}
            </div>
          ) : (
            formData.category && (
              <div className='space-y-2'>
                <Label className='text-sm font-medium text-gray-700'>
                  Subcategory *
                </Label>
                <Select
                  value={formData.subcategory}
                  onValueChange={handleSubcategoryChange}
                >
                  <SelectTrigger
                    className={errors.subcategory ? 'border-red-500' : ''}
                  >
                    <SelectValue placeholder='Select a subcategory' />
                  </SelectTrigger>
                  <SelectContent>
                    {currentSubcategories.map(subcategory => (
                      <SelectItem key={subcategory} value={subcategory}>
                        {subcategory}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {errors.subcategory && (
                  <p className='text-sm text-red-600'>{errors.subcategory}</p>
                )}
              </div>
            )
          )}

          {/* Custom Reviewer for "Others" */}
          {formData.subcategory === 'Others' && (
            <div className='space-y-2'>
              <Label
                htmlFor='customReviewer'
                className='text-sm font-medium text-gray-700'
              >
                Reviewer Name *
              </Label>
              <Input
                id='customReviewer'
                value={formData.customReviewer}
                onChange={e =>
                  setFormData(prev => ({
                    ...prev,
                    customReviewer: e.target.value,
                  }))
                }
                placeholder='Enter reviewer name'
                className={errors.customReviewer ? 'border-red-500' : ''}
              />
              {errors.customReviewer && (
                <p className='text-sm text-red-600'>{errors.customReviewer}</p>
              )}
            </div>
          )}

          {/* Assigned Reviewer Display */}
          {formData.subcategory &&
            formData.subcategory !== 'Others' &&
            currentReviewers.length > 0 && (
              <div className='p-4 bg-blue-50 border border-blue-200 rounded-lg'>
                <Label className='text-sm font-medium text-blue-900'>
                  Assigned Reviewer
                </Label>
                <p className='text-sm text-blue-700 mt-1'>
                  {currentReviewers[0]}
                </p>
              </div>
            )}

          {/* File Upload */}
          <div className='space-y-2'>
            <Label className='text-sm font-medium text-gray-700'>
              Upload Certificate *
            </Label>
            <div className='border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-blue-400 transition-colors'>
              <input
                type='file'
                accept='.pdf,.jpg,.jpeg,.png'
                onChange={handleFileChange}
                className='hidden'
                id='certificate-file'
              />
              <label htmlFor='certificate-file' className='cursor-pointer'>
                <Upload className='h-8 w-8 text-gray-400 mx-auto mb-2' />
                <p className='text-sm text-gray-600'>
                  Click to upload or drag and drop
                </p>
                <p className='text-xs text-gray-500 mt-1'>
                  PDF or image files (max 5MB)
                </p>
              </label>
              {formData.file && (
                <div className='mt-4 flex items-center justify-center gap-2'>
                  <span className='text-sm text-green-600'>
                    {formData.file.name}
                  </span>
                  <Button
                    type='button'
                    variant='ghost'
                    size='sm'
                    onClick={() =>
                      setFormData(prev => ({ ...prev, file: null }))
                    }
                  >
                    <X className='h-4 w-4' />
                  </Button>
                </div>
              )}
            </div>
            {errors.file && (
              <p className='text-sm text-red-600'>{errors.file}</p>
            )}
          </div>

          {/* Submit Buttons */}
          <div className='flex gap-3 pt-4'>
            <Button
              type='button'
              variant='outline'
              onClick={onClose}
              className='flex-1'
            >
              Cancel
            </Button>
            <Button
              type='submit'
              className='flex-1 bg-blue-600 hover:bg-blue-700 text-white'
            >
              Upload Certificate
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
};

export default UploadCertificateForm;

import React, { useState, useEffect } from 'react';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import { useProfile } from '@/hooks/useProfile';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/integrations/supabase/client';
import {
  CheckCircle,
  XCircle,
  Clock,
  Users,
  FileText,
  MessageSquare,
  BookOpen,
  ExternalLink,
} from 'lucide-react';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import MonitoringSection from './faculty/MonitoringSection';
import StudentManagement from './faculty/StudentManagement';
import CourseAssignment from './faculty/CourseAssignment';
import { IssueCredentialModal } from '../verifiableCredentials/IssueCredentialModal';
import { FacultyCredentials } from '../verifiableCredentials/FacultyCredentials';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { useNavigate } from 'react-router-dom';

interface Certificate {
  id: string;
  title: string;
  description: string;
  category: 'academic' | 'co_curricular';
  status: 'pending' | 'approved' | 'rejected';
  file_url: string;
  file_name: string;
  uploaded_at: string;
  rejection_reason?: string;
  remark?: string;
  student: {
    id: string;
    full_name: string;
    email: string;
    student_id?: string;
  };
}

interface Student {
  id: string;
  full_name: string;
  email: string;
  student_id?: string;
}

interface Course {
  id: string;
  name: string;
  course_code: string;
  faculty_id: string | null;
  thumbnail_url?: string | null;
  description?: string | null;
  external_link?: string | null;
}

const FacultyDashboard = () => {
  const { profile } = useProfile();
  const { toast } = useToast();
  const [certificates, setCertificates] = useState<Certificate[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [courses, setCourses] = useState<Course[]>([]);
  const [loading, setLoading] = useState(false);
  const [processingCert, setProcessingCert] = useState<string | null>(null);
  const [remarks, setRemarks] = useState<Record<string, string>>({});
  const [useMock, setUseMock] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    if (profile) {
      if (useMock) {
        mockFetchCertificates();
        mockFetchStudents();
      } else {
        fetchCertificates();
        fetchStudents();
        fetchCourses();
      }
    }
  }, [profile, useMock]);

  const mockDelay = (ms: number) => new Promise(res => setTimeout(res, ms));

  const mockFetchCertificates = async () => {
    setLoading(true);
    await mockDelay(500);
    const data: Certificate[] = [
      {
        id: 'mock-1',
        title: 'National Science Fair',
        description: 'Participation certificate',
        category: 'co_curricular',
        status: 'pending',
        file_url: 'https://example.com/cert1.pdf',
        file_name: 'cert1.pdf',
        uploaded_at: new Date(Date.now() - 86400000).toISOString(),
        student: {
          id: 'stu-1',
          full_name: 'Alice Johnson',
          email: 'alice@example.edu',
          student_id: '2021-CSE-034',
        },
      },
      {
        id: 'mock-2',
        title: 'B.Tech Degree',
        description: 'Verified by registrar',
        category: 'academic',
        status: 'approved',
        file_url: 'https://example.com/cert2.pdf',
        file_name: 'cert2.pdf',
        uploaded_at: new Date(Date.now() - 172800000).toISOString(),
        remark: 'Excellent achievement',
        student: {
          id: 'stu-2',
          full_name: 'Bob Smith',
          email: 'bob@example.edu',
          student_id: '2020-EEE-112',
        },
      },
      {
        id: 'mock-3',
        title: 'Hackathon Winner',
        description: 'First place',
        category: 'co_curricular',
        status: 'rejected',
        file_url: 'https://example.com/cert3.pdf',
        file_name: 'cert3.pdf',
        uploaded_at: new Date(Date.now() - 259200000).toISOString(),
        rejection_reason: 'Illegible scan',
        remark: 'Please re-upload a clearer copy',
        student: {
          id: 'stu-3',
          full_name: 'Carol Danvers',
          email: 'carol@example.edu',
          student_id: '2019-MECH-076',
        },
      },
    ];
    setCertificates(data);
    setLoading(false);
  };

  const fetchCourses = async () => {
    if (!profile) return;

    try {
      // Faculty: show own courses; Senior/Admin could see all, but we filter to own here
      const { data, error } = await supabase
        .from('courses')
        .select('*')
        .eq('faculty_id', profile.id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setCourses((data as Course[]) || []);
    } catch (err) {
      console.error('Error fetching courses:', err);
    }
  };

  const fetchCertificates = async () => {
    if (!profile) return;

    if (useMock) {
      await mockFetchCertificates();
      return;
    }

    setLoading(true);
    try {
      let filterIds: string[] | null = null;
      if (
        profile.faculty_level !== 'senior' &&
        profile.faculty_level !== 'admin'
      ) {
        // Get assigned students through the student_mentor_assignments table
        const { data: facultyData, error: facultyError } = await supabase
          .from('faculty')
          .select('id')
          .eq('email', profile.email)
          .single();

        if (facultyError || !facultyData) {
          console.log('No faculty record found, showing no certificates');
          setCertificates([]);
          setLoading(false);
          return;
        }

        const { data: assignmentsData, error: assignmentsError } =
          await supabase
            .from('student_mentor_assignments')
            .select('student_id')
            .eq('mentor_id', facultyData.id);

        if (assignmentsError) {
          console.error('Error fetching assignments:', assignmentsError);
          setCertificates([]);
          setLoading(false);
          return;
        }

        const ids = (assignmentsData || []).map(
          (assignment: any) => assignment.student_id
        );
        filterIds = ids.length ? ids : [];
        if (filterIds.length === 0) {
          setCertificates([]);
          setLoading(false);
          return;
        }
      }

      let query = supabase
        .from('certificates')
        .select(`*, student:student_id ( id, full_name, email, student_id )`)
        .order('uploaded_at', { ascending: false });
      if (filterIds) {
        query = query.in('student_id', filterIds);
      }
      const { data, error } = await query;
      if (error) throw error;
      setCertificates((data as any[]) || []);
    } catch (err) {
      console.error('Error fetching certificates:', err);
      toast({
        title: 'Error',
        description: (err as any)?.message || 'Failed to fetch certificates',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  const mockFetchStudents = async () => {
    await mockDelay(300);
    setStudents([
      {
        id: 'stu-1',
        full_name: 'Alice Johnson',
        email: 'alice@example.edu',
        student_id: '2021-CSE-034',
      },
      {
        id: 'stu-2',
        full_name: 'Bob Smith',
        email: 'bob@example.edu',
        student_id: '2020-EEE-112',
      },
      {
        id: 'stu-3',
        full_name: 'Carol Danvers',
        email: 'carol@example.edu',
        student_id: '2019-MECH-076',
      },
    ]);
  };

  const fetchStudents = async () => {
    if (!profile) return;

    if (useMock) {
      await mockFetchStudents();
      return;
    }

    try {
      // Get faculty record by email (simpler approach)
      console.log('Looking up faculty by email:', profile.email);
      const { data: facultyData, error: facultyError } = await supabase
        .from('faculty')
        .select('id, email, name, department, designation')
        .eq('email', profile.email)
        .single();

      if (facultyError && facultyError.code === 'PGRST116') {
        // No faculty record found, show helpful message
        console.log('No faculty record found for user');
        toast({
          title: 'Faculty Record Not Found',
          description:
            'No faculty record found for your account. Please contact administrator to set up your faculty profile.',
          variant: 'destructive',
        });
        return;
      }

      if (facultyError) {
        console.error('Error fetching faculty:', facultyError);
        toast({
          title: 'Error fetching faculty',
          description:
            'Failed to load faculty information. Please ensure you are registered as faculty.',
          variant: 'destructive',
        });
        return;
      }

      if (!facultyData) {
        console.error('No faculty record found for user');
        toast({
          title: 'Faculty Not Found',
          description:
            'No faculty record found for your account. Please contact administrator.',
          variant: 'destructive',
        });
        return;
      }

      // Get assigned students through the student_mentor_assignments table
      const { data: assignmentsData, error: assignmentsError } = await supabase
        .from('student_mentor_assignments')
        .select(
          `
          *,
          student:profiles!student_mentor_assignments_student_id_fkey(
            id,
            full_name,
            email,
            student_id,
            department
          )
        `
        )
        .eq('mentor_id', facultyData.id)
        .order('created_at', { ascending: false });

      if (assignmentsError) {
        console.error('Error fetching assignments:', assignmentsError);
        toast({
          title: 'Error fetching students',
          description: 'Failed to load assigned students',
          variant: 'destructive',
        });
        return;
      }

      // Extract students from assignments
      const studentsData =
        assignmentsData
          ?.map(assignment => assignment.student)
          .filter(Boolean) || [];
      setStudents(studentsData as Student[]);
    } catch (err) {
      console.error('Error fetching students:', err);
      toast({
        title: 'Error fetching students',
        description: (err as any)?.message || JSON.stringify(err),
        variant: 'destructive',
      });
    }
  };

  const handleCertificateAction = async (
    certificateId: string,
    action: 'approve' | 'reject',
    reason: string
  ) => {
    if (!reason || !reason.trim()) {
      toast({
        title: 'Remark required',
        description: 'Please provide a remark before proceeding.',
        variant: 'destructive',
      });
      return;
    }

    if (useMock) {
      setProcessingCert(certificateId);
      try {
        await mockDelay(700);
        setCertificates(prev =>
          prev.map(c =>
            c.id === certificateId
              ? {
                  ...c,
                  status: action === 'approve' ? 'approved' : 'rejected',
                  remark: reason,
                  rejection_reason:
                    action === 'reject' ? reason : c.rejection_reason,
                }
              : c
          )
        );
        toast({
          title: 'Success',
          description: `Certificate ${action}ed successfully!`,
        });
        setRemarks(prev => ({ ...prev, [certificateId]: '' }));
      } catch (e: any) {
        toast({
          title: 'Error',
          description: e?.message || 'Mock request failed',
          variant: 'destructive',
        });
      } finally {
        setProcessingCert(null);
      }
      return;
    }

    setProcessingCert(certificateId);
    try {
      const updates: any = {
        status: action === 'approve' ? 'approved' : 'rejected',
        verified_by: profile?.id,
        verified_at: new Date().toISOString(),
        remark: reason,
      };

      if (action === 'reject' && reason) {
        updates.rejection_reason = reason;
      }

      const { error } = await supabase
        .from('certificates')
        .update(updates)
        .eq('id', certificateId);
      if (error) throw error;

      toast({
        title: 'Success',
        description: `Certificate ${action}ed successfully!`,
      });

      // Refresh certificates
      fetchCertificates();
      setRemarks(prev => ({ ...prev, [certificateId]: '' }));
    } catch (error: any) {
      console.error('Error updating certificate:', error);
      toast({
        title: 'Error',
        description: error.message || `Failed to ${action} certificate`,
        variant: 'destructive',
      });
    } finally {
      setProcessingCert(null);
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'approved':
        return <CheckCircle className='h-4 w-4 text-green-600' />;
      case 'rejected':
        return <XCircle className='h-4 w-4 text-red-600' />;
      default:
        return <Clock className='h-4 w-4 text-yellow-600' />;
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'approved':
        return <Badge className='bg-green-100 text-green-800'>Approved</Badge>;
      case 'rejected':
        return <Badge className='bg-red-100 text-red-800'>Rejected</Badge>;
      default:
        return <Badge className='bg-yellow-100 text-yellow-800'>Pending</Badge>;
    }
  };

  const pendingCertificates = certificates.filter(
    cert => cert.status === 'pending'
  );
  const processedCertificates = certificates.filter(
    cert => cert.status !== 'pending'
  );

  return (
    <div className='max-w-7xl mx-auto p-6 space-y-6'>
      <div className='flex justify-between items-center'>
        <div>
          <h1 className='text-3xl font-bold text-foreground'>
            Faculty Dashboard
          </h1>
          <p className='text-muted-foreground'>
            Welcome back, {profile?.full_name}!
          </p>
        </div>
        <div className='flex items-center space-x-2'>
          <Label htmlFor='mock-mode'>Mock mode</Label>
          <Switch
            id='mock-mode'
            checked={useMock}
            onCheckedChange={setUseMock}
          />
        </div>
      </div>

      {/* Overview Cards */}
      <div className='grid grid-cols-1 md:grid-cols-4 gap-6'>
        <Card>
          <CardHeader className='flex flex-row items-center justify-between space-y-0 pb-2'>
            <CardTitle className='text-sm font-medium'>
              Total Students
            </CardTitle>
            <Users className='h-4 w-4 text-muted-foreground' />
          </CardHeader>
          <CardContent>
            <div className='text-2xl font-bold'>{students.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className='flex flex-row items-center justify-between space-y-0 pb-2'>
            <CardTitle className='text-sm font-medium'>
              Pending Reviews
            </CardTitle>
            <Clock className='h-4 w-4 text-yellow-600' />
          </CardHeader>
          <CardContent>
            <div className='text-2xl font-bold text-yellow-600'>
              {pendingCertificates.length}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className='flex flex-row items-center justify-between space-y-0 pb-2'>
            <CardTitle className='text-sm font-medium'>
              Total Certificates
            </CardTitle>
            <FileText className='h-4 w-4 text-muted-foreground' />
          </CardHeader>
          <CardContent>
            <div className='text-2xl font-bold'>{certificates.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className='flex flex-row items-center justify-between space-y-0 pb-2'>
            <CardTitle className='text-sm font-medium'>Approved</CardTitle>
            <CheckCircle className='h-4 w-4 text-green-600' />
          </CardHeader>
          <CardContent>
            <div className='text-2xl font-bold text-green-600'>
              {certificates.filter(cert => cert.status === 'approved').length}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Main Content */}
      <Tabs defaultValue='pending' className='w-full'>
        <TabsList className='grid w-full grid-cols-7'>
          <TabsTrigger value='pending'>
            Pending Reviews ({pendingCertificates.length})
          </TabsTrigger>
          <TabsTrigger value='processed'>Processed</TabsTrigger>
          <TabsTrigger value='students'>Students</TabsTrigger>
          <TabsTrigger value='monitoring'>Monitoring</TabsTrigger>
          <TabsTrigger value='management'>Management</TabsTrigger>
          <TabsTrigger value='courses'>Courses</TabsTrigger>
          <TabsTrigger value='credentials'>Credentials</TabsTrigger>
        </TabsList>

        <TabsContent value='pending' className='space-y-4'>
          <Card>
            <CardHeader>
              <CardTitle>Pending Certificate Reviews</CardTitle>
              <CardDescription>
                Review and verify student certificates
              </CardDescription>
            </CardHeader>
            <CardContent>
              {loading ? (
                <div className='text-center py-4'>Loading certificates...</div>
              ) : pendingCertificates.length === 0 ? (
                <div className='text-center py-8 text-muted-foreground'>
                  No pending certificates to review
                </div>
              ) : (
                <div className='space-y-4'>
                  {pendingCertificates.map(cert => (
                    <div
                      key={cert.id}
                      className='border rounded-lg p-4 space-y-4'
                    >
                      <div className='flex justify-between items-start'>
                        <div className='flex-1'>
                          <div className='flex items-center space-x-2'>
                            {getStatusIcon(cert.status)}
                            <h3 className='font-semibold'>{cert.title}</h3>
                            {getStatusBadge(cert.status)}
                          </div>
                          <p className='text-sm text-muted-foreground mt-1'>
                            Student: {cert.student.full_name} (
                            {cert.student.email})
                          </p>
