interface Certificate {
  id: string;
  title: string;
  description: string;
  category: 'academic' | 'co_curricular';
  status: 'pending' | 'approved' | 'rejected';
  file_url: string;
  file_name: string;
  uploaded_at: string;
  rejection_reason?: string;
  remark?: string;
}

const StudentDashboard = () => {
  const { profile } = useProfile();
  const {
    progress,
    achievements,
    activities,
    goals,
    connections,
    portfolio,
    recommendations,
    milestones,
    loading: studentLoading,
  } = useStudent();
  const [certificates, setCertificates] = useState<Certificate[]>([]);
  const [loading, setLoading] = useState(false);
  const [showUploadPanel, setShowUploadPanel] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);
  const [certsOpen, setCertsOpen] = useState(false);

  useEffect(() => {
    if (profile) {
      fetchCertificates();
    }
  }, [profile]);

  const fetchCertificates = async () => {
    if (!profile) return;

    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('certificates')
        .select('*')
        .eq('student_id', profile.id)
        .order('uploaded_at', { ascending: false });
      if (error) throw error;
      setCertificates((data as any) || []);
    } catch (error) {
      console.error('Error fetching certificates:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleUploadComplete = async () => {
    await fetchCertificates();
    setShowUploadPanel(false);
  };

  if (loading) {
    return (
      <div className='max-w-7xl mx-auto p-6'>
        <div className='text-center py-8'>
          <div className='animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4'></div>
          <p className='text-muted-foreground'>Loading your dashboard...</p>
        </div>
      </div>
    );
  }

  // Derived stats for visuals
  const total = certificates.length;
  const approved = certificates.filter(c => c.status === 'approved').length;
  const pending = certificates.filter(c => c.status === 'pending').length;
  const rejected = total - approved - pending;

  const last7: { day: string; count: number }[] = (() => {
    const map = new Map<string, number>();
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const key = d.toLocaleDateString(undefined, { weekday: 'short' });
      map.set(key, 0);
    }
    for (const c of certificates) {
      const d = new Date(c.uploaded_at);
      const key = d.toLocaleDateString(undefined, { weekday: 'short' });
      if (map.has(key)) map.set(key, (map.get(key) || 0) + 1);
    }
    return Array.from(map.entries()).map(([day, count]) => ({ day, count }));
  })();

  const weekTotal = last7.reduce((s, x) => s + x.count, 0) || 1;
  const pct = (n: number) => Math.round((n / (total || 1)) * 100);
  const maxCount = Math.max(...last7.map(x => x.count)) || 1;
  const avgCount = weekTotal / (last7.length || 1);

  const CountUp: React.FC<{ to: number; duration?: number }> = ({
    to,
    duration = 800,
  }) => {
    const [val, setVal] = useState(0);
    useEffect(() => {
      let raf = 0;
      const start = performance.now();
      const tick = (now: number) => {
        const p = Math.min(1, (now - start) / duration);
        setVal(Math.round(to * p));
        if (p < 1) raf = requestAnimationFrame(tick);
      };
      raf = requestAnimationFrame(tick);
      return () => cancelAnimationFrame(raf);
    }, [to, duration]);
    return <span>{val}</span>;
  };

  return (
    <div className='max-w-7xl mx-auto p-6 space-y-6'>
      {/* Header */}
      <div className='flex justify-between items-center'>
        <div>
          <h1 className='text-3xl font-bold text-gray-900'>
            Student Dashboard
          </h1>
          <div className='inline-flex items-center gap-3 bg-white rounded-full px-3 py-1 shadow-sm'>
            <span className='text-gray-600 text-sm'>
              Welcome back, {profile?.full_name}!
            </span>
          </div>
        </div>
        <div className='flex items-center gap-3'>
          <Button
            variant='outline'
            size='sm'
            onClick={() => setProfileOpen(true)}
          >
            Profile
          </Button>
          <Button
            variant='outline'
            size='sm'
            onClick={() => setCertsOpen(true)}
          >
            My Certificates
          </Button>
          <Button
            size='sm'
            onClick={() => setShowUploadPanel(v => !v)}
            className='bg-violet-100 hover:bg-violet-200 text-violet-700 border border-violet-200'
          >
            <Upload className='h-4 w-4 mr-2' />
            {showUploadPanel ? 'Close Upload' : 'Upload Certificate'}
          </Button>
          <NotificationsDropdown />
        </div>
      </div>

      {/* Main Dashboard Tabs */}
      <Tabs defaultValue='overview' className='w-full'>
        <TabsList className='grid w-full grid-cols-7'>
          <TabsTrigger value='overview'>Overview</TabsTrigger>
          <TabsTrigger value='progress'>Progress</TabsTrigger>
          <TabsTrigger value='goals'>Goals</TabsTrigger>
          <TabsTrigger value='achievements'>Achievements</TabsTrigger>
          <TabsTrigger value='activity'>Activity</TabsTrigger>
          <TabsTrigger value='recommendations'>Recommendations</TabsTrigger>
          <TabsTrigger value='credentials'>Credentials</TabsTrigger>
        </TabsList>

        {/* Overview Tab */}
        <TabsContent value='overview' className='space-y-6'>
          {/* Academic Achievement Dashboard */}
          <AcademicAchievementDashboard loading={studentLoading} />

          {/* Quick Upload Section */}
          <QuickUpload
            onUploadStart={type => console.log('Upload started:', type)}
            onUploadComplete={handleUploadComplete}
          />

          {/* Progress and Goals */}
          <div className='grid grid-cols-1 lg:grid-cols-2 gap-6'>
            <StudentProgressCard progress={progress} loading={studentLoading} />
            <StudentGoalsCard goals={goals} loading={studentLoading} />
