interface Course {
  id: string;
  name: string;
  course_code: string;
  description?: string;
  external_link?: string;
  thumbnail_url?: string;
  assigned_student_ids: string[];
  faculty_id?: string;
}

interface Student {
  id: string;
  full_name: string;
  email: string;
  student_id?: string;
}

const CourseAssignment: React.FC = () => {
  const { profile } = useProfile();
  const { toast } = useToast();

  const [courses, setCourses] = useState<Course[]>([]);
  const [assignedStudents, setAssignedStudents] = useState<Student[]>([]);
  const [loading, setLoading] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState<string>('');
  const [selectedStudent, setSelectedStudent] = useState<string>('');

  // Fetch courses - simple approach
  const fetchCourses = async () => {
    console.log('fetchCourses called, profile:', profile);
    console.log('Profile role:', profile?.role);

    if (!profile) {
      console.log('No profile found, cannot fetch courses');
      return;
    }

    if (profile.role !== 'faculty') {
      console.log('Profile role is not faculty, cannot fetch courses');
      return;
    }

    try {
      setLoading(true);

      // Just fetch all courses - simple
      const { data: coursesData, error: coursesError } = await supabase
        .from('courses')
        .select('*')
        .order('name');

      if (coursesError) {
        console.error('Error fetching courses:', coursesError);
        return;
      }

      console.log('Fetched courses:', coursesData);
      console.log('Number of courses:', coursesData?.length || 0);
      setCourses(coursesData || []);
    } catch (err) {
      console.error('Error fetching courses:', err);
    } finally {
      setLoading(false);
    }
  };

  // Fetch assigned students - simple approach
  const fetchAssignedStudents = async () => {
    console.log('fetchAssignedStudents called, profile:', profile);

    if (!profile || profile.role !== 'faculty') {
      console.log('Cannot fetch students - no profile or not faculty');
      return;
    }

    try {
      // Just fetch all students for now - simple
      const { data: studentsData, error: studentsError } = await supabase
        .from('profiles')
        .select('*')
        .eq('role', 'student')
        .order('full_name');

      if (studentsError) {
        console.error('Error fetching students:', studentsError);
        return;
      }

      console.log('Fetched students:', studentsData);
      console.log('Number of students:', studentsData?.length || 0);
      setAssignedStudents(studentsData || []);
    } catch (err) {
      console.error('Error fetching students:', err);
    }
  };

  // Assign student to course
  const assignStudentToCourse = async () => {
    if (!selectedCourse || !selectedStudent) {
      toast({
        title: 'Error',
        description: 'Please select both course and student',
        variant: 'destructive',
      });
      return;
    }

    try {
      const course = courses.find(c => c.id === selectedCourse);
      if (!course) return;

      let updatedStudentIds = [...(course.assigned_student_ids || [])];

      if (selectedStudent === 'all') {
        // Assign all assigned students to the course
        const allStudentIds = assignedStudents.map(s => s.id.toString());
        updatedStudentIds = [
          ...new Set([...updatedStudentIds, ...allStudentIds]),
        ];
      } else {
        // Assign single student
        const studentId = selectedStudent.toString();
        if (!updatedStudentIds.includes(studentId)) {
          updatedStudentIds.push(studentId);
        }
      }

      console.log('Updating course with student IDs:', updatedStudentIds);
      console.log('Course ID:', selectedCourse);

      const { error } = await supabase
        .from('courses')
        .update({ assigned_student_ids: updatedStudentIds })
        .eq('id', selectedCourse);

      if (error) {
        console.error('Error updating course:', error);
        throw error;
      }

      console.log('Course updated successfully');

      const message =
        selectedStudent === 'all'
          ? `All ${assignedStudents.length} students assigned to course successfully`
          : 'Student assigned to course successfully';

      toast({
        title: 'Success',
        description: message,
      });

      // Refresh courses
      await fetchCourses();
      setSelectedStudent('');
    } catch (err: any) {
      console.error('Error assigning student to course:', err);
      toast({
        title: 'Error',
        description: err.message || 'Failed to assign student to course',
        variant: 'destructive',
      });
    }
  };

  // Remove student from course
  const removeStudentFromCourse = async (
    courseId: string,
    studentId: string
  ) => {
    try {
      const course = courses.find(c => c.id === courseId);
      if (!course) return;

      const updatedStudentIds = (course.assigned_student_ids || []).filter(
        id => id !== studentId
      );

      const { error } = await supabase
        .from('courses')
        .update({ assigned_student_ids: updatedStudentIds })
        .eq('id', courseId);

      if (error) {
        throw error;
      }

      toast({
        title: 'Success',
        description: 'Student removed from course successfully',
      });

      // Refresh courses
      await fetchCourses();
    } catch (err: any) {
      console.error('Error removing student from course:', err);
      toast({
        title: 'Error',
        description: err.message || 'Failed to remove student from course',
        variant: 'destructive',
      });
    }
  };

  // Load data on component mount
  useEffect(() => {
    console.log('CourseAssignment useEffect called, profile:', profile);
    fetchCourses();
    fetchAssignedStudents();
  }, [profile]);

  // Refresh courses when a new one is created

  return (
    <div className='space-y-6'>
