                >
                  <SelectTrigger>
                    <SelectValue placeholder='Gender' />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value='male'>Boy</SelectItem>
                    <SelectItem value='female'>Girl</SelectItem>
                    <SelectItem value='other'>Other</SelectItem>
                  </SelectContent>
                </Select>
                <Input
                  placeholder='Section'
                  value={row.section}
                  onChange={e =>
                    setRows(r =>
                      r.map((x, i) =>
                        i === idx ? { ...x, section: e.target.value } : x
