import React, { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { useProfile } from '@/hooks/useProfile';
import { supabase } from '@/integrations/supabase/client';
import { Bell, CheckCircle, XCircle, Award, Lightbulb } from 'lucide-react';

interface Notification {
  id: string;
  title: string;
  message: string;
  type: string;
  created_at: string;
  read_at: string | null;
}

const NotificationsDropdown = () => {
  const { profile } = useProfile();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    if (profile) {
      fetchNotifications();
    }
  }, [profile]);

  const fetchNotifications = async () => {
    if (!profile) return;

    try {
      const { data, error } = await supabase
        .from('notifications')
        .select('*')
        .eq('user_id', profile.id)
        .order('created_at', { ascending: false })
        .limit(20);
      if (error) throw error;
      setNotifications((data as any) || []);
      setUnreadCount((data || []).filter((n: any) => !n.read_at).length);
    } catch (error) {
      console.error('Error fetching notifications:', error);
    }
  };

  const markAsRead = async (notificationId: string) => {
    try {
      const { error } = await supabase
        .from('notifications')
        .update({ read_at: new Date().toISOString() })
        .eq('id', notificationId);
      if (error) throw error;
      setNotifications(prev =>
        prev.map(n =>
          n.id === notificationId
            ? { ...n, read_at: new Date().toISOString() }
            : n
        )
      );
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (error) {
      console.error('Error marking notification as read:', error);
    }
  };

  const markAllAsRead = async () => {
    try {
      const unreadIds = notifications.filter(n => !n.read_at).map(n => n.id);
      if (unreadIds.length === 0) return;

      const { error } = await supabase
        .from('notifications')
        .update({ read_at: new Date().toISOString() })
        .in('id', unreadIds);
      if (error) throw error;
      setNotifications(prev =>
        prev.map(n => ({ ...n, read_at: new Date().toISOString() }))
      );
      setUnreadCount(0);
    } catch (error) {
      console.error('Error marking all notifications as read:', error);
    }
  };

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case 'certificate_approved':
        return <CheckCircle className='h-4 w-4 text-green-600' />;
      case 'certificate_rejected':
        return <XCircle className='h-4 w-4 text-red-600' />;
      case 'new_recommendation':
        return <Lightbulb className='h-4 w-4 text-blue-600' />;
      default:
        return <Award className='h-4 w-4 text-primary' />;
    }
  };

  const formatTimeAgo = (dateString: string) => {
    const now = new Date();
    const date = new Date(dateString);
    const diffInHours = Math.floor(
      (now.getTime() - date.getTime()) / (1000 * 60 * 60)
    );

    if (diffInHours < 1) return 'Just now';
    if (diffInHours < 24) return `${diffInHours}h ago`;
    if (diffInHours < 168) return `${Math.floor(diffInHours / 24)}d ago`;
    return date.toLocaleDateString();
  };

  return (
    <Popover open={isOpen} onOpenChange={setIsOpen}>
      <PopoverTrigger asChild>
        <Button variant='outline' size='sm' className='relative'>
          <Bell className='h-4 w-4' />
          {unreadCount > 0 && (
            <Badge className='absolute -top-2 -right-2 h-5 w-5 rounded-full p-0 flex items-center justify-center text-xs bg-red-500 text-white'>
              {unreadCount > 9 ? '9+' : unreadCount}
            </Badge>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className='w-80' align='end'>
        <div className='space-y-4'>
          <div className='flex items-center justify-between'>
            <h3 className='font-semibold'>Notifications</h3>
            {unreadCount > 0 && (
              <Button variant='ghost' size='sm' onClick={markAllAsRead}>
                Mark all read
              </Button>
            )}
          </div>

          <ScrollArea className='h-80'>
            {notifications.length === 0 ? (
              <div className='text-center py-8 text-muted-foreground'>
                <Bell className='h-8 w-8 mx-auto mb-2 opacity-50' />
                <p>No notifications yet</p>
              </div>
            ) : (
              <div className='space-y-2'>
                {notifications.map(notification => (
                  <div
                    key={notification.id}
                    className={`p-3 rounded-lg border cursor-pointer transition-colors ${
                      notification.read_at
                        ? 'bg-background border-border'
                        : 'bg-muted/30 border-primary/20'
                    }`}
                    onClick={() =>
                      !notification.read_at && markAsRead(notification.id)
                    }
                  >
                    <div className='flex items-start space-x-3'>
                      {getNotificationIcon(notification.type)}
                      <div className='flex-1 space-y-1'>
                        <p className='text-sm font-medium leading-none'>
                          {notification.title}
                        </p>
                        <p className='text-xs text-muted-foreground'>
                          {notification.message}
                        </p>
                        <p className='text-xs text-muted-foreground'>
                          {formatTimeAgo(notification.created_at)}
                        </p>
                      </div>
                      {!notification.read_at && (
                        <div className='h-2 w-2 bg-primary rounded-full' />
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </ScrollArea>
        </div>
      </PopoverContent>
    </Popover>
  );
};

export default NotificationsDropdown;

