import React, { useState } from 'react';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { useProfile } from '@/hooks/useProfile';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/integrations/supabase/client';
import { Upload } from 'lucide-react';

interface UploadCertificateSectionProps {
  onUploadComplete: () => void;
}

const UploadCertificateSection: React.FC<UploadCertificateSectionProps> = ({
  onUploadComplete,
}) => {
  const { profile } = useProfile();
  const { toast } = useToast();
  const [uploading, setUploading] = useState(false);

  // Upload form state
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState<'academic' | 'co_curricular'>(
    'academic'
  );
  const [file, setFile] = useState<File | null>(null);

  const uploadCertificate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file || !profile) return;

    setUploading(true);
    try {
      const fileExt = file.name.split('.').pop();
      const path = `${profile.user_id}/${Date.now()}.${fileExt}`;
      const { error: uploadError } = await supabase.storage
        .from('certificates')
        .upload(path, file);
      if (uploadError) throw uploadError;
      const { data: publicData } = supabase.storage
        .from('certificates')
        .getPublicUrl(path);
      const publicUrl = publicData.publicUrl;

      const { error: insertError } = await supabase
        .from('certificates')
        .insert({
          student_id: profile.id,
          title,
          description,
          category,
          file_url: publicUrl,
          file_name: file.name,
          status: 'pending',
        });
      if (insertError) throw insertError;

      toast({
        title: 'Success',
        description: 'Certificate uploaded successfully!',
      });

      // Reset form
      setTitle('');
      setDescription('');
      setCategory('academic');
      setFile(null);

      // Notify parent component
      onUploadComplete();
    } catch (error: any) {
      console.error('Error uploading certificate:', error);
      toast({
        title: 'Error',
        description: error.message || 'Failed to upload certificate',
        variant: 'destructive',
      });
    } finally {
      setUploading(false);
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className='flex items-center space-x-2'>
          <Upload className='h-5 w-5' />
          <span>Upload Certificate</span>
        </CardTitle>
        <CardDescription>
          Upload your academic or co-curricular certificates for verification
        </CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={uploadCertificate} className='space-y-4'>
          <div className='grid grid-cols-1 md:grid-cols-2 gap-4'>
            <div className='space-y-2'>
              <Label htmlFor='title'>Certificate Title</Label>
              <Input
                id='title'
                value={title}
                onChange={e => setTitle(e.target.value)}
                placeholder='e.g., Computer Science Degree'
                required
              />
            </div>
            <div className='space-y-2'>
              <Label htmlFor='category'>Category</Label>
              <Select
                value={category}
                onValueChange={(value: 'academic' | 'co_curricular') =>
                  setCategory(value)
                }
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value='academic'>Academic</SelectItem>
                  <SelectItem value='co_curricular'>Co-Curricular</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className='space-y-2'>
            <Label htmlFor='description'>Description (Optional)</Label>
            <Textarea
              id='description'
              value={description}
              onChange={e => setDescription(e.target.value)}
              placeholder='Brief description of the certificate...'
              rows={3}
            />
          </div>

          <div className='space-y-2'>
            <Label htmlFor='file'>Certificate File (PDF/JPEG)</Label>
            <Input
              id='file'
              type='file'
              accept='.pdf,.jpg,.jpeg,.png'
              onChange={e => setFile(e.target.files?.[0] || null)}
              required
            />
          </div>

          <Button
            type='submit'
            disabled={uploading || !file}
            className='w-full'
          >
            {uploading ? 'Uploading...' : 'Upload Certificate'}
          </Button>
        </form>
      </CardContent>
    </Card>
  );
};

export default UploadCertificateSection;

import React, { useMemo, useState } from 'react';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Switch } from '@/components/ui/switch';
import {
  Select,
  SelectTrigger,
  SelectValue,
  SelectContent,
  SelectItem,
} from '@/components/ui/select';
import PlatformInput from './PlatformInput';
import { defaultSuggestions } from './platforms';
import type { Goal, GoalUnit, PlatformKey } from './types';

interface Props {
  open: boolean;
  onOpenChange: (v: boolean) => void;
  initial?: Partial<Goal>;
  onSave: (g: Goal) => void;
}

const units: GoalUnit[] = ['problems', 'contests', 'points'];

function daysBetween(a: string, b: string) {
  const A = new Date(a + 'T00:00:00');
  const B = new Date(b + 'T00:00:00');
  return Math.max(
    1,
    Math.round((B.getTime() - A.getTime()) / (1000 * 60 * 60 * 24))
  );
}

const GoalForm: React.FC<Props> = ({ open, onOpenChange, initial, onSave }) => {
  const [title, setTitle] = useState(initial?.title ?? '');
  const [platform, setPlatform] = useState<PlatformKey>(
    initial?.platform ?? 'leetcode'
  );
  const [account, setAccount] = useState(initial?.account ?? '');
  const [target, setTarget] = useState<number>(initial?.target ?? 50);
  const [unit, setUnit] = useState<GoalUnit>(initial?.unit ?? 'problems');
  const today = useMemo(() => new Date().toISOString().split('T')[0], []);
  const [startDate, setStartDate] = useState(initial?.startDate ?? today);
  const [endDate, setEndDate] = useState(initial?.endDate ?? today);
  const [autoSync, setAutoSync] = useState(initial?.autoSync ?? true);
  const [privacy, setPrivacy] = useState<'public' | 'private'>(
    initial?.privacy ?? 'private'
  );
  const [submitting, setSubmitting] = useState(false);

  const dailyRate = useMemo(() => {
    const days = daysBetween(startDate, endDate);
    return Math.max(0, Math.ceil((target || 0) / days));
  }, [startDate, endDate, target]);

  const valid = title.trim() && account.trim() && Number(target) > 0;

  const handleSave = () => {
    if (!valid) return;
    setSubmitting(true);
    const now = Date.now();
    const g: Goal = {
      id: initial?.id ?? crypto.randomUUID(),
      title: title.trim(),
      platform,
      account: account.trim(),
      target: Number(target),
      unit,
      startDate,
      endDate,
      autoSync,
      privacy,
      progress: initial?.progress ?? 0,
      lastSyncAt: null,
      syncStatus: 'idle',
      activity: initial?.activity ?? [],
      createdAt: initial?.createdAt ?? now,
      updatedAt: now,
      completed: false,
      paused: false,
    };
    onSave(g);
    setSubmitting(false);
    onOpenChange(false);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className='sm:max-w-[720px]'>
        <DialogHeader>
          <DialogTitle>{initial?.id ? 'Edit Goal' : 'Create Goal'}</DialogTitle>
        </DialogHeader>
        <div className='space-y-4'>
          <div>
            <label className='block text-sm font-medium mb-1'>Goal title</label>
            <Input
              value={title}
              onChange={e => setTitle(e.target.value)}
              placeholder='Solve 50 LeetCode problems'
              className='h-11'
            />
            <div className='mt-2 flex flex-wrap gap-2'>
              {defaultSuggestions.map(s => (
                <button
                  key={s}
                  type='button'
                  onClick={() => setTitle(s)}
                  className='text-xs px-2 py-1 rounded-full bg-gray-100 hover:bg-gray-200'
                >
                  {s}
                </button>
              ))}
            </div>
          </div>

          <PlatformInput
            platform={platform}
            account={account}
            onPlatformChange={setPlatform}
            onAccountChange={setAccount}
          />

          <div className='grid grid-cols-1 sm:grid-cols-3 gap-3'>
            <div>
              <label className='block text-sm font-medium mb-1'>Target</label>
              <Input
                type='number'
                min={1}
                value={target}
                onChange={e => setTarget(Number(e.target.value))}
                className='h-11'
              />
            </div>
            <div>
              <label className='block text-sm font-medium mb-1'>Unit</label>
              <Select value={unit} onValueChange={v => setUnit(v as GoalUnit)}>
                <SelectTrigger className='w-full h-11'>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {units.map(u => (
                    <SelectItem key={u} value={u}>
                      {u}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className='rounded-md bg-indigo-50 text-indigo-800 p-3 text-sm flex items-center justify-between'>
              <span>Daily pace</span>
              <span className='font-semibold'>
                {dailyRate}/{unit.slice(0, -1)}
              </span>
            </div>
          </div>

          <div className='grid grid-cols-1 sm:grid-cols-2 gap-3'>
            <div>
              <label className='block text-sm font-medium mb-1'>
                Start date
              </label>
              <Input
                type='date'
                value={startDate}
                onChange={e => setStartDate(e.target.value)}
                className='h-11'
              />
            </div>
            <div>
              <label className='block text-sm font-medium mb-1'>End date</label>
              <Input
                type='date'
                value={endDate}
                onChange={e => setEndDate(e.target.value)}
                className='h-11'
              />
            </div>
          </div>

          <div className='grid grid-cols-1 sm:grid-cols-3 gap-3'>
            <div className='flex items-center justify-between rounded-md border p-3'>
              <div>
                <div className='text-sm font-medium'>Auto-sync</div>
                <div className='text-xs text-muted-foreground'>
                  Fetch from platform periodically
                </div>
              </div>
              <Switch checked={autoSync} onCheckedChange={setAutoSync} />
            </div>
            <div className='flex items-center justify-between rounded-md border p-3'>
              <div>
                <div className='text-sm font-medium'>Privacy</div>
                <div className='text-xs text-muted-foreground'>
                  Public or private goal
                </div>
              </div>
              <Select value={privacy} onValueChange={v => setPrivacy(v as any)}>
                <SelectTrigger className='w-28 h-9'>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value='public'>public</SelectItem>
                  <SelectItem value='private'>private</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className='rounded-md bg-emerald-50 text-emerald-800 p-3 text-sm'>
              <div className='font-medium'>ETA helper</div>
              <div className='text-xs'>
                Stay on pace to finish by{' '}
                {new Date(endDate + 'T00:00:00').toLocaleDateString()}
              </div>
            </div>
          </div>
        </div>
        <DialogFooter>
          <Button variant='ghost' onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button disabled={!valid || submitting} onClick={handleSave}>
            {initial?.id ? 'Save Changes' : 'Save Goal'}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

