import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Loader2, ExternalLink, CheckCircle, AlertCircle } from 'lucide-react';

interface Platform {
  id: string;
  name: string;
  icon: string;
  description: string;
  authType: 'oauth' | 'api_key' | 'profile_url';
  isConnected: boolean;
  handle?: string;
  lastSync?: string;
  syncStatus?: 'idle' | 'syncing' | 'success' | 'error';
}

interface PlatformCardProps {
  platform: Platform;
  onConnect: (platformId: string, credentials: any) => Promise<void>;
  onDisconnect: (platformId: string) => void;
  onSync: (platformId: string) => Promise<void>;
}

const PlatformCard: React.FC<PlatformCardProps> = ({
  platform,
  onConnect,
  onDisconnect,
  onSync,
}) => {
  const [showConnectDialog, setShowConnectDialog] = useState(false);
  const [credentials, setCredentials] = useState({
    handle: '',
    apiKey: '',
    profileUrl: '',
  });
  const [connecting, setConnecting] = useState(false);

  const handleConnect = async () => {
    setConnecting(true);
    try {
      await onConnect(platform.id, credentials);
      setShowConnectDialog(false);
      setCredentials({ handle: '', apiKey: '', profileUrl: '' });
    } catch (error) {
      console.error('Connection failed:', error);
    } finally {
      setConnecting(false);
    }
  };

  const handleSync = async () => {
    try {
      await onSync(platform.id);
    } catch (error) {
      console.error('Sync failed:', error);
    }
  };

  const getStatusIcon = () => {
    switch (platform.syncStatus) {
      case 'syncing':
        return <Loader2 className='h-4 w-4 animate-spin text-blue-600' />;
      case 'success':
        return <CheckCircle className='h-4 w-4 text-green-600' />;
      case 'error':
        return <AlertCircle className='h-4 w-4 text-red-600' />;
      default:
        return null;
    }
  };

  return (
    <>
      <Card className='group relative overflow-hidden rounded-2xl border border-gray-200/70 bg-white shadow-md transition-all duration-300 hover:shadow-xl hover:-translate-y-1'>
        <div className='absolute inset-0 bg-gradient-to-br from-indigo-50/50 to-purple-50/50 opacity-0 group-hover:opacity-100 transition-opacity duration-300' />

        <CardHeader className='relative pb-3'>
          <div className='flex items-center justify-between'>
            <div className='flex items-center gap-3'>
              <div className='text-2xl'>{platform.icon}</div>
              <div>
                <CardTitle className='text-lg font-semibold'>
                  {platform.name}
                </CardTitle>
                <p className='text-sm text-muted-foreground'>
                  {platform.description}
                </p>
              </div>
            </div>
            {platform.isConnected && (
              <Badge
                variant='secondary'
                className='bg-green-100 text-green-800'
              >
                Connected
              </Badge>
            )}
          </div>
        </CardHeader>

        <CardContent className='relative space-y-4'>
          {platform.isConnected ? (
            <div className='space-y-3'>
              <div className='flex items-center justify-between text-sm'>
                <span className='text-muted-foreground'>Handle:</span>
                <span className='font-medium'>{platform.handle}</span>
              </div>

              {platform.lastSync && (
                <div className='flex items-center justify-between text-sm'>
                  <span className='text-muted-foreground'>Last sync:</span>
                  <div className='flex items-center gap-2'>
                    {getStatusIcon()}
                    <span className='font-medium'>
                      {new Date(platform.lastSync).toLocaleString()}
                    </span>
                  </div>
                </div>
              )}

              <div className='flex gap-2'>
                <Button
                  size='sm'
                  onClick={handleSync}
                  disabled={platform.syncStatus === 'syncing'}
                  className='flex-1'
                >
                  {platform.syncStatus === 'syncing' ? (
                    <>
                      <Loader2 className='h-4 w-4 mr-2 animate-spin' />
                      Syncing...
                    </>
                  ) : (
                    'Sync Now'
                  )}
                </Button>
                <Button
                  variant='outline'
                  size='sm'
                  onClick={() => onDisconnect(platform.id)}
                >
                  Disconnect
                </Button>
              </div>
            </div>
          ) : (
            <div className='space-y-3'>
              <p className='text-sm text-muted-foreground'>
                Connect your {platform.name} account to track your progress
                automatically.
              </p>
              <Button
                onClick={() => setShowConnectDialog(true)}
                className='w-full bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700'
              >
                Connect {platform.name}
              </Button>
            </div>
          )}
        </CardContent>
      </Card>

      <Dialog open={showConnectDialog} onOpenChange={setShowConnectDialog}>
        <DialogContent className='sm:max-w-md'>
          <DialogHeader>
            <DialogTitle className='flex items-center gap-2'>
              <span className='text-xl'>{platform.icon}</span>
              Connect {platform.name}
            </DialogTitle>
          </DialogHeader>

          <div className='space-y-4'>
            {platform.authType === 'profile_url' && (
              <div className='space-y-2'>
                <Label htmlFor='profileUrl'>Profile URL or Username</Label>
                <Input
                  id='profileUrl'
                  placeholder={`e.g., https://${platform.name.toLowerCase()}.com/username or username`}
                  value={credentials.profileUrl}
                  onChange={e =>
                    setCredentials(prev => ({
                      ...prev,
                      profileUrl: e.target.value,
                    }))
                  }
                />
              </div>
            )}

            {platform.authType === 'api_key' && (
              <div className='space-y-2'>
                <Label htmlFor='apiKey'>API Key</Label>
                <Input
                  id='apiKey'
                  type='password'
                  placeholder='Enter your API key'
                  value={credentials.apiKey}
                  onChange={e =>
                    setCredentials(prev => ({
                      ...prev,
                      apiKey: e.target.value,
                    }))
                  }
                />
                <p className='text-xs text-muted-foreground'>
                  Find your API key in your {platform.name} account settings
                </p>
              </div>
            )}

            {platform.authType === 'oauth' && (
              <div className='text-center py-4'>
                <p className='text-sm text-muted-foreground mb-4'>
                  You'll be redirected to {platform.name} to authorize access
                </p>
              </div>
            )}

            <div className='flex justify-end gap-2'>
              <Button
                variant='outline'
                onClick={() => setShowConnectDialog(false)}
              >
                Cancel
              </Button>
              <Button onClick={handleConnect} disabled={connecting}>
                {connecting ? (
                  <>
                    <Loader2 className='h-4 w-4 mr-2 animate-spin' />
                    Connecting...
                  </>
                ) : (
                  'Connect'
                )}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
};

export default PlatformCard;

import React from 'react';
import { Link, NavLink, useLocation, useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { useAuth } from '@/hooks/useAuth';
import { useProfile } from '@/hooks/useProfile';
import { useToast } from '@/hooks/use-toast';
import { LogOut, User } from 'lucide-react';
import NotificationBell from '../NotificationBell';
import {
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
  DropdownMenuItem,
} from '@/components/ui/dropdown-menu';

const Navbar = () => {
  const { signOut } = useAuth();
  const { profile } = useProfile();
  const { toast } = useToast();
  const navigate = useNavigate();

  // Get profile picture from localStorage
  const getProfilePicture = () => {
    if (typeof window === 'undefined') return '';
    try {
      const overrides = JSON.parse(
        localStorage.getItem('profile_overrides_v1') || '{}'
      );
      return overrides.avatarDataUrl || '';
    } catch {
      return '';
    }
  };

  const handleSignOut = async () => {
    try {
      console.log('Starting sign out process...');
      const { error } = await signOut();
      if (error) {
        console.error('Sign out error:', error);
        toast({
          title: 'Error',
          description: error.message,
          variant: 'destructive',
        });
      } else {
        console.log('Sign out successful, navigating to auth...');
        toast({
          title: 'Success',
          description: 'Signed out successfully!',
        });
        navigate('/auth', { replace: true });
      }
    } catch (err) {
      console.error('Unexpected error during sign out:', err);
      toast({
        title: 'Error',
        description: 'An unexpected error occurred during sign out',
        variant: 'destructive',
      });
    }
  };

  const location = useLocation();
  const tabsRef = React.useRef<HTMLDivElement | null>(null);
  const btnRefs = React.useRef<Record<string, HTMLElement | null>>({});
  const [indicator, setIndicator] = React.useState<{
    left: number;
    width: number;
  }>({ left: 0, width: 0 });
  const [focusedIndex, setFocusedIndex] = React.useState<number | null>(null);

  // ΓöÇΓöÇ Student-only routes ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const studentItems = [
    { label: 'Home', to: '/home' },
    { label: 'Dashboard', to: '/' },
    { label: 'Community', to: '/community' },
    { label: 'Events', to: '/events' },
    { label: 'Leaderboard', to: '/leaderboard' },
    { label: 'My Courses', to: '/student-courses' },
  ];

  // ΓöÇΓöÇ Faculty-only routes ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const facultyItems = [
    { label: 'Dashboard', to: '/' },
    { label: 'Courses', to: '/courses' },
    { label: 'Schedule', to: '/schedule' },
    { label: 'My Students', to: '/faculty/students' },
    { label: 'Faculty Community', to: '/faculty/community' },
    { label: 'Events', to: '/events' },
  ];

  // ΓöÇΓöÇ Admin-only routes ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const adminItems = [
    { label: 'Admin Dashboard', to: '/admin' },
    { label: 'Faculty Mgmt', to: '/admin/faculty' },
    { label: 'Assignments', to: '/admin/assignments' },
    { label: 'LMS Integrations', to: '/admin/integrations' },
    { label: 'Reports', to: '/admin/reports' },
    { label: 'Debug', to: '/admin/debug' },
  ];

  const items = React.useMemo(() => {
    if (profile?.role === 'faculty' && profile?.faculty_level === 'admin') {
      return adminItems;
    }
    if (profile?.role === 'faculty') {
      return facultyItems;
    }
    if (profile?.role === 'student') {
      return studentItems;
    }
    // default / loading: show a minimal common set
    return [
      { label: 'Dashboard', to: '/' },
      { label: 'Events', to: '/events' },
    ];
  }, [profile]);

  // Match active tab: exact for '/', prefix for everything else
  const isItemActive = (to: string) => {
    if (to === '/') return location.pathname === '/';
    return location.pathname === to || location.pathname.startsWith(to + '/');
  };

  React.useLayoutEffect(() => {
    const active = items.find(i => isItemActive(i.to));
    if (active) {
      const container = tabsRef.current;
      const btn = btnRefs.current[active.label];
      if (container && btn) {
        const cRect = container.getBoundingClientRect();
        const bRect = btn.getBoundingClientRect();
        setIndicator({ left: bRect.left - cRect.left, width: bRect.width });
      }
    }
  }, [location.pathname, items]);

  // keyboard navigation for tabs
  const onTabsKeyDown = (e: React.KeyboardEvent) => {
    const currentPathIndex = items.findIndex(i => isItemActive(i.to));
    const current =
      focusedIndex ?? (currentPathIndex >= 0 ? currentPathIndex : 0);
    if (e.key === 'ArrowRight') {
      const next = Math.min(items.length - 1, current + 1);
      setFocusedIndex(next);
      btnRefs.current[items[next].label]?.focus();
      e.preventDefault();
    } else if (e.key === 'ArrowLeft') {
      const prev = Math.max(0, current - 1);
      setFocusedIndex(prev);
      btnRefs.current[items[prev].label]?.focus();
      e.preventDefault();
    }
  };

  return (
    <nav className='sticky top-0 z-40 border-b bg-white shadow-sm transition-colors duration-300'>
      <div className='max-w-7xl mx-auto px-4 sm:px-6 lg:px-8'>
        <div className='flex items-center justify-between h-16'>
          <div className='flex items-center gap-3'>
            <Link
              to='/'
              className='text-lg font-semibold tracking-tight hover:opacity-80 transition-opacity'
            >
              mondly
            </Link>
          </div>

          <div
            ref={tabsRef}
            onKeyDown={onTabsKeyDown}
            tabIndex={0}
            aria-label='Main navigation'
            role='tablist'
            className='relative hidden md:flex items-center gap-1 bg-gray-100 rounded-full p-1'
          >
            <span
              aria-hidden='true'
              className='pointer-events-none absolute top-1 bottom-1 rounded-full bg-[#111827] shadow-sm transition-all duration-300 ease-out z-0'
              style={{ left: indicator.left, width: indicator.width }}
            />
            {items.map((item, idx) => {
              const isActive = isItemActive(item.to);
              return (
                <NavLink
                  key={item.label}
                  ref={el => (btnRefs.current[item.label] = el)}
                  to={item.to}
                  role='tab'
                  aria-selected={isActive}
                  tabIndex={-1}
                  className={`relative z-10 px-4 py-1.5 rounded-full text-sm transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-ring ${isActive ? 'text-white' : 'text-gray-700 hover:text-gray-900'}`}
                  style={isActive ? { color: 'white !important' } : {}}
                >
                  {item.label}
                </NavLink>
              );
            })}
          </div>

          <div className='flex items-center gap-3'>
            {profile && <NotificationBell />}
            {profile && (
              <>
                {/* Desktop Profile */}
                <div className='hidden sm:flex items-center gap-3 text-sm text-gray-700 transition-colors'>
                  <Link
                    to='/profile'
                    className='flex items-center gap-3 hover:opacity-80 transition-opacity'
                  >
                    <Avatar className='h-8 w-8'>
                      <AvatarImage
                        src={getProfilePicture()}
                        alt={profile.full_name}
                      />
                      <AvatarFallback className='text-xs'>
                        {profile.full_name
                          .split(' ')
                          .map(n => n[0])
                          .join('')
                          .slice(0, 2)
                          .toUpperCase()}
                      </AvatarFallback>
                    </Avatar>
                    <div className='flex flex-col'>
                      <span className='font-medium'>{profile.full_name}</span>
                      <span className='text-xs capitalize text-gray-500'>
                        ({profile.role})
                      </span>
                    </div>
                  </Link>
                </div>

                {/* Mobile Profile Dropdown */}
                <div className='sm:hidden'>
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button variant='ghost' size='sm' className='p-1'>
                        <Avatar className='h-8 w-8'>
                          <AvatarImage
                            src={getProfilePicture()}
                            alt={profile.full_name}
                          />
                          <AvatarFallback className='text-xs'>
                            {profile.full_name
                              .split(' ')
                              .map(n => n[0])
                              .join('')
                              .slice(0, 2)
                              .toUpperCase()}
                          </AvatarFallback>
                        </Avatar>
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align='end' className='w-56'>
                      <div className='flex items-center gap-3 p-2'>
                        <Avatar className='h-10 w-10'>
                          <AvatarImage
                            src={getProfilePicture()}
                            alt={profile.full_name}
                          />
                          <AvatarFallback>
                            {profile.full_name
                              .split(' ')
                              .map(n => n[0])
                              .join('')
                              .slice(0, 2)
                              .toUpperCase()}
                          </AvatarFallback>
                        </Avatar>
                        <div className='flex flex-col'>
                          <span className='font-medium'>
                            {profile.full_name}
                          </span>
                          <span className='text-xs capitalize text-gray-500'>
                            ({profile.role})
                          </span>
                        </div>
                      </div>
                      <DropdownMenuItem asChild>
                        <Link to='/profile' className='w-full'>
                          <User className='h-4 w-4 mr-2' />
                          View Profile
                        </Link>
                      </DropdownMenuItem>
                      <DropdownMenuItem onClick={handleSignOut}>
                        <LogOut className='h-4 w-4 mr-2' />
                        Sign Out
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </div>
              </>
            )}
            {profile && (
              <div className='hidden sm:block'>
                <Button
                  variant='outline'
                  size='sm'
                  onClick={handleSignOut}
                  className='transition-all duration-200 hover:-translate-y-0.5'
                >
                  <LogOut className='h-4 w-4 mr-2' />
                  Sign Out
                </Button>
              </div>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

