import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { useProfile } from '@/hooks/useProfile';
import { useToast } from '@/hooks/use-toast';
import {
  recommendationEngine,
  StudentProfile,
} from '@/services/recommendationService';
import {
  User,
  Plus,
  X,
  Save,
  Target,
  Award,
  BookOpen,
  Lightbulb,
} from 'lucide-react';

const ProfileSetup: React.FC = () => {
  const { profile } = useProfile();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [newInterest, setNewInterest] = useState('');
  const [newCertification, setNewCertification] = useState('');
  const [newSkill, setNewSkill] = useState('');
  const [newCareerGoal, setNewCareerGoal] = useState('');

  const [profileData, setProfileData] = useState<Partial<StudentProfile>>({
    interests: [],
    certifications: [],
    skills: [],
    career_goals: [],
    experience_level: 'beginner',
    preferred_learning_style: 'mixed',
  });

  const availableInterests = [
    'web_development',
    'data_science',
    'mobile_development',
    'cloud_computing',
    'cybersecurity',
    'blockchain',
    'game_development',
    'database',
    'algorithms',
    'ui_ux',
  ];

  const availableCertifications = [
    'aws_certified',
    'google_certified',
    'microsoft_certified',
    'cisco_certified',
    'comptia_certified',
    'pmp_certified',
    'salesforce_certified',
    'oracle_certified',
    'adobe_certified',
    'google_analytics',
  ];

  const availableSkills = [
    'javascript',
    'python',
    'react',
    'node.js',
    'html',
    'css',
    'sql',
    'mongodb',
    'aws',
    'docker',
    'kubernetes',
    'git',
    'linux',
    'data analysis',
    'machine learning',
    'ui/ux',
    'mobile development',
    'web development',
    'cybersecurity',
    'blockchain',
  ];

  const availableCareerGoals = [
    'software engineer',
    'data scientist',
    'web developer',
    'mobile developer',
    'devops engineer',
    'cybersecurity analyst',
    'ui/ux designer',
    'product manager',
    'cloud architect',
    'machine learning engineer',
    'blockchain developer',
  ];

  useEffect(() => {
    if (profile) {
      setProfileData({
        interests: profile.interests || [],
        certifications: profile.certifications || [],
        skills: profile.skills || [],
        career_goals: profile.career_goals || [],
        experience_level: profile.experience_level || 'beginner',
        preferred_learning_style: profile.preferred_learning_style || 'mixed',
      });
    }
  }, [profile]);

  const addItem = (type: keyof StudentProfile, value: string) => {
    if (!value.trim()) return;

    setProfileData(prev => ({
      ...prev,
      [type]: [...((prev[type] as string[]) || []), value.trim()],
    }));
  };

  const removeItem = (type: keyof StudentProfile, index: number) => {
    setProfileData(prev => ({
      ...prev,
      [type]: ((prev[type] as string[]) || []).filter((_, i) => i !== index),
    }));
  };

  const handleSave = async () => {
    if (!profile) return;

    try {
      setSaving(true);
      const success = await recommendationEngine.updateStudentProfile(
        profile.id,
        profileData
      );

      if (success) {
        toast({
          title: 'Profile Updated',
          description:
            'Your profile has been updated successfully. Recommendations will be refreshed.',
        });
      } else {
        throw new Error('Failed to update profile');
      }
    } catch (error) {
      console.error('Error updating profile:', error);
      toast({
        title: 'Error',
        description: 'Failed to update your profile. Please try again.',
        variant: 'destructive',
      });
    } finally {
      setSaving(false);
    }
  };

  if (!profile || profile.role !== 'student') {
    return null;
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className='flex items-center gap-2'>
          <User className='h-5 w-5' />
          Profile Setup for Better Recommendations
        </CardTitle>
        <CardDescription>
          Help us understand your interests, skills, and goals to provide
          personalized course recommendations
        </CardDescription>
      </CardHeader>

      <CardContent className='space-y-6'>
        {/* Experience Level */}
        <div className='space-y-2'>
          <Label htmlFor='experience'>Experience Level</Label>
          <Select
            value={profileData.experience_level}
            onValueChange={value =>
              setProfileData(prev => ({
                ...prev,
                experience_level: value as any,
              }))
            }
          >
            <SelectTrigger>
              <SelectValue placeholder='Select your experience level' />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value='beginner'>Beginner</SelectItem>
              <SelectItem value='intermediate'>Intermediate</SelectItem>
              <SelectItem value='advanced'>Advanced</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Learning Style */}
        <div className='space-y-2'>
          <Label htmlFor='learning-style'>Preferred Learning Style</Label>
          <Select
            value={profileData.preferred_learning_style}
            onValueChange={value =>
              setProfileData(prev => ({
                ...prev,
                preferred_learning_style: value as any,
              }))
            }
          >
            <SelectTrigger>
              <SelectValue placeholder='Select your learning style' />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value='visual'>Visual</SelectItem>
              <SelectItem value='hands-on'>Hands-on</SelectItem>
              <SelectItem value='theoretical'>Theoretical</SelectItem>
              <SelectItem value='mixed'>Mixed</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Interests */}
        <div className='space-y-3'>
          <Label>Interests</Label>
          <div className='flex gap-2'>
            <Select
              value={newInterest || 'select'}
              onValueChange={value =>
                setNewInterest(value === 'select' ? '' : value)
              }
            >
              <SelectTrigger className='flex-1'>
                <SelectValue placeholder='Select an interest' />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value='select'>Select an interest</SelectItem>
                {availableInterests.map(interest => (
                  <SelectItem key={interest} value={interest}>
                    {interest
                      .replace('_', ' ')
                      .replace(/\b\w/g, l => l.toUpperCase())}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Button
              type='button'
              onClick={() => {
                addItem('interests', newInterest);
                setNewInterest('');
              }}
              disabled={!newInterest}
            >
              <Plus className='h-4 w-4' />
            </Button>
          </div>
          <div className='flex flex-wrap gap-2'>
            {profileData.interests?.map((interest, index) => (
              <Badge
                key={index}
                variant='secondary'
                className='flex items-center gap-1'
              >
                {interest
                  .replace('_', ' ')
                  .replace(/\b\w/g, l => l.toUpperCase())}
                <Button
                  type='button'
                  variant='ghost'
                  size='sm'
                  className='h-4 w-4 p-0 hover:bg-transparent'
                  onClick={() => removeItem('interests', index)}
                >
                  <X className='h-3 w-3' />
                </Button>
              </Badge>
            ))}
          </div>
        </div>

        {/* Certifications */}
        <div className='space-y-3'>
          <Label>Certifications</Label>
          <div className='flex gap-2'>
            <Select
              value={newCertification || 'select'}
              onValueChange={value =>
                setNewCertification(value === 'select' ? '' : value)
              }
            >
              <SelectTrigger className='flex-1'>
                <SelectValue placeholder='Select a certification' />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value='select'>Select a certification</SelectItem>
                {availableCertifications.map(cert => (
                  <SelectItem key={cert} value={cert}>
                    {cert
                      .replace('_', ' ')
                      .replace(/\b\w/g, l => l.toUpperCase())}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Button
              type='button'
              onClick={() => {
                addItem('certifications', newCertification);
                setNewCertification('');
              }}
              disabled={!newCertification}
            >
              <Plus className='h-4 w-4' />
            </Button>
          </div>
          <div className='flex flex-wrap gap-2'>
            {profileData.certifications?.map((cert, index) => (
              <Badge
                key={index}
                variant='secondary'
                className='flex items-center gap-1'
              >
                <Award className='h-3 w-3' />
                {cert.replace('_', ' ').replace(/\b\w/g, l => l.toUpperCase())}
                <Button
                  type='button'
                  variant='ghost'
                  size='sm'
                  className='h-4 w-4 p-0 hover:bg-transparent'
                  onClick={() => removeItem('certifications', index)}
                >
                  <X className='h-3 w-3' />
                </Button>
              </Badge>
            ))}
          </div>
        </div>

        {/* Skills */}
        <div className='space-y-3'>
          <Label>Skills</Label>
          <div className='flex gap-2'>
            <Select
              value={newSkill || 'select'}
              onValueChange={value =>
                setNewSkill(value === 'select' ? '' : value)
              }
            >
              <SelectTrigger className='flex-1'>
                <SelectValue placeholder='Select a skill' />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value='select'>Select a skill</SelectItem>
                {availableSkills.map(skill => (
                  <SelectItem key={skill} value={skill}>
                    {skill}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Button
              type='button'
              onClick={() => {
                addItem('skills', newSkill);
                setNewSkill('');
              }}
              disabled={!newSkill}
            >
              <Plus className='h-4 w-4' />
            </Button>
          </div>
          <div className='flex flex-wrap gap-2'>
            {profileData.skills?.map((skill, index) => (
              <Badge
                key={index}
                variant='secondary'
                className='flex items-center gap-1'
              >
                <BookOpen className='h-3 w-3' />
                {skill}
                <Button
                  type='button'
                  variant='ghost'
                  size='sm'
                  className='h-4 w-4 p-0 hover:bg-transparent'
                  onClick={() => removeItem('skills', index)}
                >
                  <X className='h-3 w-3' />
                </Button>
              </Badge>
            ))}
          </div>
        </div>

        {/* Career Goals */}
        <div className='space-y-3'>
          <Label>Career Goals</Label>
          <div className='flex gap-2'>
            <Select
              value={newCareerGoal || 'select'}
              onValueChange={value =>
                setNewCareerGoal(value === 'select' ? '' : value)
              }
            >
              <SelectTrigger className='flex-1'>
                <SelectValue placeholder='Select a career goal' />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value='select'>Select a career goal</SelectItem>
                {availableCareerGoals.map(goal => (
                  <SelectItem key={goal} value={goal}>
                    {goal}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Button
              type='button'
              onClick={() => {
                addItem('career_goals', newCareerGoal);
                setNewCareerGoal('');
              }}
              disabled={!newCareerGoal}
            >
              <Plus className='h-4 w-4' />
            </Button>
          </div>
          <div className='flex flex-wrap gap-2'>
            {profileData.career_goals?.map((goal, index) => (
              <Badge
                key={index}
                variant='secondary'
                className='flex items-center gap-1'
              >
                <Target className='h-3 w-3' />
                {goal}
                <Button
                  type='button'
                  variant='ghost'
                  size='sm'
                  className='h-4 w-4 p-0 hover:bg-transparent'
                  onClick={() => removeItem('career_goals', index)}
                >
                  <X className='h-3 w-3' />
                </Button>
              </Badge>
            ))}
          </div>
        </div>

        {/* Save Button */}
        <div className='flex justify-end pt-4'>
          <Button
            onClick={handleSave}
            disabled={saving}
            className='min-w-[120px]'
          >
            {saving ? (
              <>
                <div className='animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2'></div>
                Saving...
              </>
            ) : (
              <>
                <Save className='h-4 w-4 mr-2' />
                Save Profile
              </>
            )}
          </Button>
        </div>
      </CardContent>
    </Card>
  );
};

export default ProfileSetup;

import React from 'react';
import { Navigate } from 'react-router-dom';
import { useAuth } from '@/hooks/useAuth';
import { useProfile } from '@/hooks/useProfile';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import {
  Shield,
  AlertTriangle,
  Lock,
  RefreshCw,
  Home,
  ArrowLeft,
  User,
  Database,
  CheckCircle,
  XCircle,
} from 'lucide-react';

interface AdminRouteProps {
  children: React.ReactNode;
}

const AdminRoute: React.FC<AdminRouteProps> = ({ children }) => {
  const { user, loading: authLoading } = useAuth();
  const {
    profile,
    loading: profileLoading,
    error: profileError,
  } = useProfile();

  // Show loading while auth or profile is loading
  if (authLoading || profileLoading) {
    return (
      <div className='min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-100 flex items-center justify-center p-8'>
        <Card className='w-full max-w-md border-0 bg-white/80 backdrop-blur-sm shadow-2xl'>
          <CardContent className='p-8 text-center'>
            <div className='relative mb-6'>
              <div className='animate-spin rounded-full h-16 w-16 border-4 border-blue-200 border-t-blue-600 mx-auto'></div>
              <div
                className='absolute inset-0 rounded-full h-16 w-16 border-4 border-transparent border-t-purple-400 animate-spin mx-auto'
                style={{
                  animationDirection: 'reverse',
                  animationDuration: '1.5s',
                }}
              ></div>
            </div>
            <h2 className='text-2xl font-bold text-gray-900 mb-2'>
              Loading Admin Portal
            </h2>
            <p className='text-gray-600 mb-4'>
              Please wait while we verify your access...
            </p>
            <div className='flex items-center justify-center space-x-2 text-sm text-gray-500'>
              <Database className='h-4 w-4' />
              <span>Connecting to database</span>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  // If there's a profile error, show error message
  if (profileError) {
    return (
      <div className='min-h-screen bg-gradient-to-br from-red-50 via-orange-50 to-yellow-50 flex items-center justify-center p-8'>
        <Card className='w-full max-w-lg border-0 bg-white/80 backdrop-blur-sm shadow-2xl'>
          <CardHeader className='text-center pb-4'>
            <div className='w-20 h-20 bg-gradient-to-br from-red-500 to-orange-500 rounded-full flex items-center justify-center mx-auto mb-4'>
              <AlertTriangle className='h-10 w-10 text-white' />
            </div>
            <CardTitle className='text-2xl font-bold text-gray-900'>
              Profile Error
            </CardTitle>
          </CardHeader>
          <CardContent className='text-center space-y-4'>
            <p className='text-gray-600'>
              There was an error loading your profile. Please try refreshing the
              page.
            </p>
            <div className='p-4 bg-red-50 rounded-lg'>
              <p className='text-sm text-red-800 font-mono'>
                Error: {profileError.message || 'Unknown error'}
              </p>
            </div>
            <div className='flex flex-col sm:flex-row gap-3'>
              <Button
                onClick={() => window.location.reload()}
                className='flex-1'
              >
                <RefreshCw className='h-4 w-4 mr-2' />
                Refresh Page
              </Button>
              <Button
                variant='outline'
                onClick={() => (window.location.href = '/')}
                className='flex-1'
              >
                <Home className='h-4 w-4 mr-2' />
                Go Home
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  // If no user, redirect to auth
  if (!user) {
    return <Navigate to='/auth' replace />;
  }

  // If no profile or user is not an admin-level faculty, show access denied
  const isAdmin =
    profile?.role === 'faculty' && profile?.faculty_level === 'admin';
  if (!profile || !isAdmin) {
    return (
      <div className='min-h-screen bg-gradient-to-br from-red-50 via-pink-50 to-purple-50 flex items-center justify-center p-8'>
        <Card className='w-full max-w-lg border-0 bg-white/80 backdrop-blur-sm shadow-2xl'>
          <CardHeader className='text-center pb-4'>
            <div className='w-20 h-20 bg-gradient-to-br from-red-500 to-pink-500 rounded-full flex items-center justify-center mx-auto mb-4'>
              <Lock className='h-10 w-10 text-white' />
            </div>
            <CardTitle className='text-2xl font-bold text-gray-900'>
              Access Denied
            </CardTitle>
          </CardHeader>
          <CardContent className='text-center space-y-4'>
            <p className='text-gray-600'>
              You don't have permission to access the Admin Portal.
            </p>
            <div className='flex items-center justify-center space-x-2'>
              <Badge className='bg-red-100 text-red-800'>
                <XCircle className='h-3 w-3 mr-1' />
                Current Role: {profile?.role || 'None'}
              </Badge>
              <Badge className='bg-green-100 text-green-800'>
                <CheckCircle className='h-3 w-3 mr-1' />
                Required: Admin
              </Badge>
            </div>
            <p className='text-sm text-gray-500'>
              Contact your administrator if you believe this is an error.
            </p>
            <div className='flex flex-col sm:flex-row gap-3'>
              <Button
                onClick={() => (window.location.href = '/')}
                className='flex-1'
              >
                <Home className='h-4 w-4 mr-2' />
                Go to Dashboard
              </Button>
              <Button
                variant='outline'
                onClick={() => window.history.back()}
                className='flex-1'
              >
                <ArrowLeft className='h-4 w-4 mr-2' />
                Go Back
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  return <>{children}</>;
};

export default AdminRoute;

import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '@/hooks/useAuth';
import { useProfile } from '@/hooks/useProfile';

interface Props {
  children: React.ReactElement;
}

const FacultyRoute: React.FC<Props> = ({ children }) => {
  const { user, loading: authLoading } = useAuth();
  const { profile, loading: profileLoading } = useProfile();
  const location = useLocation();

  if (authLoading || profileLoading) {
    return (
      <div className='min-h-screen flex items-center justify-center bg-gray-100'>
        <div className='text-center'>
          <div className='animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4'></div>
          <p className='text-muted-foreground'>Loading...</p>
        </div>
      </div>
    );
  }

  if (!user) return <Navigate to='/auth' state={{ from: location }} replace />;

  const metaRole = (user as any)?.user_metadata?.role;
  const isFaculty = (profile?.role ?? metaRole) === 'faculty';
  if (!isFaculty) {
    if (profile && profile.role !== 'faculty')
      return <Navigate to='/' replace />;
    return (
      <div className='min-h-screen flex items-center justify-center bg-gray-100'>
        <div className='text-center'>
          <div className='animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4'></div>
          <p className='text-muted-foreground'>Preparing your accessΓÇª</p>
        </div>
      </div>
    );
  }

  return children;
};

export default FacultyRoute;

import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '@/hooks/useAuth';
import { useProfile } from '@/hooks/useProfile';

interface Props {
  children: React.ReactElement;
}

const StudentRoute: React.FC<Props> = ({ children }) => {
  const { user, loading: authLoading } = useAuth();
  const { profile, loading: profileLoading } = useProfile();
  const location = useLocation();

  if (authLoading || profileLoading) {
    return (
      <div className='min-h-screen flex items-center justify-center bg-gray-100'>
        <div className='text-center'>
          <div className='animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4'></div>
          <p className='text-muted-foreground'>Loading...</p>
        </div>
      </div>
    );
  }

  if (!user) {
    return <Navigate to='/auth' state={{ from: location }} replace />;
  }

  // If profile exists and is not student, block access. If profile is null (e.g., just created), keep showing loader via a minimal fallback.
  const metaRole = (user as any)?.user_metadata?.role;
  const isStudent = (profile?.role ?? metaRole) === 'student';
  if (!isStudent) {
    // If we truly know user is not student, redirect home
    if (profile && profile.role !== 'student')
      return <Navigate to='/' replace />;
    // Otherwise, show a brief loader while profile initializes
    return (
      <div className='min-h-screen flex items-center justify-center bg-gray-100'>
        <div className='text-center'>
          <div className='animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4'></div>
          <p className='text-muted-foreground'>Preparing your accessΓÇª</p>
        </div>
      </div>
    );
  }

  return children;
};

export default StudentRoute;

import * as React from 'react';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '@/lib/utils';

const badgeVariants = cva(
  'inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2',
  {
    variants: {
      variant: {
        default:
          'border-transparent bg-primary text-primary-foreground hover:bg-primary/80',
        secondary:
          'border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80',
        destructive:
          'border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80',
        outline: 'text-foreground',
      },
    },
    defaultVariants: {
      variant: 'default',
    },
  }
);

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <div className={cn(badgeVariants({ variant }), className)} {...props} />
  );
}

export { Badge, badgeVariants };

import * as React from 'react';
import { Slot } from '@radix-ui/react-slot';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '@/lib/utils';

