import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { CheckCircle, XCircle, AlertTriangle, QrCode } from 'lucide-react';
import { verifiableCredentialServiceSimple } from '../../services/verifiableCredentialServiceSimple';

export const CredentialVerificationPage: React.FC = () => {
  const [verificationToken, setVerificationToken] = useState('');
  const [verificationResult, setVerificationResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const handleVerification = async () => {
    if (!verificationToken.trim()) return;

    setLoading(true);
    try {
      const result =
        await verifiableCredentialServiceSimple.verifyCredential(
          verificationToken
        );
      setVerificationResult(result);
    } catch (error) {
      console.error('Verification failed:', error);
      setVerificationResult({
        status: 'invalid',
        errors: ['Verification failed'],
      });
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'valid':
        return <CheckCircle className='h-6 w-6 text-green-600' />;
      case 'revoked':
        return <XCircle className='h-6 w-6 text-red-600' />;
      default:
        return <AlertTriangle className='h-6 w-6 text-yellow-600' />;
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'valid':
        return 'bg-green-50 border-green-200';
      case 'revoked':
        return 'bg-red-50 border-red-200';
      default:
        return 'bg-yellow-50 border-yellow-200';
    }
  };

  return (
    <div className='max-w-4xl mx-auto p-6 space-y-6'>
      <Card>
        <CardHeader>
          <CardTitle className='flex items-center space-x-2'>
            <QrCode className='h-6 w-6 text-blue-600' />
            <span>Verify Credential</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className='space-y-4'>
            <div>
              <label className='block text-sm font-medium mb-2'>
                Verification Token or QR Code URL
              </label>
              <div className='flex space-x-2'>
                <Input
                  value={verificationToken}
                  onChange={e => setVerificationToken(e.target.value)}
                  placeholder='Enter verification token or scan QR code'
                  className='flex-1'
                />
                <Button
                  onClick={handleVerification}
                  disabled={loading || !verificationToken.trim()}
                >
                  {loading ? 'Verifying...' : 'Verify'}
                </Button>
              </div>
            </div>

            <div className='text-sm text-gray-600'>
              <p>You can verify a credential by:</p>
              <ul className='list-disc list-inside mt-1 space-y-1'>
                <li>Scanning the QR code from a credential</li>
                <li>Pasting the verification URL</li>
                <li>Entering the short token directly</li>
              </ul>
            </div>
          </div>
        </CardContent>
      </Card>

      {verificationResult && (
        <Card className={getStatusColor(verificationResult.status)}>
          <CardHeader>
            <CardTitle className='flex items-center space-x-2'>
              {getStatusIcon(verificationResult.status)}
              <span>Verification Result</span>
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className='space-y-4'>
              <div className='flex items-center space-x-2'>
                <span className='font-medium'>Status:</span>
                <Badge
                  variant={
                    verificationResult.status === 'valid'
                      ? 'default'
                      : 'destructive'
                  }
                >
                  {verificationResult.status.toUpperCase()}
                </Badge>
              </div>

              {verificationResult.status === 'valid' && (
                <div className='space-y-3'>
                  <div>
                    <h3 className='font-semibold text-lg'>
                      {verificationResult.credentialSubject?.title ||
                        'Credential'}
                    </h3>
                    <p className='text-sm text-gray-600'>
                      Issued by:{' '}
                      {verificationResult.issuer?.name || 'Unknown Issuer'}
                    </p>
                  </div>

                  <div className='grid grid-cols-2 gap-4 text-sm'>
                    <div>
                      <span className='font-medium'>Activity Type:</span>
                      <p>
                        {verificationResult.credentialSubject?.activityType ||
                          'N/A'}
                      </p>
                    </div>
                    <div>
                      <span className='font-medium'>Role:</span>
                      <p>
                        {verificationResult.credentialSubject?.role || 'N/A'}
                      </p>
                    </div>
                    <div>
                      <span className='font-medium'>Organizer:</span>
                      <p>
                        {verificationResult.credentialSubject?.organizer ||
                          'N/A'}
                      </p>
                    </div>
                    <div>
                      <span className='font-medium'>Hours:</span>
                      <p>
                        {verificationResult.credentialSubject?.hours || 'N/A'}
                      </p>
                    </div>
                    <div>
                      <span className='font-medium'>Issued Date:</span>
                      <p>
                        {verificationResult.issuedAt
                          ? new Date(
                              verificationResult.issuedAt
                            ).toLocaleDateString()
                          : 'N/A'}
                      </p>
                    </div>
                    <div>
                      <span className='font-medium'>Location:</span>
                      <p>
                        {verificationResult.credentialSubject?.location ||
                          'N/A'}
                      </p>
                    </div>
                  </div>

                  <div className='flex space-x-2'>
                    <Badge variant='outline'>
                      Signature:{' '}
                      {verificationResult.signatureValid ? 'Valid' : 'Invalid'}
                    </Badge>
                    <Badge variant='outline'>
                      Evidence:{' '}
                      {verificationResult.evidenceValidated
                        ? 'Validated'
                        : 'Not Validated'}
                    </Badge>
                  </div>
                </div>
              )}

              {verificationResult.status === 'revoked' && (
                <Alert>
                  <XCircle className='h-4 w-4' />
                  <AlertDescription>
                    This credential has been revoked.
                    {verificationResult.revocationReason && (
                      <span>
                        {' '}
                        Reason: {verificationResult.revocationReason}
                      </span>
                    )}
                  </AlertDescription>
                </Alert>
              )}

              {verificationResult.errors &&
                verificationResult.errors.length > 0 && (
                  <Alert>
                    <AlertTriangle className='h-4 w-4' />
                    <AlertDescription>
                      <div>
                        <p className='font-medium'>Verification Errors:</p>
                        <ul className='list-disc list-inside mt-1'>
                          {verificationResult.errors.map(
                            (error: string, index: number) => (
                              <li key={index}>{error}</li>
                            )
                          )}
                        </ul>
                      </div>
                    </AlertDescription>
                  </Alert>
                )}
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { CheckCircle, XCircle, AlertTriangle, QrCode, Bug } from 'lucide-react';
import { verifiableCredentialServiceSimple } from '../../services/verifiableCredentialServiceSimple';
import { supabase } from '@/integrations/supabase/client';

export const DebugVerification: React.FC = () => {
  const [verificationToken, setVerificationToken] = useState('');
  const [debugInfo, setDebugInfo] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const handleDebugVerification = async () => {
    if (!verificationToken.trim()) return;

    setLoading(true);
    setDebugInfo(null);

    try {
      console.log('=== DEBUG VERIFICATION START ===');
      console.log('Token:', verificationToken);

      // Step 1: Check if credential exists in database
      console.log('Step 1: Checking database for credential...');
      const { data: vcData, error: vcError } = await supabase
        .from('verifiable_credentials')
        .select('*')
        .eq('short_token', verificationToken)
        .single();

      console.log('Database query result:', { vcData, vcError });

      if (vcError || !vcData) {
        setDebugInfo({
          step: 'database_lookup',
          error: 'Credential not found in database',
          details: vcError?.message || 'No data returned',
        });
        return;
      }

      // Step 2: Check issuer
      console.log('Step 2: Checking issuer...');
      const { data: issuer, error: issuerError } = await supabase
        .from('issuers')
        .select('*')
        .eq('id', vcData.issuer_id)
        .single();

      console.log('Issuer query result:', { issuer, issuerError });

      // Step 3: Try verification
      console.log('Step 3: Attempting verification...');
      const verification =
        await verifiableCredentialServiceSimple.verifyCredential(
          verificationToken
        );
      console.log('Verification result:', verification);

      // Step 4: Check JWKS
      console.log('Step 4: Checking JWKS...');
      const { data: jwksData, error: jwksError } = await supabase
        .from('issuers')
        .select('public_key_jwk, sign_key_id')
        .eq('status', 'active');

      console.log('JWKS data:', { jwksData, jwksError });

      setDebugInfo({
        step: 'complete',
        vcData,
        issuer,
        verification,
        jwksData,
        errors: {
          vcError: vcError?.message,
          issuerError: issuerError?.message,
          jwksError: jwksError?.message,
        },
      });

      console.log('=== DEBUG VERIFICATION END ===');
    } catch (error) {
      console.error('Debug verification failed:', error);
      setDebugInfo({
        step: 'error',
        error: error instanceof Error ? error.message : 'Unknown error',
        details: error,
      });
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'valid':
        return <CheckCircle className='h-6 w-6 text-green-600' />;
      case 'revoked':
        return <XCircle className='h-6 w-6 text-red-600' />;
      default:
        return <AlertTriangle className='h-6 w-6 text-yellow-600' />;
    }
  };

  return (
    <div className='max-w-6xl mx-auto p-6 space-y-6'>
      <Card>
        <CardHeader>
          <CardTitle className='flex items-center space-x-2'>
            <Bug className='h-6 w-6 text-red-600' />
            <span>Debug Credential Verification</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className='space-y-4'>
            <div>
              <label className='block text-sm font-medium mb-2'>
                Verification Token
              </label>
              <div className='flex space-x-2'>
                <Input
                  value={verificationToken}
                  onChange={e => setVerificationToken(e.target.value)}
                  placeholder='Enter verification token'
                  className='flex-1'
                />
                <Button
                  onClick={handleDebugVerification}
                  disabled={loading || !verificationToken.trim()}
                >
                  {loading ? 'Debugging...' : 'Debug Verify'}
                </Button>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      {debugInfo && (
        <div className='space-y-4'>
          <Card>
            <CardHeader>
              <CardTitle className='flex items-center space-x-2'>
                {getStatusIcon(
                  debugInfo.step === 'complete' ? 'valid' : 'invalid'
                )}
                <span>Debug Results</span>
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className='space-y-4'>
                <div>
                  <h3 className='font-semibold mb-2'>Step: {debugInfo.step}</h3>
                  {debugInfo.error && (
                    <Alert>
                      <AlertTriangle className='h-4 w-4' />
                      <AlertDescription>
                        <strong>Error:</strong> {debugInfo.error}
                        {debugInfo.details && (
                          <div className='mt-2'>
                            <strong>Details:</strong>{' '}
                            {JSON.stringify(debugInfo.details, null, 2)}
                          </div>
                        )}
                      </AlertDescription>
                    </Alert>
                  )}
                </div>

                {debugInfo.vcData && (
                  <div>
                    <h4 className='font-semibold mb-2'>Credential Data:</h4>
                    <pre className='bg-gray-100 p-3 rounded text-xs overflow-auto'>
                      {JSON.stringify(debugInfo.vcData, null, 2)}
                    </pre>
                  </div>
                )}

                {debugInfo.issuer && (
                  <div>
                    <h4 className='font-semibold mb-2'>Issuer Data:</h4>
                    <pre className='bg-gray-100 p-3 rounded text-xs overflow-auto'>
                      {JSON.stringify(debugInfo.issuer, null, 2)}
                    </pre>
                  </div>
                )}

                {debugInfo.verification && (
                  <div>
                    <h4 className='font-semibold mb-2'>Verification Result:</h4>
                    <pre className='bg-gray-100 p-3 rounded text-xs overflow-auto'>
                      {JSON.stringify(debugInfo.verification, null, 2)}
                    </pre>
                  </div>
                )}

                {debugInfo.jwksData && (
                  <div>
                    <h4 className='font-semibold mb-2'>JWKS Data:</h4>
                    <pre className='bg-gray-100 p-3 rounded text-xs overflow-auto'>
                      {JSON.stringify(debugInfo.jwksData, null, 2)}
                    </pre>
                  </div>
                )}

                {debugInfo.errors && (
                  <div>
                    <h4 className='font-semibold mb-2'>Errors:</h4>
                    <pre className='bg-red-100 p-3 rounded text-xs overflow-auto'>
                      {JSON.stringify(debugInfo.errors, null, 2)}
                    </pre>
                  </div>
                )}
              </div>
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
