interface Credential {
  id: string;
  vc_id: string;
  student_id: string;
  issuer_id: string;
  activity_id?: string;
  credential_json: any;
  short_token: string;
  issued_at: string;
  expires_at: string;
  revoked_at?: string;
  revocation_reason?: string;
  student: {
    id: string;
    full_name: string;
    email: string;
  };
}

interface IssueCredentialFormData {
  studentId: string;
  activityTitle: string;
  activityType: string;
  organizer: string;
  role: string;
  date: string;
  location: string;
  hours: number;
  department: string;
  description: string;
}

export const FacultyCredentials: React.FC = () => {
  const { profile } = useProfile();
  const [credentials, setCredentials] = useState<Credential[]>([]);
  const [students, setStudents] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isIssueModalOpen, setIsIssueModalOpen] = useState(false);
  const [formData, setFormData] = useState<IssueCredentialFormData>({
    studentId: '',
    activityTitle: '',
    activityType: 'Conference',
    organizer: '',
    role: 'Participant',
    date: '',
    location: '',
    hours: 1,
    department: '',
    description: '',
  });

  useEffect(() => {
    if (profile) {
      fetchCredentials();
      fetchStudents();
    }
  }, [profile]);

  const fetchCredentials = async () => {
    if (!profile) {
      console.log('No profile found');
      return;
    }

    console.log('Fetching credentials for profile:', profile.email);
    setLoading(true);

    try {
      // Get faculty record by email (fallback to user_id if needed)
      console.log('Looking up faculty by email:', profile.email);
      let { data: facultyData, error: facultyError } = await supabase
        .from('faculty')
        .select('id, email, name, user_id')
        .eq('email', profile.email)
        .single();

      // If not found by email, try by user_id
      if (facultyError && profile.id) {
        console.log('Faculty not found by email, trying user_id:', profile.id);
        const { data: facultyDataByUserId, error: facultyErrorByUserId } =
          await supabase
            .from('faculty')
            .select('id, email, name, user_id')
            .eq('user_id', profile.id)
            .single();

        if (!facultyErrorByUserId && facultyDataByUserId) {
          facultyData = facultyDataByUserId;
          facultyError = null;
        }
      }

      console.log('Faculty lookup result:', { facultyData, facultyError });

      if (facultyError || !facultyData) {
        console.error('Faculty not found:', facultyError);
        console.log('Falling back to show all credentials for debugging...');

        // Fallback: show all credentials for debugging
        const { data: allCredentials, error: allCredentialsError } =
          await supabase
            .from('verifiable_credentials')
            .select(
              `
            *,
            student:profiles!verifiable_credentials_student_id_fkey(
              id,
              full_name,
              email
            )
          `
            )
            .order('issued_at', { ascending: false })
            .limit(10);

        console.log('All credentials (fallback):', allCredentials);
        setCredentials(allCredentials || []);
        setLoading(false);
        return;
      }

      console.log('Faculty found:', facultyData);

      // Get credentials issued by this faculty
      // Since we now use a default issuer, we need to find credentials by checking the faculty info in metadata
      console.log('Fetching credentials for faculty:', facultyData.id);

      // First, let's try to get all credentials and filter by faculty info in metadata
      const { data: allCredentials, error: allCredentialsError } =
        await supabase
          .from('verifiable_credentials')
          .select(
            `
          *,
          student:profiles!verifiable_credentials_student_id_fkey(
            id,
            full_name,
            email
          )
        `
          )
          .order('issued_at', { ascending: false });

      if (allCredentialsError) {
        console.error('Error fetching all credentials:', allCredentialsError);
        setLoading(false);
        return;
      }

      // Filter credentials by faculty info in metadata
      const credentialsData =
        allCredentials?.filter(cred => {
          const facultyInfo =
            cred.credential_json?.credentialSubject?.metadata?.issuedByFaculty;
          return facultyInfo && facultyInfo.id === facultyData.id;
        }) || [];

      console.log('Filtered credentials for faculty:', credentialsData);
      console.log('Number of credentials found:', credentialsData?.length || 0);
      setCredentials(credentialsData || []);
    } catch (error) {
      console.error('Error fetching credentials:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchStudents = async () => {
    if (!profile) return;

    try {
      // Get faculty record by email (fallback to user_id if needed)
      let { data: facultyData, error: facultyError } = await supabase
        .from('faculty')
        .select('id')
        .eq('email', profile.email)
        .single();

      // If not found by email, try by user_id
      if (facultyError && profile.id) {
        const { data: facultyDataByUserId, error: facultyErrorByUserId } =
          await supabase
            .from('faculty')
            .select('id')
            .eq('user_id', profile.id)
            .single();

        if (!facultyErrorByUserId && facultyDataByUserId) {
          facultyData = facultyDataByUserId;
          facultyError = null;
        }
      }

      if (facultyError || !facultyData) {
        console.error('Faculty not found');
        return;
      }

      // Get assigned students
      const { data: assignmentsData, error: assignmentsError } = await supabase
        .from('student_mentor_assignments')
        .select(
          `
          student:profiles!student_mentor_assignments_student_id_fkey(
            id,
            full_name,
            email
          )
        `
        )
        .eq('mentor_id', facultyData.id);

      if (assignmentsError) {
        console.error('Error fetching students:', assignmentsError);
        return;
      }

      const studentsData =
        assignmentsData
          ?.map(assignment => assignment.student)
          .filter(Boolean) || [];
      setStudents(studentsData);
    } catch (error) {
      console.error('Error fetching students:', error);
    }
  };

  const handleIssueCredential = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!profile) {
      console.log('No profile found for credential issuance');
      return;
    }

    console.log('Issuing credential with data:', formData);
    console.log('Profile ID:', profile.id);

    try {
      setLoading(true);

      const credential =
        await verifiableCredentialServiceSimple.issueCredential({
          studentId: formData.studentId,
          evidenceIds: [], // No evidence files for now
          issuedByUserId: profile.id,
          activityData: {
            title: formData.activityTitle,
            type: formData.activityType,
            organizer: formData.organizer,
            role: formData.role,
            date: formData.date,
            location: formData.location,
            hours: formData.hours,
            department: formData.department,
          },
        });

      console.log('Credential issued successfully:', credential);

      // Reset form
      setFormData({
        studentId: '',
        activityTitle: '',
        activityType: 'Conference',
        organizer: '',
        role: 'Participant',
        date: '',
        location: '',
        hours: 1,
        department: '',
        description: '',
      });

      setIsIssueModalOpen(false);

      // Refresh credentials list
      console.log('Refreshing credentials list...');
      await fetchCredentials();

      alert('Credential issued successfully!');
    } catch (error) {
      console.error('Error issuing credential:', error);
      alert('Failed to issue credential. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const filteredCredentials = credentials.filter(
    credential =>
      credential.student?.full_name
        ?.toLowerCase()
        .includes(searchTerm.toLowerCase()) ||
      credential.credential_json?.credentialSubject?.title
        ?.toLowerCase()
        .includes(searchTerm.toLowerCase()) ||
      credential.credential_json?.credentialSubject?.organizer
        ?.toLowerCase()
        .includes(searchTerm.toLowerCase())
  );

  const getStatusIcon = (credential: Credential) => {
    if (credential.revoked_at) {
      return <XCircle className='h-4 w-4 text-red-500' />;
    }
    if (new Date(credential.expires_at) < new Date()) {
      return <Clock className='h-4 w-4 text-amber-500' />;
    }
    return <CheckCircle className='h-4 w-4 text-green-500' />;
  };

  const getStatusBadge = (credential: Credential) => {
    if (credential.revoked_at) {
      return <Badge variant='destructive'>Revoked</Badge>;
    }
    if (new Date(credential.expires_at) < new Date()) {
      return <Badge variant='secondary'>Expired</Badge>;
    }
    return <Badge variant='default'>Active</Badge>;
  };

  return (
    <div className='space-y-6'>
      {/* Header */}
      <div className='flex justify-between items-center'>
        <div>
          <h2 className='text-2xl font-bold'>Issue Credentials</h2>
          <p className='text-muted-foreground'>
            Issue verifiable credentials to students
          </p>
        </div>
        <Dialog open={isIssueModalOpen} onOpenChange={setIsIssueModalOpen}>
          <DialogTrigger asChild>
            <Button className='bg-violet-100 hover:bg-violet-200 text-violet-700 border border-violet-200'>
              <Plus className='h-4 w-4 mr-2' />
              Issue Credential
            </Button>
          </DialogTrigger>
          <DialogContent className='max-w-2xl max-h-[90vh] overflow-y-auto'>
            <DialogHeader>
              <DialogTitle>Issue New Credential</DialogTitle>
            </DialogHeader>
            <form onSubmit={handleIssueCredential} className='space-y-4'>
              <div className='grid grid-cols-2 gap-4'>
                <div className='space-y-2'>
                  <Label htmlFor='studentId'>Student</Label>
                  <Select
                    value={formData.studentId}
                    onValueChange={value =>
                      setFormData({ ...formData, studentId: value })
                    }
                    required
                  >
                    <SelectTrigger>
                      <SelectValue placeholder='Select student' />
                    </SelectTrigger>
                    <SelectContent>
                      {students.map(student => (
                        <SelectItem key={student.id} value={student.id}>
                          {student.full_name} ({student.email})
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className='space-y-2'>
                  <Label htmlFor='activityType'>Activity Type</Label>
                  <Select
                    value={formData.activityType}
                    onValueChange={value =>
                      setFormData({ ...formData, activityType: value })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value='Conference'>Conference</SelectItem>
                      <SelectItem value='Workshop'>Workshop</SelectItem>
                      <SelectItem value='Seminar'>Seminar</SelectItem>
                      <SelectItem value='Competition'>Competition</SelectItem>
                      <SelectItem value='Project'>Project</SelectItem>
                      <SelectItem value='Internship'>Internship</SelectItem>
                      <SelectItem value='Research'>Research</SelectItem>
                      <SelectItem value='Volunteer'>Volunteer</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className='space-y-2'>
                <Label htmlFor='activityTitle'>Activity Title</Label>
                <Input
                  id='activityTitle'
                  value={formData.activityTitle}
                  onChange={e =>
                    setFormData({ ...formData, activityTitle: e.target.value })
                  }
                  placeholder='e.g., International Conference on AI'
                  required
                />
              </div>

              <div className='grid grid-cols-2 gap-4'>
                <div className='space-y-2'>
                  <Label htmlFor='organizer'>Organizer</Label>
                  <Input
                    id='organizer'
                    value={formData.organizer}
                    onChange={e =>
                      setFormData({ ...formData, organizer: e.target.value })
                    }
                    placeholder='e.g., IEEE Computer Society'
                    required
                  />
                </div>

                <div className='space-y-2'>
                  <Label htmlFor='role'>Role</Label>
                  <Input
                    id='role'
                    value={formData.role}
                    onChange={e =>
                      setFormData({ ...formData, role: e.target.value })
                    }
                    placeholder='e.g., Presenter, Participant'
                    required
                  />
                </div>
              </div>

              <div className='grid grid-cols-2 gap-4'>
                <div className='space-y-2'>
                  <Label htmlFor='date'>Date</Label>
                  <Input
                    id='date'
                    type='date'
                    value={formData.date}
                    onChange={e =>
                      setFormData({ ...formData, date: e.target.value })
                    }
                    required
                  />
                </div>

                <div className='space-y-2'>
                  <Label htmlFor='hours'>Hours</Label>
                  <Input
                    id='hours'
                    type='number'
                    min='1'
                    value={formData.hours}
                    onChange={e =>
                      setFormData({
                        ...formData,
                        hours: parseInt(e.target.value) || 1,
                      })
                    }
                    required
                  />
                </div>
              </div>

              <div className='space-y-2'>
                <Label htmlFor='location'>Location</Label>
                <Input
                  id='location'
                  value={formData.location}
                  onChange={e =>
                    setFormData({ ...formData, location: e.target.value })
                  }
                  placeholder='e.g., Mumbai, India'
                />
              </div>

              <div className='space-y-2'>
                <Label htmlFor='department'>Department</Label>
                <Input
                  id='department'
                  value={formData.department}
                  onChange={e =>
                    setFormData({ ...formData, department: e.target.value })
                  }
                  placeholder='e.g., Computer Science'
                  required
                />
              </div>

              <div className='space-y-2'>
                <Label htmlFor='description'>Description (Optional)</Label>
                <Textarea
                  id='description'
                  value={formData.description}
                  onChange={e =>
                    setFormData({ ...formData, description: e.target.value })
                  }
                  placeholder='Additional details about the activity...'
                  rows={3}
                />
              </div>

              <div className='flex justify-end space-x-2'>
                <Button
                  type='button'
                  variant='outline'
                  onClick={() => setIsIssueModalOpen(false)}
                >
                  Cancel
                </Button>
                <Button type='submit' disabled={loading}>
                  {loading ? 'Issuing...' : 'Issue Credential'}
                </Button>
              </div>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      {/* Search */}
      <div className='flex items-center space-x-2'>
        <div className='relative flex-1 max-w-sm'>
          <Search className='absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground h-4 w-4' />
          <Input
            placeholder='Search credentials...'
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            className='pl-10'
          />
        </div>
      </div>

      {/* Credentials List */}
      <Card>
        <CardHeader>
          <CardTitle className='flex items-center gap-2'>
            <Award className='h-5 w-5' />
            Issued Credentials ({credentials.length})
          </CardTitle>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className='text-center py-8'>Loading credentials...</div>
          ) : filteredCredentials.length === 0 ? (
            <div className='text-center py-8 text-muted-foreground'>
              <Award className='h-12 w-12 mx-auto mb-4 opacity-50' />
              <p>No credentials issued yet</p>
              <p className='text-sm'>
                Issue your first credential to get started
              </p>
            </div>
          ) : (
            <div className='space-y-4'>
              {filteredCredentials.map(credential => (
                <div
                  key={credential.id}
                  className='border rounded-lg p-4 space-y-3'
                >
                  <div className='flex justify-between items-start'>
                    <div className='flex-1'>
                      <div className='flex items-center space-x-2 mb-2'>
                        {getStatusIcon(credential)}
                        <h3 className='font-semibold'>
                          {credential.credential_json?.credentialSubject
                            ?.title || 'Activity Credential'}
                        </h3>
                        {getStatusBadge(credential)}
                      </div>

                      <div className='grid grid-cols-2 gap-4 text-sm text-muted-foreground'>
                        <div>
                          <span className='font-medium'>Student:</span>{' '}
                          {credential.student?.full_name}
                        </div>
                        <div>
                          <span className='font-medium'>Organizer:</span>{' '}
                          {
                            credential.credential_json?.credentialSubject
                              ?.organizer
                          }
                        </div>
                        <div>
                          <span className='font-medium'>Role:</span>{' '}
                          {credential.credential_json?.credentialSubject?.role}
                        </div>
                        <div>
                          <span className='font-medium'>Date:</span>{' '}
                          {new Date(credential.issued_at).toLocaleDateString()}
                        </div>
                        <div>
                          <span className='font-medium'>Hours:</span>{' '}
                          {credential.credential_json?.credentialSubject?.hours}
                        </div>
                        <div>
                          <span className='font-medium'>Expires:</span>{' '}
                          {new Date(credential.expires_at).toLocaleDateString()}
                        </div>
                      </div>
                    </div>

                    <div className='flex space-x-2'>
                      <Button
                        size='sm'
                        variant='outline'
                        onClick={() =>
                          window.open(
                            `/verify?t=${credential.short_token}`,
                            '_blank'
                          )
                        }
                      >
                        <Eye className='h-4 w-4 mr-1' />
                        View
                      </Button>
                      <Button
                        size='sm'
                        variant='outline'
                        onClick={() => {
                          const dataStr = JSON.stringify(
                            credential.credential_json,
                            null,
                            2
                          );
                          const dataUri =
                            'data:application/json;charset=utf-8,' +
                            encodeURIComponent(dataStr);
                          const linkElement = document.createElement('a');
                          linkElement.setAttribute('href', dataUri);
                          linkElement.setAttribute(
                            'download',
                            `credential-${credential.vc_id.split(':').pop()}.json`
                          );
                          linkElement.click();
                        }}
                      >
                        <Download className='h-4 w-4 mr-1' />
                        Download
                      </Button>
                    </div>
                  </div>

                  {credential.revoked_at && (
                    <div className='bg-red-50 border border-red-200 rounded p-3'>
                      <p className='text-sm text-red-800'>
                        <strong>Revoked:</strong>{' '}
                        {credential.revocation_reason || 'No reason provided'}
                      </p>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import {
  Shield,
  Upload,
  X,
  Plus,
  Calendar,
  Clock,
  MapPin,
  Building,
  User,
  FileText,
  CheckCircle,
} from 'lucide-react';
import { verifiableCredentialService } from '../../services/verifiableCredentialService';
import { toast } from '@/hooks/use-toast';

interface IssueCredentialModalProps {
  studentId: string;
  studentName: string;
  activityId?: string;
  onCredentialIssued?: (credential: any) => void;
  children: React.ReactNode;
}

interface EvidenceFile {
  id: string;
  file: File;
  name: string;
  type: string;
  size: number;
}

export const IssueCredentialModal: React.FC<IssueCredentialModalProps> = ({
  studentId,
  studentName,
  activityId,
  onCredentialIssued,
  children,
}) => {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);
  const [evidenceFiles, setEvidenceFiles] = useState<EvidenceFile[]>([]);
  const [formData, setFormData] = useState({
    title: '',
    activityType: '',
    organizer: '',
    role: '',
    date: new Date().toISOString().split('T')[0],
    location: '',
    hours: 1,
    department: '',
    description: '',
  });

  const activityTypes = [
    'Conference',
    'Workshop',
    'Seminar',
    'Training',
    'Competition',
    'Project',
    'Research',
    'Internship',
    'Volunteer Work',
    'Other',
  ];

  const roles = [
    'Participant',
    'Presenter',
    'Speaker',
    'Organizer',
    'Volunteer',
    'Mentor',
    'Judge',
    'Team Lead',
    'Researcher',
    'Other',
  ];

  const handleInputChange = (field: string, value: any) => {
    setFormData(prev => ({
      ...prev,
      [field]: value,
    }));
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const evidenceFile: EvidenceFile = {
        id: Math.random().toString(36).substr(2, 9),
        file,
        name: file.name,
        type: file.type,
        size: file.size,
      };
      setEvidenceFiles(prev => [...prev, evidenceFile]);
    });
  };

  const removeEvidenceFile = (id: string) => {
    setEvidenceFiles(prev => prev.filter(file => file.id !== id));
  };

  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const validateForm = () => {
    const required = [
      'title',
      'activityType',
      'organizer',
      'role',
      'date',
      'hours',
      'department',
    ];
    const missing = required.filter(
      field => !formData[field as keyof typeof formData]
    );

    if (missing.length > 0) {
      toast({
        title: 'Validation Error',
        description: `Please fill in: ${missing.join(', ')}`,
        variant: 'destructive',
      });
      return false;
    }

    if (formData.hours < 1) {
      toast({
        title: 'Validation Error',
        description: 'Hours must be at least 1',
        variant: 'destructive',
      });
      return false;
    }

    return true;
  };

  const handleIssueCredential = async () => {
    if (!validateForm()) return;

    try {
      setLoading(true);

      const result = await verifiableCredentialService.issueCredential({
        activityId: activityId || '',
        studentId,
        evidenceIds: evidenceFiles.map(f => f.id),
        issuedByUserId: '', // This would come from auth context
        activityData: {
          title: formData.title,
          type: formData.activityType,
          organizer: formData.organizer,
          role: formData.role,
          date: formData.date,
          location: formData.location || undefined,
          hours: formData.hours,
          department: formData.department,
        },
      });

      toast({
        title: 'Success',
        description: 'Credential issued successfully',
      });

      onCredentialIssued?.(result);
      setOpen(false);
      resetForm();
    } catch (error) {
      console.error('Error issuing credential:', error);
      toast({
        title: 'Error',
        description: 'Failed to issue credential',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setFormData({
      title: '',
      activityType: '',
      organizer: '',
      role: '',
      date: new Date().toISOString().split('T')[0],
      location: '',
      hours: 1,
      department: '',
      description: '',
    });
    setEvidenceFiles([]);
    setStep(1);
  };

  const nextStep = () => {
    if (step === 1 && validateForm()) {
      setStep(2);
    }
  };

  const prevStep = () => {
    setStep(step - 1);
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>{children}</DialogTrigger>

      <DialogContent className='max-w-4xl max-h-[90vh] overflow-y-auto'>
        <DialogHeader>
          <DialogTitle className='flex items-center space-x-2'>
            <Shield className='h-6 w-6 text-blue-600' />
            <span>Issue Verifiable Credential</span>
          </DialogTitle>
        </DialogHeader>

        <div className='space-y-6'>
          {/* Student Info */}
          <Card>
            <CardHeader>
              <CardTitle className='text-lg flex items-center'>
                <User className='h-5 w-5 mr-2' />
                Student Information
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className='flex items-center space-x-2'>
                <Badge variant='secondary'>{studentName}</Badge>
                <span className='text-sm text-gray-600'>ID: {studentId}</span>
              </div>
            </CardContent>
          </Card>

          {/* Progress Steps */}
          <div className='flex items-center space-x-4'>
            <div
              className={`flex items-center space-x-2 ${step >= 1 ? 'text-blue-600' : 'text-gray-400'}`}
            >
              <div
                className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${
                  step >= 1
                    ? 'bg-blue-600 text-white'
                    : 'bg-gray-200 text-gray-600'
                }`}
              >
                1
              </div>
              <span className='text-sm font-medium'>Activity Details</span>
            </div>
            <div className='flex-1 h-px bg-gray-200'></div>
            <div
              className={`flex items-center space-x-2 ${step >= 2 ? 'text-blue-600' : 'text-gray-400'}`}
            >
              <div
                className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${
                  step >= 2
                    ? 'bg-blue-600 text-white'
                    : 'bg-gray-200 text-gray-600'
                }`}
              >
                2
              </div>
              <span className='text-sm font-medium'>Evidence & Review</span>
            </div>
          </div>

          {/* Step 1: Activity Details */}
          {step === 1 && (
            <div className='space-y-4'>
              <div className='grid grid-cols-1 md:grid-cols-2 gap-4'>
                <div>
                  <Label htmlFor='title'>Activity Title *</Label>
                  <Input
                    id='title'
                    value={formData.title}
                    onChange={e => handleInputChange('title', e.target.value)}
                    placeholder='e.g., International Conference on AI'
                  />
                </div>

                <div>
                  <Label htmlFor='activityType'>Activity Type *</Label>
                  <Select
                    value={formData.activityType}
                    onValueChange={value =>
                      handleInputChange('activityType', value)
                    }
                  >
                    <SelectTrigger>
                      <SelectValue placeholder='Select activity type' />
                    </SelectTrigger>
                    <SelectContent>
                      {activityTypes.map(type => (
                        <SelectItem key={type} value={type}>
                          {type}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label htmlFor='organizer'>Organizer *</Label>
                  <Input
                    id='organizer'
                    value={formData.organizer}
                    onChange={e =>
                      handleInputChange('organizer', e.target.value)
                    }
                    placeholder='e.g., IEEE Computer Society'
                  />
                </div>

                <div>
                  <Label htmlFor='role'>Student Role *</Label>
                  <Select
                    value={formData.role}
                    onValueChange={value => handleInputChange('role', value)}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder='Select role' />
                    </SelectTrigger>
                    <SelectContent>
                      {roles.map(role => (
                        <SelectItem key={role} value={role}>
                          {role}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label htmlFor='date'>Date *</Label>
                  <Input
                    id='date'
                    type='date'
                    value={formData.date}
                    onChange={e => handleInputChange('date', e.target.value)}
                  />
                </div>

                <div>
                  <Label htmlFor='hours'>Duration (hours) *</Label>
                  <Input
                    id='hours'
                    type='number'
                    min='1'
                    value={formData.hours}
                    onChange={e =>
                      handleInputChange('hours', parseInt(e.target.value) || 1)
                    }
                  />
                </div>

                <div>
                  <Label htmlFor='location'>Location</Label>
                  <Input
                    id='location'
                    value={formData.location}
                    onChange={e =>
                      handleInputChange('location', e.target.value)
                    }
                    placeholder='e.g., Mumbai, India'
                  />
                </div>

                <div>
                  <Label htmlFor='department'>Department *</Label>
                  <Input
                    id='department'
                    value={formData.department}
                    onChange={e =>
                      handleInputChange('department', e.target.value)
                    }
                    placeholder='e.g., Computer Science'
                  />
                </div>
              </div>

              <div>
                <Label htmlFor='description'>Description</Label>
                <Textarea
                  id='description'
                  value={formData.description}
                  onChange={e =>
                    handleInputChange('description', e.target.value)
                  }
                  placeholder='Additional details about the activity...'
                  rows={3}
                />
              </div>
            </div>
          )}

          {/* Step 2: Evidence & Review */}
          {step === 2 && (
            <div className='space-y-6'>
              {/* Evidence Files */}
              <div>
                <Label>Evidence Files</Label>
                <div className='mt-2'>
                  <input
                    type='file'
                    multiple
                    onChange={handleFileUpload}
                    className='hidden'
                    id='evidence-upload'
                    accept='.pdf,.jpg,.jpeg,.png,.doc,.docx'
                  />
                  <label
                    htmlFor='evidence-upload'
                    className='flex items-center justify-center w-full h-32 border-2 border-dashed border-gray-300 rounded-lg cursor-pointer hover:border-gray-400'
                  >
                    <div className='text-center'>
                      <Upload className='h-8 w-8 text-gray-400 mx-auto mb-2' />
                      <p className='text-sm text-gray-600'>
                        Click to upload evidence files
                      </p>
                      <p className='text-xs text-gray-500'>
                        PDF, JPG, PNG, DOC supported
                      </p>
                    </div>
                  </label>
                </div>

                {evidenceFiles.length > 0 && (
                  <div className='mt-4 space-y-2'>
                    {evidenceFiles.map(file => (
                      <div
                        key={file.id}
                        className='flex items-center justify-between p-3 bg-gray-50 rounded-lg'
                      >
                        <div className='flex items-center space-x-3'>
                          <FileText className='h-5 w-5 text-gray-500' />
                          <div>
                            <p className='text-sm font-medium text-gray-900'>
                              {file.name}
                            </p>
                            <p className='text-xs text-gray-500'>
                              {formatFileSize(file.size)}
                            </p>
                          </div>
                        </div>
                        <Button
                          size='sm'
                          variant='ghost'
                          onClick={() => removeEvidenceFile(file.id)}
                        >
                          <X className='h-4 w-4' />
                        </Button>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Review */}
              <Card>
                <CardHeader>
                  <CardTitle className='text-lg'>Credential Preview</CardTitle>
                </CardHeader>
                <CardContent className='space-y-4'>
                  <div className='grid grid-cols-1 md:grid-cols-2 gap-4'>
                    <div className='space-y-2'>
                      <p className='text-sm font-medium text-gray-700'>Title</p>
                      <p className='text-gray-900'>{formData.title}</p>
                    </div>
                    <div className='space-y-2'>
                      <p className='text-sm font-medium text-gray-700'>Type</p>
                      <p className='text-gray-900'>{formData.activityType}</p>
                    </div>
                    <div className='space-y-2'>
                      <p className='text-sm font-medium text-gray-700'>
                        Organizer
                      </p>
                      <p className='text-gray-900'>{formData.organizer}</p>
                    </div>
                    <div className='space-y-2'>
                      <p className='text-sm font-medium text-gray-700'>Role</p>
                      <p className='text-gray-900'>{formData.role}</p>
                    </div>
                    <div className='space-y-2'>
                      <p className='text-sm font-medium text-gray-700'>Date</p>
                      <p className='text-gray-900'>
                        {new Date(formData.date).toLocaleDateString()}
                      </p>
                    </div>
                    <div className='space-y-2'>
                      <p className='text-sm font-medium text-gray-700'>
                        Duration
                      </p>
                      <p className='text-gray-900'>{formData.hours} hours</p>
                    </div>
                    {formData.location && (
                      <div className='space-y-2'>
                        <p className='text-sm font-medium text-gray-700'>
                          Location
                        </p>
                        <p className='text-gray-900'>{formData.location}</p>
                      </div>
                    )}
                    <div className='space-y-2'>
                      <p className='text-sm font-medium text-gray-700'>
                        Department
                      </p>
                      <p className='text-gray-900'>{formData.department}</p>
                    </div>
                  </div>

                  {evidenceFiles.length > 0 && (
                    <div className='space-y-2'>
                      <p className='text-sm font-medium text-gray-700'>
                        Evidence Files
                      </p>
                      <div className='flex flex-wrap gap-2'>
                        {evidenceFiles.map(file => (
                          <Badge key={file.id} variant='secondary'>
                            {file.name}
                          </Badge>
                        ))}
                      </div>
                    </div>
                  )}
                </CardContent>
              </Card>

              <Alert>
                <CheckCircle className='h-4 w-4' />
                <AlertDescription>
                  This credential will be digitally signed and can be verified
                  by anyone with the QR code or verification link.
                </AlertDescription>
              </Alert>
            </div>
          )}

          {/* Actions */}
          <div className='flex justify-between pt-4 border-t'>
            <div>
              {step > 1 && (
                <Button variant='outline' onClick={prevStep}>
                  Previous
                </Button>
              )}
            </div>

            <div className='flex space-x-2'>
              <Button variant='outline' onClick={() => setOpen(false)}>
                Cancel
              </Button>

              {step === 1 ? (
                <Button onClick={nextStep}>Next</Button>
              ) : (
                <Button onClick={handleIssueCredential} disabled={loading}>
                  {loading ? 'Issuing...' : 'Issue Credential'}
                </Button>
              )}
            </div>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
};

import React, { useState } from 'react';
import QRCode from 'qrcode';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import {
  Download,
  Share2,
  Copy,
  CheckCircle,
  Shield,
  Calendar,
  Clock,
  MapPin,
} from 'lucide-react';
import { toast } from '@/hooks/use-toast';

interface QRCardGeneratorProps {
  credential: {
    vcId: string;
    credentialJson: any;
    shortToken: string;
    qrUrl: string;
    credentialUrl: string;
  };
  onDownload?: () => void;
  onShare?: () => void;
}

export const QRCardGenerator: React.FC<QRCardGeneratorProps> = ({
  credential,
  onDownload,
  onShare,
}) => {
  const [qrCodeDataUrl, setQrCodeDataUrl] = useState<string>('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);

  // Generate QR code when component mounts
  React.useEffect(() => {
    generateQRCode();
  }, [credential.qrUrl]);

  const generateQRCode = async () => {
    setIsGenerating(true);
    try {
      const qrDataUrl = await QRCode.toDataURL(credential.qrUrl, {
        width: 256,
        margin: 2,
        color: {
          dark: '#000000',
          light: '#FFFFFF',
        },
        errorCorrectionLevel: 'M',
      });
      setQrCodeDataUrl(qrDataUrl);
    } catch (error) {
      console.error('Error generating QR code:', error);
      toast({
        title: 'Error',
        description: 'Failed to generate QR code',
        variant: 'destructive',
      });
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownloadCredential = async () => {
    try {
      const blob = new Blob(
        [JSON.stringify(credential.credentialJson, null, 2)],
        {
          type: 'application/json',
        }
      );
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `credential-${credential.vcId.split(':').pop()}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      onDownload?.();
      toast({
        title: 'Success',
        description: 'Credential downloaded successfully',
      });
    } catch (error) {
      console.error('Error downloading credential:', error);
      toast({
        title: 'Error',
        description: 'Failed to download credential',
        variant: 'destructive',
      });
    }
  };

  const handleCopyLink = async () => {
    try {
      await navigator.clipboard.writeText(credential.qrUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
      toast({
        title: 'Success',
        description: 'Verification link copied to clipboard',
      });
    } catch (error) {
      console.error('Error copying link:', error);
      toast({
        title: 'Error',
        description: 'Failed to copy link',
        variant: 'destructive',
      });
    }
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Verifiable Credential',
          text: `Check out my verified activity: ${credential.credentialJson.credentialSubject.title}`,
          url: credential.qrUrl,
        });
        onShare?.();
      } catch (error) {
        console.error('Error sharing:', error);
        // Fallback to copy
        handleCopyLink();
      }
    } else {
      // Fallback to copy
      handleCopyLink();
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  };

  const formatTime = (dateString: string) => {
    return new Date(dateString).toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  return (
    <div className='max-w-2xl mx-auto p-6'>
      {/* QR Card */}
      <Card className='mb-6 shadow-lg'>
        <CardHeader className='text-center pb-4'>
          <div className='flex items-center justify-center mb-4'>
            <div className='bg-green-100 p-3 rounded-full'>
              <Shield className='h-8 w-8 text-green-600' />
            </div>
          </div>
          <CardTitle className='text-2xl font-bold text-gray-900'>
            Verified Activity Credential
          </CardTitle>
