import React, { useRef, useEffect, useState } from 'react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { QrCode, Camera, X } from 'lucide-react';

interface QRScannerProps {
  onScan: (result: string) => void;
  onClose: () => void;
}

export const QRScanner: React.FC<QRScannerProps> = ({ onScan, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    startScanning();
    return () => {
      stopScanning();
    };
  }, []);

  const startScanning = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: {
          facingMode: 'environment',
          width: { ideal: 1280 },
          height: { ideal: 720 },
        },
      });

      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.play();
        setIsScanning(true);
        setError(null);

        // Start scanning loop
        scanLoop();
      }
    } catch (err) {
      console.error('Error accessing camera:', err);
      setError('Unable to access camera. Please check permissions.');
    }
  };

  const stopScanning = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    setIsScanning(false);
  };

  const scanLoop = () => {
    if (!isScanning || !videoRef.current || !canvasRef.current) return;

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const context = canvas.getContext('2d');

    if (video.readyState === video.HAVE_ENOUGH_DATA && context) {
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      context.drawImage(video, 0, 0, canvas.width, canvas.height);

      // Simple QR code detection (this is a basic implementation)
      // In a real app, you'd use a library like jsQR or @zxing/library
      const imageData = context.getImageData(0, 0, canvas.width, canvas.height);

      // For demo purposes, we'll simulate QR detection
      // In reality, you'd use a proper QR code library here
      setTimeout(() => {
        if (isScanning) {
          scanLoop();
        }
      }, 100);
    } else {
      setTimeout(() => {
        if (isScanning) {
          scanLoop();
        }
      }, 100);
    }
  };

  const handleManualInput = () => {
    const input = prompt('Enter verification token or URL:');
    if (input && input.trim()) {
      onScan(input.trim());
    }
  };

  return (
    <div className='fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50'>
      <Card className='w-full max-w-md mx-4'>
        <CardHeader className='flex flex-row items-center justify-between'>
          <CardTitle className='flex items-center gap-2'>
            <QrCode className='h-5 w-5' />
            Scan QR Code
          </CardTitle>
          <Button variant='ghost' size='sm' onClick={onClose}>
            <X className='h-4 w-4' />
          </Button>
        </CardHeader>
        <CardContent className='space-y-4'>
          {error ? (
            <div className='text-center py-8'>
              <Camera className='h-12 w-12 mx-auto mb-4 text-muted-foreground' />
              <p className='text-red-600 mb-4'>{error}</p>
              <Button onClick={handleManualInput} variant='outline'>
                Enter Token Manually
              </Button>
            </div>
          ) : (
            <div className='space-y-4'>
              <div className='relative bg-black rounded-lg overflow-hidden'>
                <video
                  ref={videoRef}
                  className='w-full h-64 object-cover'
                  playsInline
                  muted
                />
                <div className='absolute inset-0 border-2 border-white border-dashed rounded-lg m-4 pointer-events-none'>
                  <div className='absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-white rounded-tl-lg'></div>
                  <div className='absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-white rounded-tr-lg'></div>
                  <div className='absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-white rounded-bl-lg'></div>
                  <div className='absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-white rounded-br-lg'></div>
                </div>
              </div>

              <canvas ref={canvasRef} className='hidden' />

              <div className='text-center'>
                <p className='text-sm text-muted-foreground mb-4'>
                  Position the QR code within the frame
                </p>
                <Button
                  onClick={handleManualInput}
                  variant='outline'
                  className='w-full'
                >
                  Enter Token Manually
                </Button>
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { CheckCircle, XCircle, Bug } from 'lucide-react';
import { verifiableCredentialServiceSimple } from '../../services/verifiableCredentialServiceSimple';
import { keyManagementService } from '../../services/keyManagementService';
import { supabase } from '@/integrations/supabase/client';

export const SimpleVerificationTest: React.FC = () => {
  const [token, setToken] = useState('');
  const [result, setResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const testVerification = async () => {
    if (!token.trim()) return;

    setLoading(true);
    setResult(null);

    try {
      console.log('=== SIMPLE VERIFICATION TEST ===');
      console.log('Token:', token);

      // Step 1: Get credential from database
      console.log('Step 1: Getting credential from database...');
      const { data: vcData, error: vcError } = await supabase
        .from('verifiable_credentials')
        .select('*')
        .eq('short_token', token)
        .single();

      console.log('Database result:', { vcData, vcError });

      if (vcError || !vcData) {
        setResult({
          step: 'database',
          success: false,
          error: 'Credential not found in database',
          details: vcError?.message,
        });
        return;
      }

      // Step 2: Check if we have a JWS
      console.log('Step 2: Checking JWS...');
      const credential = vcData.credential_json;
      const jws = credential.proof?.jws;

      console.log('JWS:', jws);
      console.log('Credential proof:', credential.proof);

      if (!jws) {
        setResult({
          step: 'jws',
          success: false,
          error: 'No JWS found in credential proof',
          details: 'The credential does not have a valid signature',
        });
        return;
      }

      // Step 3: Try to verify the JWS
      console.log('Step 3: Verifying JWS...');
      try {
        const verification = await keyManagementService.verifyJWT(jws);
        console.log('JWT verification successful:', verification);

        setResult({
          step: 'verification',
          success: true,
          message: 'Credential verification successful',
          details: {
            credential: credential,
            verification: verification,
            jws: jws,
          },
        });
      } catch (verifyError) {
        console.error('JWT verification failed:', verifyError);

        setResult({
          step: 'verification',
          success: false,
          error: 'JWT verification failed',
          details:
            verifyError instanceof Error
              ? verifyError.message
              : 'Unknown error',
        });
      }
    } catch (error) {
      console.error('Test failed:', error);
      setResult({
        step: 'error',
        success: false,
        error: 'Test failed',
        details: error instanceof Error ? error.message : 'Unknown error',
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className='max-w-4xl mx-auto p-6 space-y-6'>
      <Card>
        <CardHeader>
          <CardTitle className='flex items-center space-x-2'>
            <Bug className='h-6 w-6 text-blue-600' />
            <span>Simple Verification Test</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className='space-y-4'>
            <div>
              <label className='block text-sm font-medium mb-2'>
                Verification Token
              </label>
              <div className='flex space-x-2'>
                <Input
                  value={token}
                  onChange={e => setToken(e.target.value)}
                  placeholder='Enter verification token'
                  className='flex-1'
                />
                <Button
                  onClick={testVerification}
                  disabled={loading || !token.trim()}
                >
                  {loading ? 'Testing...' : 'Test'}
                </Button>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      {result && (
        <Card>
          <CardHeader>
            <CardTitle className='flex items-center space-x-2'>
              {result.success ? (
                <CheckCircle className='h-6 w-6 text-green-600' />
              ) : (
                <XCircle className='h-6 w-6 text-red-600' />
              )}
              <span>Test Result - Step: {result.step}</span>
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className='space-y-4'>
              {result.success ? (
                <Alert>
                  <CheckCircle className='h-4 w-4' />
                  <AlertDescription>
                    <strong>Success:</strong> {result.message}
                  </AlertDescription>
                </Alert>
              ) : (
                <Alert>
                  <XCircle className='h-4 w-4' />
                  <AlertDescription>
                    <strong>Error:</strong> {result.error}
                    {result.details && (
                      <div className='mt-2'>
                        <strong>Details:</strong> {result.details}
                      </div>
                    )}
                  </AlertDescription>
                </Alert>
              )}

              {result.details && typeof result.details === 'object' && (
                <div>
                  <h4 className='font-semibold mb-2'>Full Details:</h4>
                  <pre className='bg-gray-100 p-3 rounded text-xs overflow-auto max-h-96'>
                    {JSON.stringify(result.details, null, 2)}
                  </pre>
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Search,
  Download,
  Share2,
  Eye,
  Calendar,
  Clock,
  MapPin,
  Building,
  Shield,
  CheckCircle,
  XCircle,
  AlertTriangle,
  Filter,
  SortAsc,
  SortDesc,
} from 'lucide-react';
import {
  verifiableCredentialService,
  VerifiableCredential,
} from '../../services/verifiableCredentialService';
import { QRCardGenerator } from './QRCardGenerator';
import { toast } from '@/hooks/use-toast';

interface StudentCredentialsProps {
  studentId: string;
}

type SortField = 'issuedAt' | 'title' | 'issuer';
type SortOrder = 'asc' | 'desc';
type FilterStatus = 'all' | 'valid' | 'revoked' | 'expired';

export const StudentCredentials: React.FC<StudentCredentialsProps> = ({
  studentId,
}) => {
  const [credentials, setCredentials] = useState<VerifiableCredential[]>([]);
  const [filteredCredentials, setFilteredCredentials] = useState<
    VerifiableCredential[]
  >([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [sortField, setSortField] = useState<SortField>('issuedAt');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');
  const [filterStatus, setFilterStatus] = useState<FilterStatus>('all');
  const [selectedCredential, setSelectedCredential] =
    useState<VerifiableCredential | null>(null);
  const [showQRCard, setShowQRCard] = useState(false);

  useEffect(() => {
    loadCredentials();
  }, [studentId]);

  useEffect(() => {
    filterAndSortCredentials();
  }, [credentials, searchQuery, sortField, sortOrder, filterStatus]);

  const loadCredentials = async () => {
    try {
      setLoading(true);
      const creds =
        await verifiableCredentialService.getStudentCredentials(studentId);
      setCredentials(creds);
    } catch (error) {
      console.error('Error loading credentials:', error);
      toast({
        title: 'Error',
        description: 'Failed to load credentials',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  const filterAndSortCredentials = () => {
    let filtered = [...credentials];

    // Apply search filter
    if (searchQuery) {
      filtered = filtered.filter(
        cred =>
          cred.credentialSubject.title
            .toLowerCase()
            .includes(searchQuery.toLowerCase()) ||
          cred.credentialSubject.activityType
            .toLowerCase()
            .includes(searchQuery.toLowerCase()) ||
          cred.credentialSubject.organizer
            .toLowerCase()
            .includes(searchQuery.toLowerCase()) ||
          cred.issuer.name.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }

    // Apply status filter
    if (filterStatus !== 'all') {
      filtered = filtered.filter(cred => {
        const isExpired =
          cred.expirationDate && new Date(cred.expirationDate) < new Date();
        switch (filterStatus) {
          case 'valid':
            return !isExpired;
          case 'expired':
            return isExpired;
          case 'revoked':
            // This would need to be checked against the database
            return false;
          default:
            return true;
        }
      });
    }

    // Apply sorting
    filtered.sort((a, b) => {
      let aValue: any, bValue: any;

      switch (sortField) {
        case 'issuedAt':
          aValue = new Date(a.issuanceDate);
          bValue = new Date(b.issuanceDate);
          break;
        case 'title':
          aValue = a.credentialSubject.title;
          bValue = b.credentialSubject.title;
          break;
        case 'issuer':
          aValue = a.issuer.name;
          bValue = b.issuer.name;
          break;
        default:
          return 0;
      }

      if (aValue < bValue) return sortOrder === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortOrder === 'asc' ? 1 : -1;
      return 0;
    });

    setFilteredCredentials(filtered);
  };

  const getCredentialStatus = (credential: VerifiableCredential) => {
    const isExpired =
      credential.expirationDate &&
      new Date(credential.expirationDate) < new Date();
    if (isExpired)
      return { status: 'expired', color: 'bg-yellow-100 text-yellow-800' };
    return { status: 'valid', color: 'bg-green-100 text-green-800' };
  };

  const getStatusIcon = (credential: VerifiableCredential) => {
    const { status } = getCredentialStatus(credential);
    switch (status) {
      case 'valid':
        return <CheckCircle className='h-4 w-4 text-green-600' />;
      case 'expired':
        return <AlertTriangle className='h-4 w-4 text-yellow-600' />;
      case 'revoked':
        return <XCircle className='h-4 w-4 text-red-600' />;
      default:
        return <AlertTriangle className='h-4 w-4 text-gray-600' />;
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  const handleViewCredential = (credential: VerifiableCredential) => {
    setSelectedCredential(credential);
    setShowQRCard(true);
  };

  const handleDownloadCredential = async (credential: VerifiableCredential) => {
    try {
      const blob = new Blob([JSON.stringify(credential, null, 2)], {
        type: 'application/json',
      });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `credential-${credential.id.split(':').pop()}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      toast({
        title: 'Success',
        description: 'Credential downloaded successfully',
      });
    } catch (error) {
      console.error('Error downloading credential:', error);
      toast({
        title: 'Error',
        description: 'Failed to download credential',
        variant: 'destructive',
      });
    }
  };

  const handleShareCredential = async (credential: VerifiableCredential) => {
    const verificationUrl = credential.credentialSubject.verificationUrl;

    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Verifiable Credential',
          text: `Check out my verified activity: ${credential.credentialSubject.title}`,
          url: verificationUrl,
        });
      } catch (error) {
        console.error('Error sharing:', error);
        // Fallback to copy
        navigator.clipboard.writeText(verificationUrl);
        toast({
          title: 'Success',
          description: 'Verification link copied to clipboard',
        });
      }
    } else {
      // Fallback to copy
      navigator.clipboard.writeText(verificationUrl);
      toast({
        title: 'Success',
        description: 'Verification link copied to clipboard',
      });
    }
  };

  if (loading) {
    return (
      <div className='flex items-center justify-center p-8'>
        <div className='text-center'>
          <div className='animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900 mx-auto mb-4'></div>
          <p className='text-gray-600'>Loading credentials...</p>
        </div>
      </div>
    );
  }

  if (showQRCard && selectedCredential) {
    return (
      <QRCardGenerator
        credential={{
          vcId: selectedCredential.id,
          credentialJson: selectedCredential,
          shortToken: '', // This would need to be stored in the credential
          qrUrl: selectedCredential.credentialSubject.verificationUrl,
          credentialUrl: `/api/v1/credentials/${selectedCredential.id}`,
        }}
        onDownload={() => setShowQRCard(false)}
        onShare={() => setShowQRCard(false)}
      />
    );
  }

  return (
    <div className='space-y-6'>
      {/* Header */}
      <div>
        <h2 className='text-2xl font-bold text-gray-900 mb-2'>
          My Credentials
        </h2>
        <p className='text-gray-600'>
          View and manage your verifiable credentials
        </p>
      </div>

      {/* Search and Filters */}
      <Card>
        <CardContent className='pt-6'>
          <div className='flex flex-col lg:flex-row gap-4'>
            {/* Search */}
            <div className='flex-1'>
              <div className='relative'>
                <Search className='absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400' />
                <Input
                  placeholder='Search credentials...'
                  value={searchQuery}
                  onChange={e => setSearchQuery(e.target.value)}
                  className='pl-10'
                />
              </div>
            </div>

            {/* Status Filter */}
            <div className='flex gap-2'>
              <select
                value={filterStatus}
                onChange={e => setFilterStatus(e.target.value as FilterStatus)}
                className='px-3 py-2 border border-gray-300 rounded-md text-sm'
              >
                <option value='all'>All Status</option>
                <option value='valid'>Valid</option>
                <option value='expired'>Expired</option>
                <option value='revoked'>Revoked</option>
              </select>

              {/* Sort Field */}
              <select
                value={sortField}
                onChange={e => setSortField(e.target.value as SortField)}
                className='px-3 py-2 border border-gray-300 rounded-md text-sm'
              >
                <option value='issuedAt'>Sort by Date</option>
                <option value='title'>Sort by Title</option>
                <option value='issuer'>Sort by Issuer</option>
              </select>

              {/* Sort Order */}
              <Button
                variant='outline'
                size='sm'
                onClick={() =>
                  setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')
                }
              >
                {sortOrder === 'asc' ? (
                  <SortAsc className='h-4 w-4' />
                ) : (
