import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { QrCode, Download, Eye, CheckCircle } from 'lucide-react';
import { verifiableCredentialServiceSimple } from '../../services/verifiableCredentialServiceSimple';
import { useProfile } from '../../hooks/useProfile';

export const StudentCredentialsView: React.FC = () => {
  const { profile } = useProfile();
  const [credentials, setCredentials] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (profile?.id) {
      loadCredentials();
    }
  }, [profile?.id]);

  const loadCredentials = async () => {
    try {
      setLoading(true);
      const studentCredentials =
        await verifiableCredentialServiceSimple.getStudentCredentials(
          profile.id
        );
      setCredentials(studentCredentials);
    } catch (error) {
      console.error('Error loading credentials:', error);
    } finally {
      setLoading(false);
    }
  };

  const downloadCredential = (credential: any) => {
    const dataStr = JSON.stringify(credential, null, 2);
    const dataUri =
      'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);

    const exportFileDefaultName = `credential-${credential.id.split(':').pop()}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  if (loading) {
    return (
      <Card>
        <CardContent className='p-6'>
          <div className='text-center'>Loading credentials...</div>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className='space-y-4'>
      <Card>
        <CardHeader>
          <CardTitle className='flex items-center space-x-2'>
            <CheckCircle className='h-6 w-6 text-green-600' />
            <span>My Verifiable Credentials</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          {credentials.length === 0 ? (
            <div className='text-center py-8 text-gray-500'>
              <CheckCircle className='h-12 w-12 mx-auto mb-4 text-gray-300' />
              <p>No credentials issued yet</p>
              <p className='text-sm'>
                Complete activities to earn verifiable credentials
              </p>
            </div>
          ) : (
            <div className='space-y-4'>
              {credentials.map((credential, index) => (
                <Card key={index} className='border-l-4 border-l-green-500'>
                  <CardContent className='p-4'>
                    <div className='flex justify-between items-start'>
                      <div className='flex-1'>
                        <h3 className='font-semibold text-lg'>
                          {credential.credentialSubject?.title ||
                            'Activity Credential'}
                        </h3>
                        <p className='text-sm text-gray-600 mb-2'>
                          {credential.credentialSubject?.organizer ||
                            'Unknown Organizer'}
                        </p>
                        <div className='flex flex-wrap gap-2 mb-3'>
                          <Badge variant='secondary'>
                            {credential.credentialSubject?.activityType ||
                              'Activity'}
                          </Badge>
                          <Badge variant='outline'>
                            {credential.credentialSubject?.role ||
                              'Participant'}
                          </Badge>
                          <Badge variant='outline'>
                            {credential.credentialSubject?.hours || 0} hours
                          </Badge>
                        </div>
                        <p className='text-xs text-gray-500'>
                          Issued:{' '}
                          {new Date(
                            credential.issuanceDate
                          ).toLocaleDateString()}
                        </p>
                        {credential.expirationDate && (
                          <p className='text-xs text-gray-500'>
                            Expires:{' '}
                            {new Date(
                              credential.expirationDate
                            ).toLocaleDateString()}
                          </p>
                        )}
                      </div>
                      <div className='flex space-x-2 ml-4'>
                        <Button
                          size='sm'
                          variant='outline'
                          onClick={() => downloadCredential(credential)}
                        >
                          <Download className='h-4 w-4 mr-1' />
                          Download
                        </Button>
                        <Button
                          size='sm'
                          variant='outline'
                          onClick={() =>
                            window.open(
                              credential.credentialSubject?.verificationUrl,
                              '_blank'
                            )
                          }
                        >
                          <QrCode className='h-4 w-4 mr-1' />
                          QR Code
                        </Button>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { CheckCircle, AlertTriangle, Shield } from 'lucide-react';
import { verifiableCredentialServiceSimple } from '../../services/verifiableCredentialServiceSimple';
import { keyManagementService } from '../../services/keyManagementService';
import { supabase } from '@/integrations/supabase/client';
import { checkVCSetup } from '../../setup/setupVerifiableCredentialsSimple';

export const VCIntegrationTest: React.FC = () => {
  const [testResults, setTestResults] = useState<{
    keyGeneration: boolean;
    credentialIssuance: boolean;
    credentialVerification: boolean;
    jwksEndpoint: boolean;
  }>({
    keyGeneration: false,
    credentialIssuance: false,
    credentialVerification: false,
    jwksEndpoint: false,
  });
  const [loading, setLoading] = useState(false);
  const [testCredential, setTestCredential] = useState<any>(null);

  const runTests = async () => {
    setLoading(true);
    const results = { ...testResults };

    try {
      // Test 0: Check VC Setup
      console.log('Checking VC setup...');
      const setupCheck = await checkVCSetup();
      if (!setupCheck.isSetup) {
        console.error('VC system not properly set up:', setupCheck.error);
        alert(
          'VC system not set up. Please run the fix_issuer_rls.sql script in Supabase SQL Editor first.'
        );
        setLoading(false);
        return;
      }
      console.log('VC setup check passed');

      // Test 1: Key Generation
      console.log('Testing key generation...');
      const keyPair = await keyManagementService.generateKeyPair();
      results.keyGeneration = !!(
        keyPair.publicKey &&
        keyPair.privateKey &&
        keyPair.jwk
      );
      console.log('Key generation test:', results.keyGeneration);

      // Test 2: JWKS Endpoint
      console.log('Testing JWKS endpoint...');
      const jwks = await keyManagementService.getJWKS();
      results.jwksEndpoint = !!(jwks.keys && jwks.keys.length > 0);
      console.log('JWKS endpoint test:', results.jwksEndpoint);

      // Test 3: Credential Issuance
      console.log('Testing credential issuance...');
      let issuedCredential = null;

      try {
        // First, get a real student from the database
        const studentRes = await supabase
          .from('profiles')
          .select('id, full_name')
          .eq('role', 'student')
          .limit(1);

        let students = studentRes.data;
        const studentError = studentRes.error;

        if (studentError || !students || students.length === 0) {
          console.log('No students found, creating a test student...');

          // Generate UUIDs for the test student
          const studentId = crypto.randomUUID();
          const userId = crypto.randomUUID();

          // Create a test student
          const { data: newStudent, error: createError } = await supabase
            .from('profiles')
            .insert({
              id: studentId,
              user_id: userId,
              full_name: 'Test Student VC',
              email: 'test.student.vc@example.com',
              role: 'student',
            })
            .select('id, full_name')
            .single();

          if (createError) {
            throw new Error(
              `Failed to create test student: ${createError.message}`
            );
          }

          students = [newStudent];
        }

        const student = students[0];
        console.log('Using student:', student);

        issuedCredential =
          await verifiableCredentialServiceSimple.issueCredential({
            // activityId is optional, so we'll omit it for this test
            studentId: student.id,
            evidenceIds: [],
            issuedByUserId: crypto.randomUUID(), // Generate a proper UUID
            activityData: {
              title: 'Test Conference 2025',
              type: 'Conference',
              organizer: 'Test Organizer',
              role: 'Presenter',
              date: '2025-01-15',
              location: 'Test City',
              hours: 8,
              department: 'Computer Science',
            },
          });

        results.credentialIssuance = !!(
          issuedCredential.vcId && issuedCredential.shortToken
        );
        setTestCredential(issuedCredential);
        console.log('Credential issuance test:', results.credentialIssuance);
        console.log('Test credential set:', issuedCredential);
      } catch (error) {
        console.error('Credential issuance test failed:', error);
        results.credentialIssuance = false;
      }

      // Test 4: Credential Verification
      console.log('Testing credential verification...');

      if (issuedCredential?.shortToken) {
        try {
          console.log(
            'Verifying credential with token:',
            issuedCredential.shortToken
          );
          const verification =
            await verifiableCredentialServiceSimple.verifyCredential(
              issuedCredential.shortToken
            );
          console.log('Verification result:', verification);
          results.credentialVerification = verification.status === 'valid';
          console.log(
            'Credential verification test:',
            results.credentialVerification
          );
          console.log('Verification details:', {
            status: verification.status,
            signatureValid: verification.signatureValid,
            evidenceValidated: verification.evidenceValidated,
            errors: verification.errors,
          });
        } catch (error) {
          console.error('Credential verification test failed:', error);
          results.credentialVerification = false;
        }
      } else {
        console.log('No credential available for verification');
        results.credentialVerification = false;
      }
    } catch (error) {
      console.error('Test suite failed:', error);
    }

    setTestResults(results);
    setLoading(false);
  };

  const allTestsPassed = Object.values(testResults).every(result => result);

  return (
    <Card className='w-full max-w-2xl mx-auto'>
      <CardHeader>
        <CardTitle className='flex items-center space-x-2'>
          <Shield className='h-6 w-6 text-blue-600' />
          <span>Verifiable Credentials Integration Test</span>
        </CardTitle>
      </CardHeader>

      <CardContent className='space-y-4'>
        <Alert
          className={
            allTestsPassed
              ? 'border-green-200 bg-green-50'
              : 'border-yellow-200 bg-yellow-50'
          }
        >
          <div className='flex items-center space-x-2'>
            {allTestsPassed ? (
              <CheckCircle className='h-4 w-4 text-green-600' />
            ) : (
              <AlertTriangle className='h-4 w-4 text-yellow-600' />
            )}
            <AlertDescription>
              {allTestsPassed
                ? 'All Verifiable Credentials tests passed! System is ready.'
                : 'Some tests failed. Check the console for details.'}
            </AlertDescription>
          </div>
        </Alert>

        <div className='space-y-3'>
          <div className='flex items-center justify-between'>
            <span className='text-sm font-medium'>Key Generation</span>
            <Badge
              variant={testResults.keyGeneration ? 'default' : 'destructive'}
            >
              {testResults.keyGeneration ? 'Pass' : 'Fail'}
            </Badge>
          </div>

          <div className='flex items-center justify-between'>
            <span className='text-sm font-medium'>JWKS Endpoint</span>
            <Badge
              variant={testResults.jwksEndpoint ? 'default' : 'destructive'}
            >
              {testResults.jwksEndpoint ? 'Pass' : 'Fail'}
            </Badge>
          </div>

          <div className='flex items-center justify-between'>
            <span className='text-sm font-medium'>Credential Issuance</span>
            <Badge
              variant={
                testResults.credentialIssuance ? 'default' : 'destructive'
              }
            >
              {testResults.credentialIssuance ? 'Pass' : 'Fail'}
            </Badge>
          </div>

          <div className='flex items-center justify-between'>
            <span className='text-sm font-medium'>Credential Verification</span>
            <Badge
              variant={
                testResults.credentialVerification ? 'default' : 'destructive'
              }
            >
              {testResults.credentialVerification ? 'Pass' : 'Fail'}
            </Badge>
          </div>
        </div>

        <Button onClick={runTests} disabled={loading} className='w-full'>
          {loading ? 'Running Tests...' : 'Run Integration Tests'}
        </Button>

        {testCredential && (
          <div className='mt-4 p-3 bg-gray-50 rounded-lg'>
            <h4 className='font-medium text-sm mb-2'>
              Test Credential Generated:
            </h4>
            <p className='text-xs text-gray-600 break-all'>
              ID: {testCredential.vcId}
            </p>
            <p className='text-xs text-gray-600 break-all'>
              QR URL: {testCredential.qrUrl}
            </p>
          </div>
        )}

        <div className='text-xs text-gray-500 mt-4'>
          <p>
            This test verifies that the Verifiable Credentials system is
            properly integrated and functional.
          </p>
          <p>Check the browser console for detailed test logs.</p>
        </div>
      </CardContent>
    </Card>
  );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import {
  blockchainService,
  WalletInfo,
  Achievement,
} from '../services/blockChainService';

interface BlockchainContextType {
  isConnected: boolean;
  walletInfo: WalletInfo | null;
  connectWallet: () => Promise<void>;
  disconnectWallet: () => void;
  mintAchievement: (achievement: Achievement) => Promise<string>;
  getStudentAchievements: (studentId: string) => Promise<Achievement[]>;
  verifyAchievement: (tokenId: string) => Promise<boolean>;
  loading: boolean;
  error: string | null;
  clearError: () => void;
}

const BlockchainContext = createContext<BlockchainContextType | undefined>(
  undefined
);

export const useBlockchain = () => {
  const context = useContext(BlockchainContext);
  if (!context) {
    throw new Error('useBlockchain must be used within a BlockchainProvider');
  }
  return context;
};

export const BlockchainProvider: React.FC<{ children: React.ReactNode }> = ({
  children,
}) => {
  const [isConnected, setIsConnected] = useState(false);
  const [walletInfo, setWalletInfo] = useState<WalletInfo | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const connectWallet = async () => {
    try {
      setLoading(true);
      setError(null);

      const info = await blockchainService.connectWallet();
      setWalletInfo(info);
      setIsConnected(true);

      // Save to localStorage for persistence
      localStorage.setItem('blockchain_connected', 'true');
      localStorage.setItem('wallet_address', info.address);

      console.log('≡ƒöù Wallet connected successfully!', info);
    } catch (err) {
      const errorMessage =
        err instanceof Error ? err.message : 'Failed to connect wallet';
      setError(errorMessage);
      console.error('Γ¥î Wallet connection failed:', errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const disconnectWallet = async () => {
    try {
      await blockchainService.disconnect();
      setIsConnected(false);
      setWalletInfo(null);
      setError(null);

      // Clear localStorage
      localStorage.removeItem('blockchain_connected');
      localStorage.removeItem('wallet_address');

      console.log('≡ƒöî Wallet disconnected');
    } catch (err) {
      console.error('Error disconnecting wallet:', err);
    }
  };

  const mintAchievement = async (achievement: Achievement): Promise<string> => {
    try {
      setLoading(true);
      setError(null);

      const tokenId = await blockchainService.mintAchievement(achievement);
      console.log('≡ƒÄ¿ Achievement minted as NFT!', { tokenId, achievement });

      return tokenId;
    } catch (err) {
      const errorMessage =
        err instanceof Error ? err.message : 'Failed to mint achievement';
      setError(errorMessage);
      console.error('Γ¥î Achievement minting failed:', errorMessage);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const getStudentAchievements = async (
    studentId: string
  ): Promise<Achievement[]> => {
    try {
      setLoading(true);
      setError(null);

      const achievements =
        await blockchainService.getStudentAchievements(studentId);
      console.log('≡ƒôï Fetched student achievements:', achievements);

      return achievements;
    } catch (err) {
      const errorMessage =
        err instanceof Error ? err.message : 'Failed to fetch achievements';
      setError(errorMessage);
      console.error('Γ¥î Failed to fetch achievements:', errorMessage);
      return [];
    } finally {
      setLoading(false);
    }
  };

  const verifyAchievement = async (tokenId: string): Promise<boolean> => {
    try {
      setLoading(true);
      setError(null);

      const isValid = await blockchainService.verifyAchievement(tokenId);
      console.log('Γ£à Achievement verification result:', { tokenId, isValid });

      return isValid;
    } catch (err) {
      const errorMessage =
        err instanceof Error ? err.message : 'Failed to verify achievement';
      setError(errorMessage);
      console.error('Γ¥î Achievement verification failed:', errorMessage);
      return false;
    } finally {
      setLoading(false);
    }
  };

  const clearError = () => {
    setError(null);
  };

  // Check if wallet was previously connected
  useEffect(() => {
    const wasConnected = localStorage.getItem('blockchain_connected');
    const walletAddress = localStorage.getItem('wallet_address');

    if (wasConnected && walletAddress && blockchainService.isConnected()) {
      setIsConnected(true);
      setWalletInfo({
        address: walletAddress,
        balance: '0',
        network: 'Polygon Mumbai',
        isConnected: true,
      });
    }
  }, []);

  return (
    <BlockchainContext.Provider
      value={{
        isConnected,
        walletInfo,
        connectWallet,
        disconnectWallet,
        mintAchievement,
        getStudentAchievements,
        verifyAchievement,
        loading,
        error,
        clearError,
      }}
    >
      {children}
    </BlockchainContext.Provider>
  );
};

import * as React from 'react';

import type { ToastActionElement, ToastProps } from '@/components/ui/toast';

const TOAST_LIMIT = 1;
const TOAST_REMOVE_DELAY = 1000000;

type ToasterToast = ToastProps & {
  id: string;
  title?: React.ReactNode;
  description?: React.ReactNode;
  action?: ToastActionElement;
};

const actionTypes = {
  ADD_TOAST: 'ADD_TOAST',
  UPDATE_TOAST: 'UPDATE_TOAST',
  DISMISS_TOAST: 'DISMISS_TOAST',
  REMOVE_TOAST: 'REMOVE_TOAST',
} as const;

let count = 0;

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER;
  return count.toString();
}

type ActionType = typeof actionTypes;

type Action =
  | {
      type: ActionType['ADD_TOAST'];
      toast: ToasterToast;
    }
  | {
      type: ActionType['UPDATE_TOAST'];
      toast: Partial<ToasterToast>;
    }
  | {
      type: ActionType['DISMISS_TOAST'];
      toastId?: ToasterToast['id'];
    }
  | {
      type: ActionType['REMOVE_TOAST'];
      toastId?: ToasterToast['id'];
    };

interface State {
  toasts: ToasterToast[];
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>();

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return;
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId);
    dispatch({
      type: 'REMOVE_TOAST',
      toastId: toastId,
    });
  }, TOAST_REMOVE_DELAY);

  toastTimeouts.set(toastId, timeout);
};

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case 'ADD_TOAST':
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      };

    case 'UPDATE_TOAST':
      return {
        ...state,
        toasts: state.toasts.map(t =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      };

    case 'DISMISS_TOAST': {
      const { toastId } = action;

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId);
      } else {
        state.toasts.forEach(toast => {
          addToRemoveQueue(toast.id);
        });
      }

      return {
        ...state,
        toasts: state.toasts.map(t =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      };
    }
    case 'REMOVE_TOAST':
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        };
      }
      return {
        ...state,
        toasts: state.toasts.filter(t => t.id !== action.toastId),
      };
  }
};

const listeners: Array<(state: State) => void> = [];

let memoryState: State = { toasts: [] };

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action);
  listeners.forEach(listener => {
    listener(memoryState);
  });
}

type Toast = Omit<ToasterToast, 'id'>;

function toast({ ...props }: Toast) {
  const id = genId();

  const update = (props: ToasterToast) =>
    dispatch({
      type: 'UPDATE_TOAST',
      toast: { ...props, id },
    });
  const dismiss = () => dispatch({ type: 'DISMISS_TOAST', toastId: id });

  dispatch({
    type: 'ADD_TOAST',
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: open => {
        if (!open) dismiss();
      },
    },
  });

  return {
    id: id,
    dismiss,
    update,
  };
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState);

  React.useEffect(() => {
    listeners.push(setState);
    return () => {
      const index = listeners.indexOf(setState);
      if (index > -1) {
        listeners.splice(index, 1);
      }
    };
  }, [state]);

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: 'DISMISS_TOAST', toastId }),
  };
}

export { useToast, toast };

import { useState, useEffect } from 'react';
import { User, Session } from '@supabase/supabase-js';
import { supabase } from '@/integrations/supabase/client';

export const useAuth = () => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((event, sess) => {
      console.log('Auth state change:', event, sess?.user?.id);
      setSession(sess);
      setUser(sess?.user ?? null);
      setLoading(false);
    });

    supabase.auth.getSession().then(({ data: { session }, error }) => {
      if (error) {
        console.error('Error getting session:', error);
        // Clear invalid session
        if (
          error.message?.includes('refresh_token') ||
          error.message?.includes('invalid_grant')
        ) {
          supabase.auth.signOut();
        }
      }
      setSession(session);
      setUser(session?.user ?? null);
      setLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const signUp = async (
    email: string,
    password: string,
    userData: { fullName: string; role: string }
  ) => {
    const redirectUrl = `${window.location.origin}/`;
    const { error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        emailRedirectTo: redirectUrl,
        data: { full_name: userData.fullName, role: userData.role },
      },
    });
    return { error };
  };

  const signIn = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });
    return { error };
  };

  const signOut = async () => {
    const { error } = await supabase.auth.signOut();
    return { error };
  };

  return {
    user,
    session,
    loading,
    signUp,
    signIn,
    signOut,
  };
};

