import { useState, useEffect, useCallback } from 'react';
import {
  CommunityService,
  CommunityPost,
  CommunityComment,
  CommunityGroup,
} from '@/services/communityService';
import { useProfile } from '@/hooks/useProfile';

export const useCommunity = () => {
  const { profile } = useProfile();
  const [posts, setPosts] = useState<CommunityPost[]>([]);
  const [groups, setGroups] = useState<CommunityGroup[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const userId = profile?.id;

  // Load initial data
  useEffect(() => {
    loadData();
  }, []);

  // Set up real-time subscriptions
  useEffect(() => {
    if (!userId) return;

    const postsSubscription = CommunityService.subscribeToPosts(payload => {
      console.log('Posts update:', payload);
      // Reload posts when there are changes
      loadPosts();
    });

    const commentsSubscription = CommunityService.subscribeToComments(
      payload => {
        console.log('Comments update:', payload);
        // Reload posts to get updated comment counts
        loadPosts();
      }
    );

    const interactionsSubscription = CommunityService.subscribeToInteractions(
      payload => {
        console.log('Interactions update:', payload);
        // Reload posts to get updated interaction counts
        loadPosts();
      }
    );

    return () => {
      postsSubscription.unsubscribe();
      commentsSubscription.unsubscribe();
      interactionsSubscription.unsubscribe();
    };
  }, [userId]);

  const loadData = async () => {
    try {
      setLoading(true);
      setError(null);
      await Promise.all([loadPosts(), loadGroups()]);
    } catch (err) {
      console.error('Error loading community data:', err);
      setError(
        err instanceof Error ? err.message : 'Failed to load community data'
      );
    } finally {
      setLoading(false);
    }
  };

  const loadPosts = async (groupId?: string, category?: string) => {
    try {
      const postsData = await CommunityService.getPosts(groupId, category);

      // Load interactions and comments for each post
      const postsWithInteractions = await Promise.all(
        (postsData || []).map(async post => {
          try {
            const [interactions, comments] = await Promise.all([
              CommunityService.getPostInteractions(post.id, userId),
              CommunityService.getComments(post.id),
            ]);
            return { ...post, ...interactions, comments: comments || [] };
          } catch (interactionErr) {
            console.error(
              'Error loading interactions for post:',
              post.id,
              interactionErr
            );
            return {
              ...post,
              user_has_upvoted: false,
              user_has_downvoted: false,
              user_has_bookmarked: false,
              comments: [],
            };
          }
        })
      );

      setPosts(postsWithInteractions || []);
    } catch (err) {
      console.error('Error loading posts:', err);
      setPosts([]); // Set empty array on error
      setError(err instanceof Error ? err.message : 'Failed to load posts');
    }
  };

  const loadGroups = async () => {
    try {
      const groupsData = await CommunityService.getGroups(userId);
      setGroups(groupsData || []);
    } catch (err) {
      console.error('Error loading groups:', err);
      setGroups([]); // Set empty array on error
      setError(err instanceof Error ? err.message : 'Failed to load groups');
    }
  };

  const createPost = useCallback(
    async (
      content: string,
      category: 'Academics' | 'Placements' | 'Clubs' | 'Events' | 'General',
      groupId?: string
    ) => {
      if (!userId) throw new Error('User not authenticated');

      try {
        const newPost = await CommunityService.createPost(
          userId,
          content,
          category,
          groupId
        );
        const interactions = await CommunityService.getPostInteractions(
          newPost.id,
          userId
        );
        const postWithInteractions = { ...newPost, ...interactions };

        setPosts(prev => [postWithInteractions, ...prev]);
        return newPost;
      } catch (err) {
        console.error('Error creating post:', err);
        throw err;
      }
    },
    [userId]
  );

  const createComment = useCallback(
    async (postId: string, content: string) => {
      if (!userId) throw new Error('User not authenticated');

      try {
        const newComment = await CommunityService.createComment(
          postId,
          userId,
          content
        );

        // Reload posts to get updated comment counts and comments
        await loadPosts();

        return newComment;
      } catch (err) {
        console.error('Error creating comment:', err);
        throw err;
      }
    },
    [userId, loadPosts]
  );

  const togglePostInteraction = useCallback(
    async (
      postId: string,
      interactionType: 'upvote' | 'downvote' | 'bookmark'
    ) => {
      if (!userId) throw new Error('User not authenticated');

      try {
        await CommunityService.togglePostInteraction(
          postId,
          userId,
          interactionType
        );

        // Update local state
        setPosts(prev =>
          prev.map(post => {
            if (post.id !== postId) return post;

            const newPost = { ...post };

            if (interactionType === 'upvote') {
              if (post.user_has_upvoted) {
                newPost.upvotes = (post.upvotes || 0) - 1;
                newPost.user_has_upvoted = false;
              } else {
                newPost.upvotes = (post.upvotes || 0) + 1;
                newPost.user_has_upvoted = true;
                if (post.user_has_downvoted) {
                  newPost.downvotes = (post.downvotes || 0) - 1;
                  newPost.user_has_downvoted = false;
                }
              }
            } else if (interactionType === 'downvote') {
              if (post.user_has_downvoted) {
                newPost.downvotes = (post.downvotes || 0) - 1;
                newPost.user_has_downvoted = false;
              } else {
                newPost.downvotes = (post.downvotes || 0) + 1;
                newPost.user_has_downvoted = true;
                if (post.user_has_upvoted) {
                  newPost.upvotes = (post.upvotes || 0) - 1;
                  newPost.user_has_upvoted = false;
                }
              }
            } else if (interactionType === 'bookmark') {
              newPost.user_has_bookmarked = !post.user_has_bookmarked;
              newPost.bookmarks = post.user_has_bookmarked
                ? (post.bookmarks || 0) - 1
                : (post.bookmarks || 0) + 1;
            }

            return newPost;
          })
        );
      } catch (err) {
        console.error('Error toggling post interaction:', err);
        throw err;
      }
    },
    [userId]
  );

  const createGroup = useCallback(
    async (name: string, description: string) => {
      if (!userId) throw new Error('User not authenticated');

      try {
        const newGroup = await CommunityService.createGroup(
          name,
          description,
          userId
        );
        setGroups(prev => [newGroup, ...prev]);
        return newGroup;
      } catch (err) {
        console.error('Error creating group:', err);
        throw err;
      }
    },
    [userId]
  );

  const joinGroup = useCallback(
    async (groupId: string) => {
      if (!userId) throw new Error('User not authenticated');

      try {
        await CommunityService.joinGroup(groupId, userId);
        setGroups(prev =>
          prev.map(group =>
            group.id === groupId
              ? {
                  ...group,
                  is_member: true,
                  member_count: (group.member_count || 0) + 1,
                }
              : group
          )
        );
      } catch (err) {
        console.error('Error joining group:', err);
        throw err;
      }
    },
    [userId]
  );

  const leaveGroup = useCallback(
    async (groupId: string) => {
      if (!userId) throw new Error('User not authenticated');

      try {
        await CommunityService.leaveGroup(groupId, userId);
        setGroups(prev =>
          prev.map(group =>
            group.id === groupId
              ? {
                  ...group,
                  is_member: false,
                  member_count: Math.max(0, (group.member_count || 0) - 1),
                }
              : group
          )
        );
      } catch (err) {
        console.error('Error leaving group:', err);
        throw err;
      }
    },
    [userId]
  );

  const deletePost = useCallback(
    async (postId: string) => {
      if (!userId) throw new Error('User not authenticated');

      try {
        await CommunityService.deletePost(postId);
        // Reload posts to reflect the deletion
        await loadPosts();
      } catch (err) {
        console.error('Error deleting post:', err);
        throw err;
      }
    },
    [userId, loadPosts]
  );

  return {
    posts,
    groups,
    loading,
    error,
    createPost,
    createComment,
    togglePostInteraction,
    createGroup,
    joinGroup,
    leaveGroup,
    deletePost,
    loadPosts,
    loadGroups,
    refresh: loadData,
  };
};

import { useEffect, useMemo, useState } from 'react';
import {
  initialEvents,
  type EventItem,
  type EventCategory,
} from '@/data/events';
import { useAuth } from '@/hooks/useAuth';

const STORAGE_KEY = 'events_v1';
const REG_KEY = 'event_registrations_v1';

type Registration = {
  id: string; // registration id
  eventId: string;
  userId: string | null; // can be null if not logged in
  name: string;
  email: string;
  studentId?: string;
  createdAt: string; // ISO
};

function loadEvents(): EventItem[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      console.log('No events in localStorage, using initial events');
      return initialEvents;
    }
    const parsed = JSON.parse(raw) as EventItem[];
    console.log('Loaded events from localStorage:', parsed.length);
    // Merge by id to ensure seeded events are available if missing
    const map = new Map<string, EventItem>();
    initialEvents.forEach(e => map.set(e.id, e));
    parsed.forEach(e => map.set(e.id, e));
    const result = Array.from(map.values());
    console.log('Merged events result:', result.length);
    return result;
  } catch (error) {
    console.error('Error loading events from localStorage:', error);
    return initialEvents;
  }
}

function saveEvents(events: EventItem[]) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(events));
}

function loadRegistrations(): Registration[] {
  try {
    const raw = localStorage.getItem(REG_KEY);
    return raw ? (JSON.parse(raw) as Registration[]) : [];
  } catch {
    return [];
  }
}

function saveRegistrations(rows: Registration[]) {
  localStorage.setItem(REG_KEY, JSON.stringify(rows));
}

export function useEvents() {
  const [events, setEvents] = useState<EventItem[]>([]);

  useEffect(() => {
    const loadedEvents = loadEvents();
    console.log('Loaded events from storage:', loadedEvents.length);
    console.log('Events data:', loadedEvents);
    setEvents(loadedEvents);
  }, []);

  const addEvent = (payload: Omit<EventItem, 'id'>) => {
    const id = `${payload.category}-${Math.random().toString(36).slice(2, 9)}`;
    const next = [{ ...payload, id }, ...events];
    setEvents(next);
    saveEvents(next);
    return id;
  };

  const updateEvent = (id: string, changes: Partial<EventItem>) => {
    const next = events.map(e => (e.id === id ? { ...e, ...changes } : e));
    setEvents(next);
    saveEvents(next);
  };

  const removeEvent = (id: string) => {
    const next = events.filter(e => e.id !== id);
    setEvents(next);
    saveEvents(next);
  };

  const byCategory = useMemo(
    () => ({
      academic: events.filter(e => e.category === 'academic'),
      co_curricular: events.filter(e => e.category === 'co_curricular'),
      outside_university: events.filter(
        e => e.category === 'outside_university'
      ),
    }),
    [events]
  );

  const getById = (id: string) => {
    console.log('getById called with:', id);
    console.log(
      'Current events:',
      events.map(e => e.id)
    );
    const found = events.find(e => e.id === id) || null;
    console.log('getById result:', found);
    return found;
  };

  return { events, byCategory, addEvent, updateEvent, removeEvent, getById };
}

export function useEventRegistration(eventId: string | null) {
  const { user } = useAuth();
  const [rows, setRows] = useState<Registration[]>([]);

  useEffect(() => {
    setRows(loadRegistrations());
  }, []);

  const myRegistration = useMemo(() => {
    if (!eventId) return null;
    if (!user) return null;
    return (
      rows.find(r => r.eventId === eventId && r.userId === user.id) || null
    );
  }, [rows, user, eventId]);

  const register = (data: {
    name: string;
    email: string;
    studentId?: string;
  }) => {
    if (!eventId) return { error: 'Missing event' };
    const reg: Registration = {
      id: `r_${Math.random().toString(36).slice(2, 10)}`,
      eventId,
      userId: user?.id || null,
      name: data.name,
      email: data.email,
      studentId: data.studentId,
      createdAt: new Date().toISOString(),
    };
    const next = [reg, ...rows];
    setRows(next);
    saveRegistrations(next);
    return { error: null, registrationId: reg.id };
  };

  return { rows, myRegistration, register };
}

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useProfile } from './useProfile';

export interface StudentMonitoring {
  id: string;
  student_id: string;
  platform: string;
  platform_handle: string;
  solved_count: number;
  contest_count: number;
  rating: number;
  last_updated: string;
  student: {
    id: string;
    full_name: string;
    email: string;
    student_id?: string;
    department?: string;
  };
}

export interface FacultyAssignment {
  id: string;
  faculty_id: string;
  student_id: string;
  assigned_at: string;
  student: {
    id: string;
    full_name: string;
    email: string;
    student_id?: string;
    department?: string;
  };
}

export const useFaculty = () => {
  const { profile } = useProfile();
  const [assignedStudents, setAssignedStudents] = useState<FacultyAssignment[]>(
    []
  );
  const [monitoringData, setMonitoringData] = useState<StudentMonitoring[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<any>(null);

  // Fetch assigned students using the faculty_assignments table (our actual schema)
  const fetchAssignedStudents = async () => {
    if (!profile || profile.role !== 'faculty') return;

    try {
      setLoading(true);
      setError(null);

      const { data, error } = await supabase
        .from('faculty_assignments')
        .select(
          `
          *,
          student:profiles!faculty_assignments_student_id_fkey(
            id,
            full_name,
            email,
            student_id,
            department
          )
        `
        )
        .eq('faculty_id', profile.id);

      if (error) {
        setError(error);
        console.error('Error fetching assigned students:', error);
      } else {
        setAssignedStudents(data || []);
      }
    } catch (err) {
      setError(err);
      console.error('Error fetching assigned students:', err);
    } finally {
      setLoading(false);
    }
  };

  // Fetch student monitoring data
  const fetchMonitoringData = async (studentIds?: string[]) => {
    if (!profile || profile.role !== 'faculty') return;

    try {
      setLoading(true);
      let query = supabase.from('student_monitoring').select(`
          *,
          student:profiles!student_monitoring_student_id_fkey(
            id,
            full_name,
            email,
            student_id,
            department
          )
        `);

      if (studentIds && studentIds.length > 0) {
        query = query.in('student_id', studentIds);
      } else if (profile.faculty_level === 'basic') {
        // Basic faculty: only show assigned students
        const assignedStudentIds = assignedStudents.map(a => a.student_id);
        if (assignedStudentIds.length > 0) {
          query = query.in('student_id', assignedStudentIds);
        } else {
          setMonitoringData([]);
          setLoading(false);
          return;
        }
      }
      // senior/admin faculty see all

      const { data, error } = await query.order('last_updated', {
        ascending: false,
      });

      if (error) {
        setError(error);
        console.error('Error fetching monitoring data:', error);
      } else {
        setMonitoringData(data || []);
      }
    } catch (err) {
      setError(err);
      console.error('Error fetching monitoring data:', err);
    } finally {
      setLoading(false);
    }
  };

  // Add student monitoring data
  const addMonitoringData = async (data: {
    student_id: string;
    platform: string;
    platform_handle: string;
    solved_count?: number;
    contest_count?: number;
    rating?: number;
  }) => {
    try {
      const { error } = await supabase.from('student_monitoring').upsert(
        {
          ...data,
          last_updated: new Date().toISOString(),
        },
        {
          onConflict: 'student_id,platform,platform_handle',
        }
      );

      if (error) {
        setError(error);
        console.error('Error adding monitoring data:', error);
        return { error };
      }

      await fetchMonitoringData();
      return { error: null };
    } catch (err) {
      setError(err);
      console.error('Error adding monitoring data:', err);
      return { error: err };
    }
  };

  // Assign student to faculty
  const assignStudent = async (studentId: string) => {
    if (!profile || profile.role !== 'faculty')
      return { error: 'Not authorized' };

    try {
      const { error } = await supabase.from('faculty_assignments').insert({
        faculty_id: profile.id,
        student_id: studentId,
      });

      if (error) {
        setError(error);
        console.error('Error assigning student:', error);
        return { error };
      }

      await fetchAssignedStudents();
      return { error: null };
    } catch (err) {
      setError(err);
      console.error('Error assigning student:', err);
      return { error: err };
    }
  };

  // Unassign student from faculty
  const unassignStudent = async (studentId: string) => {
    if (!profile || profile.role !== 'faculty')
      return { error: 'Not authorized' };

    try {
      const { error } = await supabase
        .from('faculty_assignments')
        .delete()
        .eq('faculty_id', profile.id)
        .eq('student_id', studentId);

      if (error) {
        setError(error);
        console.error('Error unassigning student:', error);
        return { error };
      }

      await fetchAssignedStudents();
      return { error: null };
    } catch (err) {
      setError(err);
      console.error('Error unassigning student:', err);
      return { error: err };
    }
  };

  // Fetch all students (for faculty to browse and assign)
  const fetchAllStudents = async () => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('id, full_name, email, student_id, department, avatar_url')
        .eq('role', 'student')
        .order('full_name');

      if (error) throw error;
      return data || [];
    } catch (err) {
      console.error('Error fetching all students:', err);
      return [];
    }
  };

  // Load data when profile changes
  useEffect(() => {
    if (profile && profile.role === 'faculty') {
      fetchAssignedStudents();
    }
  }, [profile]);

  // Load monitoring data when assigned students change
  useEffect(() => {
    if (assignedStudents.length > 0) {
      const studentIds = assignedStudents.map(a => a.student_id);
      fetchMonitoringData(studentIds);
    }
  }, [assignedStudents]);

  return {
    assignedStudents,
    monitoringData,
    loading,
    error,
    fetchAssignedStudents,
    fetchMonitoringData,
    addMonitoringData,
    assignStudent,
    unassignStudent,
    fetchAllStudents,
  };
};

import { useState, useEffect, useCallback } from 'react';
import {
  NotificationService,
  Notification,
} from '@/services/notificationService';
import { useProfile } from '@/hooks/useProfile';

export const useNotifications = () => {
  const { profile } = useProfile();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const userId = profile?.id;

  // Load initial notifications
  useEffect(() => {
    if (userId) {
      loadNotifications();
      loadUnreadCount();
    }
  }, [userId]);

  // Set up real-time subscription
  useEffect(() => {
    if (!userId) return;

    const subscription = NotificationService.subscribeToNotifications(
      payload => {
        console.log('Notification update:', payload);

        if (payload.eventType === 'INSERT') {
          // New notification added
          const newNotification = payload.new as Notification;
          if (newNotification.user_id === userId) {
            setNotifications(prev => [newNotification, ...prev]);
            setUnreadCount(prev => prev + 1);
          }
        } else if (payload.eventType === 'UPDATE') {
          // Notification updated (e.g., marked as read)
          const updatedNotification = payload.new as Notification;
          setNotifications(prev =>
            prev.map(notification =>
              notification.id === updatedNotification.id
                ? updatedNotification
                : notification
            )
          );

          // Update unread count
          loadUnreadCount();
        } else if (payload.eventType === 'DELETE') {
          // Notification deleted
          const deletedId = payload.old.id;
          setNotifications(prev => prev.filter(n => n.id !== deletedId));
          loadUnreadCount();
        }
      }
    );

    return () => {
      subscription.unsubscribe();
    };
  }, [userId]);

  const loadNotifications = async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await NotificationService.getNotifications();
      setNotifications(data);
    } catch (err) {
      console.error('Error loading notifications:', err);
      setError(
        err instanceof Error ? err.message : 'Failed to load notifications'
      );
    } finally {
      setLoading(false);
    }
  };

  const loadUnreadCount = async () => {
    try {
      const count = await NotificationService.getUnreadCount();
      setUnreadCount(count);
    } catch (err) {
      console.error('Error loading unread count:', err);
    }
  };

  const markAsRead = useCallback(async (notificationId: string) => {
    try {
      await NotificationService.markAsRead(notificationId);
      setNotifications(prev =>
        prev.map(notification =>
          notification.id === notificationId
            ? { ...notification, read_at: new Date().toISOString() }
            : notification
        )
      );
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (error) {
      console.error('Error marking notification as read:', error);
    }
  }, []);

  const markAllAsRead = useCallback(async () => {
    try {
      await NotificationService.markAllAsRead();
      setNotifications(prev =>
        prev.map(notification => ({
          ...notification,
          read_at: new Date().toISOString(),
        }))
      );
      setUnreadCount(0);
    } catch (error) {
      console.error('Error marking all notifications as read:', error);
    }
  }, []);

  const deleteNotification = useCallback(
    async (notificationId: string) => {
      try {
        await NotificationService.deleteNotification(notificationId);
        setNotifications(prev => prev.filter(n => n.id !== notificationId));

        // Check if the deleted notification was unread
        const deletedNotification = notifications.find(
          n => n.id === notificationId
        );
        if (deletedNotification && !deletedNotification.read_at) {
          setUnreadCount(prev => Math.max(0, prev - 1));
        }
      } catch (error) {
        console.error('Error deleting notification:', error);
      }
    },
    [notifications]
  );

  const refresh = useCallback(async () => {
    await Promise.all([loadNotifications(), loadUnreadCount()]);
  }, []);

  return {
    notifications,
    unreadCount,
    loading,
    error,
    markAsRead,
    markAllAsRead,
    deleteNotification,
    refresh,
  };
};

