export const usePlatformIntegration = () => {
  const { toast } = useToast();
  const [platforms, setPlatforms] = useState<Platform[]>(() => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      return stored ? JSON.parse(stored) : DEFAULT_PLATFORMS;
    } catch {
      return DEFAULT_PLATFORMS;
    }
  });

  const [activityStats, setActivityStats] = useState<ActivityStats>({
    totalSolved: 142,
    weekSolved: 23,
    currentStreak: 7,
    contestRating: 1456,
  });

  const [activityData, setActivityData] = useState<ActivityData>(() => {
    try {
      const stored = localStorage.getItem(ACTIVITY_KEY);
      return stored ? JSON.parse(stored) : generateSampleActivityData();
    } catch {
      return generateSampleActivityData();
    }
  });

  // Save to localStorage whenever platforms change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(platforms));
  }, [platforms]);

  useEffect(() => {
    localStorage.setItem(ACTIVITY_KEY, JSON.stringify(activityData));
  }, [activityData]);

  const connectPlatform = async (platformId: string, credentials: any) => {
    setPlatforms(prev =>
      prev.map(p =>
        p.id === platformId
          ? {
              ...p,
              isConnected: true,
              handle:
                credentials.profileUrl ||
                credentials.handle ||
                credentials.apiKey,
              syncStatus: 'idle',
              lastSync: new Date().toISOString(),
            }
          : p
      )
    );

    toast({
      title: 'Platform Connected',
      description: `Successfully connected to ${platforms.find(p => p.id === platformId)?.name}`,
    });

    // Trigger initial sync
    await syncPlatform(platformId);
  };

  const disconnectPlatform = (platformId: string) => {
    setPlatforms(prev =>
      prev.map(p =>
        p.id === platformId
          ? {
              ...p,
              isConnected: false,
              handle: undefined,
              lastSync: undefined,
              syncStatus: 'idle',
            }
          : p
      )
    );

    toast({
      title: 'Platform Disconnected',
      description: `Disconnected from ${platforms.find(p => p.id === platformId)?.name}`,
    });
  };

  const syncPlatform = async (platformId: string) => {
    const platform = platforms.find(p => p.id === platformId);
    if (!platform?.isConnected || !platform.handle) return;

    setPlatforms(prev =>
      prev.map(p => (p.id === platformId ? { ...p, syncStatus: 'syncing' } : p))
    );

    try {
      let data;

      // Extract username from handle (could be URL or username)
      const extractUsername = (handle: string) => {
        try {
          const url = new URL(handle);
          return url.pathname.split('/').filter(Boolean).pop() || handle;
        } catch {
          return handle;
        }
      };

      const username = extractUsername(platform.handle);

      switch (platformId) {
        case 'leetcode':
          data = await fetchLeetCodeData(username);
          break;
        case 'codeforces':
          data = await fetchCodeforcesData(username);
          break;
        case 'codewars':
          data = await fetchCodewarsData(username);
          break;
        case 'gfg':
          data = await fetchGFGData(username);
          break;
        case 'hackerrank':
          data = await fetchHackerRankData(username);
          break;
        case 'hackerearth':
          data = await fetchHackerEarthData(username);
          break;
        case 'codechef':
          data = await fetchCodeChefData(username);
          break;
        default:
          throw new Error('Unsupported platform');
      }

      // Update activity stats
      setActivityStats(prev => ({
        ...prev,
        totalSolved: prev.totalSolved + (data.solved || 0),
        weekSolved: prev.weekSolved + Math.floor((data.solved || 0) * 0.1),
      }));

      // Update activity data with new sync
      const today = new Date().toISOString().split('T')[0];
      setActivityData(prev => ({
        ...prev,
        dailyProgress: prev.dailyProgress.map(day =>
          day.date === today
            ? { ...day, solved: day.solved + (data.solved || 0) }
            : day
        ),
      }));

      setPlatforms(prev =>
        prev.map(p =>
          p.id === platformId
            ? {
                ...p,
                syncStatus: 'success',
                lastSync: new Date().toISOString(),
              }
            : p
        )
      );

      toast({
        title: 'Sync Successful',
        description: `Updated data from ${platform.name}. Found ${data.solved} problems solved.`,
      });
    } catch (error) {
      console.error('Sync failed:', error);

      setPlatforms(prev =>
        prev.map(p => (p.id === platformId ? { ...p, syncStatus: 'error' } : p))
      );

      toast({
        title: 'Sync Failed',
        description: `Failed to sync data from ${platform.name}. Please check your connection.`,
        variant: 'destructive',
      });
    }
  };

  const syncAllPlatforms = async () => {
    const connectedPlatforms = platforms.filter(p => p.isConnected);

    for (const platform of connectedPlatforms) {
      await syncPlatform(platform.id);
      // Add small delay between syncs to avoid rate limiting
      await new Promise(resolve => setTimeout(resolve, 1000));
    }
  };

  return {
    platforms,
    activityStats,
    activityData,
    connectPlatform,
    disconnectPlatform,
    syncPlatform,
    syncAllPlatforms,
  };
};

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from './useAuth';

export interface Profile {
  id: string;
  user_id: string;
  full_name: string;
  email: string;
  role: 'student' | 'faculty';
  faculty_level?: 'basic' | 'senior' | 'admin';
  student_id?: string;
  faculty_id?: string;
  assigned_faculty_id?: string;
  teaching_id?: string | null;
  teaching_id_verified?: boolean | null;
  created_at: string;
  updated_at: string;
}

export const useProfile = () => {
  const { user } = useAuth();
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);
  const [profileError, setProfileError] = useState<any>(null);

  useEffect(() => {
    if (user) {
      fetchProfile();
    } else {
      setProfile(null);
      setLoading(false);
    }
  }, [user]);

  const fetchProfile = async () => {
    if (!user) {
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('user_id', user.id)
        .limit(1)
        .maybeSingle();

      if (error) {
        setProfileError(error);
        console.error(
          'Error fetching profile:',
          (error as any)?.message ?? JSON.stringify(error)
        );
      } else {
        if (!data) {
          try {
            const meta = (user as any)?.user_metadata ?? {};
            const full_name = meta.full_name ?? user.email ?? '';
            const role = meta.role === 'faculty' ? 'faculty' : 'student';

            const { data: created, error: createError } = await supabase
              .from('profiles')
              .upsert(
                {
                  user_id: user.id,
                  full_name,
                  email: user.email as string,
                  role,
                },
                { onConflict: 'user_id' }
              )
              .select()
              .maybeSingle();

            if (createError) {
              const msg = (createError as any)?.message ?? '';
              if (
                msg.includes('duplicate key') ||
                msg.includes('already exists')
              ) {
                const { data: existing } = await supabase
                  .from('profiles')
                  .select('*')
                  .eq('user_id', user.id)
                  .limit(1)
                  .maybeSingle();
                setProfile((existing ?? null) as Profile | null);
              } else {
                setProfileError(createError);
                console.error(
                  'Error creating profile:',
                  (createError as any)?.message ?? JSON.stringify(createError)
                );
              }
            } else {
              setProfile((created ?? null) as Profile | null);
            }
          } catch (err) {
            setProfileError(err);
            console.error(
              'Error creating profile:',
              (err as any)?.message ?? JSON.stringify(err)
            );
          }
        } else {
          setProfile((data ?? null) as Profile | null);
        }
      }
    } catch (error) {
      setProfileError(error);
      console.error(
        'Error fetching profile:',
        (error as any)?.message ?? JSON.stringify(error)
      );
    } finally {
      setLoading(false);
    }
  };

  const updateProfile = async (updates: Partial<Profile>) => {
    if (!user || !profile) return;

    try {
      const { data, error } = await supabase
        .from('profiles')
        .update(updates)
        .eq('id', profile.id)
        .select()
        .single();

      if (error) {
        setProfileError(error);
        console.error(
          'Error updating profile:',
          (error as any)?.message ?? JSON.stringify(error)
        );
        return { error };
      } else {
        setProfile({ ...(data as Profile) });
        setProfileError(null);
        return { error: null };
      }
    } catch (error) {
      setProfileError(error);
      console.error(
        'Error updating profile:',
        (error as any)?.message ?? JSON.stringify(error)
      );
      return { error };
    }
  };

  return {
    profile,
    loading,
    error: profileError,
    updateProfile,
    refetch: fetchProfile,
  };
};

