                          <span
                            className={`text-sm ${getStatusColor(entry.response.status)}`}
                          >
                            {entry.response.status}
                          </span>
                        </div>
                        <div className='flex items-center gap-2 text-sm text-gray-500'>
                          <span>{entry.response.time}ms</span>
                          <span>{entry.timestamp.toLocaleTimeString()}</span>
                        </div>
                      </div>
                      <code className='text-xs text-blue-600 block mb-2'>
                        {entry.url}
                      </code>
                      <div className='flex gap-2'>
                        <Button
                          size='sm'
                          variant='outline'
                          onClick={() => loadSavedRequest(entry)}
                        >
                          <Eye className='w-4 h-4 mr-1' />
                          Reload
                        </Button>
                        <Button
                          size='sm'
                          variant='outline'
                          onClick={() =>
                            copyToClipboard(
                              JSON.stringify(entry.response.data, null, 2)
                            )
                          }
                        >
                          <Copy className='w-4 h-4 mr-1' />
                          Copy Response
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Load Request Dialog */}
      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className='max-w-2xl'>
          <DialogHeader>
            <DialogTitle>Load Saved Request</DialogTitle>
          </DialogHeader>
          {selectedRequest && (
            <div className='space-y-4'>
              <div className='grid grid-cols-2 gap-4'>
                <div>
                  <Label className='text-sm font-medium'>Request Name</Label>
                  <p className='text-sm text-gray-600'>
                    {selectedRequest.name}
                  </p>
                </div>
                <div>
                  <Label className='text-sm font-medium'>Method</Label>
                  <Badge variant='outline' className='ml-2'>
                    {selectedRequest.method}
                  </Badge>
                </div>
              </div>

              <div>
                <Label className='text-sm font-medium'>URL</Label>
                <code className='block text-sm text-blue-600 bg-gray-100 p-2 rounded mt-1 break-all'>
                  {selectedRequest.url}
                </code>
              </div>

              {selectedRequest.description && (
                <div>
                  <Label className='text-sm font-medium'>Description</Label>
                  <p className='text-sm text-gray-600 mt-1'>
                    {selectedRequest.description}
                  </p>
                </div>
              )}

              {Object.keys(selectedRequest.headers).length > 0 && (
                <div>
                  <Label className='text-sm font-medium'>Headers</Label>
                  <div className='bg-gray-50 rounded-lg p-3 mt-1 max-h-32 overflow-y-auto'>
                    <pre className='text-xs'>
                      {Object.entries(selectedRequest.headers).map(
                        ([key, value]) => (
                          <div key={key} className='flex justify-between'>
                            <span className='font-mono text-blue-600'>
                              {key}:
                            </span>
                            <span className='font-mono text-gray-700'>
                              {value}
                            </span>
                          </div>
                        )
                      )}
                    </pre>
                  </div>
                </div>
              )}

              {selectedRequest.body && (
                <div>
                  <Label className='text-sm font-medium'>Request Body</Label>
                  <div className='bg-gray-900 text-green-400 rounded-lg p-3 mt-1 max-h-32 overflow-y-auto'>
                    <pre className='text-xs'>{selectedRequest.body}</pre>
                  </div>
                </div>
              )}

              <div className='flex justify-end gap-2 pt-4'>
                <Button
                  variant='outline'
                  onClick={() => setIsDialogOpen(false)}
                >
                  Cancel
                </Button>
                <Button onClick={confirmLoadRequest}>Load Request</Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default AdminApiTesting;

import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import {
  Plus,
  Search,
  UserCheck,
  Users,
  GraduationCap,
  Filter,
  TrendingUp,
  Clock,
  Shield,
  Activity,
  RefreshCw,
  Download,
  Upload,
  Target,
  Link as LinkIcon,
  CheckCircle,
  AlertCircle,
  BarChart3,
  Calendar,
  Award,
  Zap,
} from 'lucide-react';
import AssignmentTable from '@/components/admin/AssignmentTable';
import AssignMentorModal from '@/components/admin/AssignMentorModal';
import type { Tables } from '@/integrations/supabase/types';

type Profile = Tables<'profiles'>;
type Faculty = Tables<'faculty'>;
type StudentMentorAssignment = Tables<'student_mentor_assignments'>;

interface AssignmentWithDetails extends StudentMentorAssignment {
  student?: Profile;
  mentor?: Faculty;
}

const AdminAssignments: React.FC = () => {
  const [assignments, setAssignments] = useState<AssignmentWithDetails[]>([]);
  const [students, setStudents] = useState<Profile[]>([]);
  const [faculty, setFaculty] = useState<Faculty[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [showAssignModal, setShowAssignModal] = useState(false);
  const [filterDepartment, setFilterDepartment] = useState('all');
  const { toast } = useToast();

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      console.log('Fetching assignment data...');

      // Fetch all assignments with student and mentor details
      const { data: assignmentsData, error: assignmentsError } = await supabase
        .from('student_mentor_assignments')
        .select(
          `
          *,
          student:profiles!student_mentor_assignments_student_id_fkey(*),
          mentor:faculty!student_mentor_assignments_mentor_id_fkey(*)
        `
        )
        .order('created_at', { ascending: false });

      console.log('Assignments data:', assignmentsData);
      console.log('Assignments error:', assignmentsError);

      if (assignmentsError) {
        console.error('Assignments error:', assignmentsError);
        throw assignmentsError;
      }

      // Fetch all students - try different approaches
      let studentsData = null;
      let studentsError = null;

      // First try with string comparison
      const { data: studentsData1, error: studentsError1 } = await supabase
        .from('profiles')
        .select('*')
        .eq('role', 'student')
        .order('full_name');

      if (studentsError1) {
        console.log('String comparison failed, trying text casting...');
        // If that fails, try with text casting
        const { data: studentsData2, error: studentsError2 } = await supabase
          .from('profiles')
          .select('*')
          .filter('role', 'eq', 'student')
          .order('full_name');

        studentsData = studentsData2;
        studentsError = studentsError2;
      } else {
        studentsData = studentsData1;
        studentsError = studentsError1;
      }

      console.log('Students data:', studentsData);
      console.log('Students error:', studentsError);

      if (studentsError) {
        console.error('Students error:', studentsError);
        // Don't throw error, just log it and continue with empty array
        console.log('Continuing with empty students array...');
        studentsData = [];
      }

      // Fetch verified faculty (potential mentors)
      const { data: facultyData, error: facultyError } = await supabase
        .from('faculty')
        .select('*')
        .eq('is_verified', true)
        .order('name');

      console.log('Faculty data:', facultyData);
      console.log('Faculty error:', facultyError);

      if (facultyError) {
        console.error('Faculty error:', facultyError);
        throw facultyError;
      }

      setAssignments(assignmentsData || []);
      setStudents(studentsData || []);
      setFaculty(facultyData || []);

      console.log('Data set successfully:', {
        assignments: assignmentsData?.length || 0,
        students: studentsData?.length || 0,
        faculty: facultyData?.length || 0,
      });
    } catch (error) {
      console.error('Error fetching data:', error);
      toast({
        title: 'Error',
        description: `Failed to fetch assignment data: ${error.message}`,
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  const handleAssignMentor = async (studentId: string, mentorId: string) => {
    try {
      // Check if assignment already exists
      const existingAssignment = assignments.find(
        a => a.student_id === studentId
      );

      if (existingAssignment) {
        // Update existing assignment
        const { error } = await supabase
          .from('student_mentor_assignments')
          .update({ mentor_id: mentorId })
          .eq('student_id', studentId);

        if (error) throw error;
      } else {
        // Create new assignment
        const { error } = await supabase
          .from('student_mentor_assignments')
          .insert([{ student_id: studentId, mentor_id: mentorId }]);

        if (error) throw error;
      }

      toast({
        title: 'Success',
        description: 'Mentor assigned successfully',
      });

      fetchData();
      setShowAssignModal(false);
    } catch (error) {
      console.error('Error assigning mentor:', error);
      toast({
        title: 'Error',
        description: 'Failed to assign mentor',
        variant: 'destructive',
      });
    }
