      const { error } = await supabase
        .from('faculty')
        .update({ is_verified: isVerified })
        .eq('id', facultyId);

      if (error) throw error;

      setFaculty(prev =>
        prev.map(f =>
          f.id === facultyId ? { ...f, is_verified: isVerified } : f
        )
      );

      toast({
        title: 'Success',
        description: `Faculty ${isVerified ? 'verified' : 'unverified'} successfully`,
