              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Faculty Table */}
      <FacultyTable
        faculty={filteredFaculty}
        onEdit={faculty => {
          setEditingFaculty(faculty);
          setShowForm(true);
        }}
        onDelete={handleDeleteFaculty}
        onVerify={handleVerifyFaculty}
      />

      {/* Faculty Form Modal */}
      <FacultyForm
        open={showForm}
        onOpenChange={setShowForm}
        faculty={editingFaculty}
        onSave={() => {
          setShowForm(false);
          setEditingFaculty(null);
          fetchFaculty();
        }}
      />

      <CSVImportModal
        open={showCSVImport}
        onOpenChange={setShowCSVImport}
        onImport={() => {
          fetchFaculty();
        }}
      />
    </div>
  );
};

