                                  const data = lines.slice(1).map(line => {
                                    const values = line.split(',');
                                    const obj: any = {};
                                    headers.forEach((header, index) => {
                                      obj[header.trim()] =
                                        values[index]?.trim();
                                    });
                                    return obj;
                                  });
                                  parsedConfig = { csvData: data };
