                          ((a.upvotes || 0) - (a.downvotes || 0)) ||
                        b.created_at.localeCompare(a.created_at)
                    );
                    return sorted.slice(0, 5).map((p, i) => (
                      <div
                        key={p.id}
                        className='flex items-start gap-3 p-3 rounded-lg hover:bg-gray-50 transition-colors'
