                        </Button>
                      </div>
                    ))}
                </div>
              </CardContent>
            </Card>

            {/* Leaderboard */}
            <Card className='shadow-lg border-0 bg-white/80 backdrop-blur-sm'>
              <CardHeader className='pb-3'>
                <CardTitle className='flex items-center gap-2 text-lg'>
                  <Award className='w-5 h-5 text-yellow-600' />
                  Top Contributors
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className='space-y-3'>
                  {Object.entries(
                    posts.reduce(
                      (acc, p) => {
                        acc[p.author_name] =
                          (acc[p.author_name] || 0) +
                          ((p.upvotes || 0) - (p.downvotes || 0));
                        return acc;
                      },
                      {} as Record<string, number>
                    )
                  )
                    .sort((a, b) => b[1] - a[1])
                    .slice(0, 5)
                    .map(([name, score], i) => (
                      <div
                        key={name}
                        className='flex items-center justify-between p-3 rounded-lg hover:bg-gray-50 transition-colors'
                      >
                        <div className='flex items-center gap-3'>
                          <div className='flex-shrink-0 w-8 h-8 rounded-full bg-gradient-to-br from-yellow-500 to-orange-500 flex items-center justify-center text-white font-bold text-sm'>
                            {i + 1}
                          </div>
                          <div>
                            <div className='font-medium text-sm'>{name}</div>
                            <div className='text-xs text-gray-500'>
                              {score} points
                            </div>
                          </div>
                        </div>
                        <div className='flex items-center gap-1'>
                          <Star className='w-4 h-4 text-yellow-500' />
                          <span className='text-sm font-medium'>{score}</span>
                        </div>
                      </div>
                    ))}
                </div>
              </CardContent>
            </Card>
          </div>
        </aside>
      </main>

      {/* Group creation modal */}
      {creatingGroup && (
        <div className='fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50'>
          <Card className='w-full max-w-md mx-4 shadow-2xl'>
            <CardHeader>
              <CardTitle className='flex items-center gap-2'>
                <Plus className='w-5 h-5 text-blue-600' />
                Create New Group
              </CardTitle>
            </CardHeader>
            <CardContent className='space-y-4'>
              <div>
                <Label htmlFor='group-name'>Group Name</Label>
                <Input
                  id='group-name'
                  value={newGroupName}
                  onChange={e => setNewGroupName(e.target.value)}
                  placeholder='Enter group name'
                  className='mt-1'
                />
              </div>
              <div>
                <Label htmlFor='group-desc'>Description (Optional)</Label>
                <Textarea
                  id='group-desc'
                  value={newGroupDesc}
                  onChange={e => setNewGroupDesc(e.target.value)}
                  placeholder='Brief description of the group'
                  className='mt-1'
                />
              </div>
              <div className='flex justify-end gap-3 pt-4'>
                <Button
                  variant='outline'
                  onClick={() => setCreatingGroup(false)}
                >
                  Cancel
                </Button>
                <Button
                  onClick={handleCreateGroup}
                  className='bg-blue-600 hover:bg-blue-700'
                >
                  Create Group
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Post comment modal using openPostId handled above */}
    </div>
  );
}

function CommentBox({
