  };
  const isBookmarked = (fid: string) => bookmarks.includes(fid);

  const onMessage = (fid: string) => {
    if (blocked.includes(fid)) {
      toast({
        title: 'Blocked',
        description: 'You have blocked this faculty. Unblock to message.',
        variant: 'destructive',
