              </CardHeader>
              <CardContent>
                <div className='relative'>
                  <div
                    className={`transition-all duration-300 ${viewMode === 'weekly' ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-2 pointer-events-none'}`}
                    aria-hidden={viewMode !== 'weekly'}
