import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { getProfileAvatarUrl } from '@/utils/avatarUtils';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { useProfile } from '@/hooks/useProfile';
import {
  Search,
  Users,
  Mail,
  Phone,
  GraduationCap,
  Calendar,
  BookOpen,
  Award,
  UserCheck,
  Filter,
} from 'lucide-react';
import type { Tables } from '@/integrations/supabase/types';

type Profile = Tables<'profiles'>;
type Faculty = Tables<'faculty'>;

const FacultyStudents: React.FC = () => {
  const [students, setStudents] = useState<Profile[]>([]);
  const [faculty, setFaculty] = useState<Faculty | null>(null);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const { toast } = useToast();
  const { profile } = useProfile();

  useEffect(() => {
    fetchFacultyAndStudents();
  }, [profile]);

  const fetchFacultyAndStudents = async () => {
    if (!profile) return;

    setLoading(true);
    try {
      // Get faculty info by email (simpler approach)
      console.log('Looking up faculty by email:', profile.email);
      const { data: facultyData, error: facultyError } = await supabase
        .from('faculty')
        .select('*')
        .eq('email', profile.email)
        .single();

      if (facultyError && facultyError.code === 'PGRST116') {
        // No faculty record found, show helpful message
        console.log('No faculty record found for user');
        toast({
          title: 'Faculty Record Not Found',
          description:
            'No faculty record found for your account. Please contact administrator to set up your faculty profile.',
          variant: 'destructive',
        });
        return;
      }

      if (facultyError) {
        console.error('Faculty error:', facultyError);
        toast({
          title: 'Error',
          description:
            'Failed to load faculty information. Please ensure you are registered as faculty.',
          variant: 'destructive',
        });
        return;
      }

      if (!facultyData) {
        console.error('No faculty record found for user');
        toast({
          title: 'Faculty Not Found',
          description:
            'No faculty record found for your account. Please contact administrator.',
          variant: 'destructive',
        });
        return;
      }

      setFaculty(facultyData);

      // Get assigned students through the student_mentor_assignments table
      const { data: assignmentsData, error: assignmentsError } = await supabase
        .from('student_mentor_assignments')
        .select(
          `
          *,
          student:profiles!student_mentor_assignments_student_id_fkey(*)
        `
        )
        .eq('mentor_id', facultyData.id)
        .order('created_at', { ascending: false });

      if (assignmentsError) {
        console.error('Assignments error:', assignmentsError);
        toast({
          title: 'Error',
          description: 'Failed to load assigned students',
          variant: 'destructive',
        });
        return;
      }

      // Extract students from assignments
      const studentsData =
        assignmentsData
          ?.map(assignment => assignment.student)
          .filter(Boolean) || [];

      setStudents(studentsData);
    } catch (error) {
      console.error('Error fetching data:', error);
      toast({
        title: 'Error',
        description: 'Failed to load data',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  const filteredStudents = students.filter(
    student =>
      student.full_name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      student.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      student.student_roll_number
        ?.toLowerCase()
        .includes(searchQuery.toLowerCase())
  );

  if (loading) {
    return (
      <div className='min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-100 flex items-center justify-center'>
        <div className='text-center'>
          <div className='animate-spin rounded-full h-12 w-12 border-4 border-blue-200 border-t-blue-600 mx-auto mb-4'></div>
          <p className='text-gray-600'>Loading your assigned students...</p>
        </div>
      </div>
    );
  }

  return (
    <div className='min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-100'>
      <div className='max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8'>
        {/* Header */}
        <div className='mb-8'>
          <div className='flex items-center justify-between'>
            <div>
              <h1 className='text-3xl font-bold text-gray-900 mb-2'>
                My Assigned Students
              </h1>
              <p className='text-gray-600'>
                {faculty?.name} - {faculty?.faculty_code}
              </p>
            </div>
            <Badge className='bg-blue-100 text-blue-800 px-4 py-2'>
              <Users className='w-4 h-4 mr-2' />
              {students.length} Students
            </Badge>
          </div>
        </div>

        {/* Search */}
        <Card className='mb-6'>
          <CardContent className='p-6'>
            <div className='relative'>
              <Search className='absolute left-4 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gray-400' />
              <Input
                placeholder='Search students by name, email, or roll number...'
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                className='pl-12 h-12'
              />
            </div>
          </CardContent>
        </Card>

        {/* Students Grid */}
        {filteredStudents.length === 0 ? (
          <Card>
            <CardContent className='p-12 text-center'>
              <div className='w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4'>
                <Users className='w-8 h-8 text-gray-400' />
              </div>
              <h3 className='text-lg font-semibold text-gray-900 mb-2'>
                {searchQuery ? 'No students found' : 'No students assigned'}
              </h3>
              <p className='text-gray-600'>
                {searchQuery
                  ? 'Try adjusting your search terms'
                  : 'Contact admin to get students assigned to you'}
              </p>
            </CardContent>
          </Card>
        ) : (
          <div className='grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6'>
            {filteredStudents.map(student => (
              <Card
                key={student.id}
                className='hover:shadow-lg transition-shadow'
              >
                <CardHeader className='pb-4'>
                  <div className='flex items-center space-x-4'>
                    <Avatar className='h-12 w-12'>
                      <AvatarImage
                        src={getProfileAvatarUrl({
                          avatar_url: student.avatar_url,
                          full_name: student.full_name,
                          role: 'student',
                        })}
                      />
                      <AvatarFallback className='bg-gradient-to-br from-blue-500 to-purple-600 text-white'>
                        {student.full_name?.charAt(0) || 'S'}
                      </AvatarFallback>
                    </Avatar>
                    <div className='flex-1 min-w-0'>
                      <h3 className='font-semibold text-gray-900 truncate'>
                        {student.full_name}
                      </h3>
                      <p className='text-sm text-gray-600 truncate'>
                        {student.student_roll_number}
                      </p>
                    </div>
                  </div>
                </CardHeader>
                <CardContent className='space-y-3'>
                  <div className='flex items-center space-x-2 text-sm text-gray-600'>
                    <Mail className='h-4 w-4' />
                    <span className='truncate'>{student.email}</span>
                  </div>

                  {student.phone && (
                    <div className='flex items-center space-x-2 text-sm text-gray-600'>
                      <Phone className='h-4 w-4' />
                      <span>{student.phone}</span>
                    </div>
                  )}

                  {student.department && (
                    <div className='flex items-center space-x-2 text-sm text-gray-600'>
                      <BookOpen className='h-4 w-4' />
                      <span>{student.department}</span>
                    </div>
                  )}

                  {student.graduation_year && (
                    <div className='flex items-center space-x-2 text-sm text-gray-600'>
                      <Calendar className='h-4 w-4' />
                      <span>Class of {student.graduation_year}</span>
                    </div>
                  )}

                  <div className='pt-2'>
                    <Badge variant='outline' className='text-xs'>
                      <UserCheck className='w-3 h-3 mr-1' />
                      Assigned Student
                    </Badge>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default FacultyStudents;

import React, { useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { CheckCircle, XCircle, Loader2, Github } from 'lucide-react';
import GitHubService from '@/services/githubService';
import { useToast } from '@/hooks/use-toast';

const GithubCallback: React.FC = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { toast } = useToast();
  const [status, setStatus] = useState<'loading' | 'success' | 'error'>(
    'loading'
  );
  const [message, setMessage] = useState('');

  useEffect(() => {
    const handleCallback = async () => {
      try {
        const code = searchParams.get('code');
        const error = searchParams.get('error');
        const errorDescription = searchParams.get('error_description');

        if (error) {
          setStatus('error');
          setMessage(errorDescription || error);
          return;
        }

        if (!code) {
          setStatus('error');
          setMessage('No authorization code received from GitHub');
          return;
        }

        // Exchange code for access token
        await GitHubService.getInstance().exchangeCodeForToken(code);

        setStatus('success');
        setMessage(
          'Successfully connected to GitHub! Redirecting to projects...'
        );

        // Show success toast
        toast({
          title: 'GitHub Connected',
          description:
            'You can now import your GitHub repositories as projects!',
        });

        // Redirect to projects page after a short delay
        setTimeout(() => {
          navigate('/my-projects');
        }, 2000);
      } catch (error: any) {
        console.error('GitHub callback error:', error);
        setStatus('error');
        setMessage(error.message || 'Failed to connect to GitHub');

        toast({
          title: 'Connection Failed',
          description: error.message || 'Failed to connect to GitHub',
          variant: 'destructive',
        });
      }
    };

    handleCallback();
  }, [searchParams, navigate, toast]);

  const handleRetry = () => {
    navigate('/my-projects');
  };

  const handleConnectAgain = () => {
    const githubService = GitHubService.getInstance();
    window.location.href = githubService.getAuthUrl();
  };

  return (
    <div className='min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-50 to-blue-50 p-4'>
      <Card className='w-full max-w-md'>
        <CardContent className='p-8 text-center'>
          <div className='mb-6'>
            {status === 'loading' && (
              <div className='mx-auto w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mb-4'>
                <Loader2 className='w-8 h-8 text-blue-600 animate-spin' />
              </div>
            )}
            {status === 'success' && (
              <div className='mx-auto w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4'>
                <CheckCircle className='w-8 h-8 text-green-600' />
              </div>
            )}
            {status === 'error' && (
              <div className='mx-auto w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mb-4'>
                <XCircle className='w-8 h-8 text-red-600' />
              </div>
            )}
          </div>

          <div className='mb-6'>
            <h1 className='text-2xl font-bold text-gray-900 mb-2'>
              {status === 'loading' && 'Connecting to GitHub...'}
              {status === 'success' && 'GitHub Connected!'}
              {status === 'error' && 'Connection Failed'}
            </h1>
            <p className='text-gray-600'>{message}</p>
          </div>

          {status === 'loading' && (
            <div className='space-y-2'>
              <p className='text-sm text-gray-500'>
                Please wait while we set up your GitHub connection...
              </p>
            </div>
          )}

          {status === 'success' && (
            <div className='space-y-4'>
              <div className='flex items-center justify-center space-x-2 text-green-600'>
                <Github className='w-5 h-5' />
                <span className='text-sm font-medium'>
                  GitHub Integration Active
                </span>
              </div>
              <p className='text-sm text-gray-500'>
                You'll be redirected to your projects page shortly.
              </p>
            </div>
          )}

          {status === 'error' && (
            <div className='space-y-4'>
              <div className='flex items-center justify-center space-x-2 text-red-600'>
                <XCircle className='w-5 h-5' />
                <span className='text-sm font-medium'>Connection Failed</span>
              </div>
              <div className='space-y-2'>
                <Button
                  onClick={handleRetry}
                  variant='outline'
                  className='w-full'
                >
                  Go to Projects
                </Button>
                <Button onClick={handleConnectAgain} className='w-full'>
                  <Github className='w-4 h-4 mr-2' />
                  Try Again
                </Button>
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

export default GithubCallback;

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Github, CheckCircle, XCircle, Loader2 } from 'lucide-react';
import GitHubService from '@/services/githubService';
import { useToast } from '@/hooks/use-toast';

const GithubTest: React.FC = () => {
  const { toast } = useToast();
  const [status, setStatus] = useState<
    'idle' | 'loading' | 'success' | 'error'
  >('idle');
  const [message, setMessage] = useState('');
  const [userInfo, setUserInfo] = useState<any>(null);

  const handleConnect = () => {
    const githubService = GitHubService.getInstance();
    window.location.href = githubService.getAuthUrl();
  };

  const handleTestToken = async () => {
    const githubService = GitHubService.getInstance();

    if (!githubService.isAuthenticated()) {
      setStatus('error');
      setMessage('No access token found. Please connect to GitHub first.');
      return;
    }

    setStatus('loading');
    setMessage('Testing GitHub API access...');

    try {
      const user = await githubService.getCurrentUser();
      setUserInfo(user);
      setStatus('success');
      setMessage(`Successfully connected as ${user.login}`);

      toast({
        title: 'GitHub Connected!',
        description: `Welcome ${user.name || user.login}!`,
      });
    } catch (error: any) {
      setStatus('error');
      setMessage(`Error: ${error.message}`);

      toast({
        title: 'Connection Failed',
        description: error.message,
        variant: 'destructive',
      });
    }
  };

  const handleDisconnect = () => {
    const githubService = GitHubService.getInstance();
    githubService.logout();
    setStatus('idle');
    setMessage('');
    setUserInfo(null);

    toast({
      title: 'Disconnected',
      description: 'GitHub connection removed',
    });
  };

  const githubService = GitHubService.getInstance();
  const isConnected = githubService.isAuthenticated();

  return (
    <div className='min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 p-8'>
      <div className='max-w-2xl mx-auto space-y-6'>
        <Card>
          <CardHeader>
            <CardTitle className='flex items-center gap-2'>
              <Github className='h-6 w-6' />
              GitHub OAuth Test
            </CardTitle>
          </CardHeader>
          <CardContent className='space-y-4'>
            <div className='flex items-center gap-4'>
              <Badge variant={isConnected ? 'default' : 'secondary'}>
                {isConnected ? 'Connected' : 'Not Connected'}
              </Badge>
              {isConnected && (
                <Button variant='outline' size='sm' onClick={handleDisconnect}>
                  Disconnect
                </Button>
              )}
            </div>

            {!isConnected ? (
              <Button onClick={handleConnect} className='w-full'>
                <Github className='h-4 w-4 mr-2' />
                Connect to GitHub
              </Button>
            ) : (
              <Button
                onClick={handleTestToken}
                disabled={status === 'loading'}
                className='w-full'
              >
                {status === 'loading' ? (
                  <Loader2 className='h-4 w-4 mr-2 animate-spin' />
                ) : (
                  <Github className='h-4 w-4 mr-2' />
                )}
                Test GitHub API Access
              </Button>
            )}

            {status !== 'idle' && (
              <div
                className={`p-4 rounded-lg flex items-center gap-3 ${
                  status === 'success'
                    ? 'bg-green-50 text-green-700'
                    : status === 'error'
                      ? 'bg-red-50 text-red-700'
                      : 'bg-blue-50 text-blue-700'
                }`}
              >
                {status === 'loading' && (
                  <Loader2 className='h-5 w-5 animate-spin' />
                )}
                {status === 'success' && <CheckCircle className='h-5 w-5' />}
                {status === 'error' && <XCircle className='h-5 w-5' />}
                <span className='font-medium'>{message}</span>
              </div>
            )}

            {userInfo && (
              <Card className='bg-gray-50'>
                <CardContent className='p-4'>
                  <div className='flex items-center gap-3'>
                    <img
                      src={userInfo.avatar_url}
                      alt={userInfo.name || userInfo.login}
                      className='w-12 h-12 rounded-full'
                    />
                    <div>
                      <h3 className='font-semibold'>
                        {userInfo.name || userInfo.login}
                      </h3>
                      <p className='text-sm text-gray-600'>@{userInfo.login}</p>
                      <p className='text-xs text-gray-500'>
                        {userInfo.public_repos} public repos ΓÇó{' '}
                        {userInfo.followers} followers
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className='text-lg'>Debug Information</CardTitle>
          </CardHeader>
          <CardContent className='space-y-2 text-sm'>
            <p>
              <strong>Current Origin:</strong> {window.location.origin}
            </p>
            <p>
              <strong>Redirect URI:</strong> {window.location.origin}
              /github-callback
            </p>
            <p>
              <strong>Client ID:</strong> Ov23liRiNJwonTZ5h3T6
            </p>
            <p>
              <strong>Access Token:</strong>{' '}
              {isConnected ? 'Present' : 'Not found'}
            </p>
          </CardContent>
        </Card>
      </div>
    </div>
  );
};

export default GithubTest;

