                                          className={`h-3 rounded ${a ? 'bg-emerald-400' : 'bg-emerald-100'} border ${a ? 'border-emerald-600' : 'border-transparent'}`}
                                        />
                                      ))}
                                    </div>
                                  </div>
                                );
                              })}
                            </div>
                          )}
                        </div>
                      );
                    })()}
