                  <CardTitle className='text-sm'>Leaderboard Snippet</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className='space-y-2'>
                    {filteredLeaderboard.slice(0, 3).map(row => (
                      <div
                        key={row.id}
