                      />
                    </div>
                  </div>

                  <div className='flex items-center justify-end gap-2 pt-1'>
                    <Button variant='ghost' onClick={() => setShowEdit(false)}>
                      Cancel
                    </Button>
                    <Button
                      onClick={async () => {
                        if (!nameInput.trim() || !emailInput.trim()) return;
                        setSaving(true);
                        await updateProfile?.({
                          full_name: nameInput.trim(),
                          email: emailInput.trim(),
                        });
                        const existing = loadOverrides();
                        const next = {
                          ...existing,
                          avatarDataUrl,
                          age: ageInput,
                          year: yearInput,
                          course: courseInput,
                          college: collegeInput,
                          phone: phoneInput,
                          bio: bioInput,
                        };
                        saveOverrides(next);
                        setSaving(false);
                        setShowEdit(false);
                      }}
                      disabled={saving}
                    >
                      {saving ? 'Saving...' : 'Save Changes'}
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        )}

        {/* 3D Profile Card Modal */}
        {showProfileCard && (
