              </div>
            </div>
            <div className='flex items-center gap-4'>
              <span className='text-sm text-gray-600'>
                Welcome, {recruiter?.contact_person}
              </span>
              <Button variant='outline' size='sm' onClick={handleLogout}>
                <LogOut className='h-4 w-4 mr-2' />
                Logout
              </Button>
