import React, { useState, useEffect } from 'react';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { useProfile } from '@/hooks/useProfile';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/integrations/supabase/client';
import {
  BookOpen,
  ExternalLink,
  Users,
  Calendar,
  Clock,
  Award,
} from 'lucide-react';

interface Course {
  id: string;
  name: string;
  course_code: string;
  description?: string;
  external_link?: string;
  thumbnail_url?: string;
  credit_hours?: number;
  deadline?: string;
  tags?: string[];
  faculty_name?: string;
  created_at: string;
}

const StudentCourses: React.FC = () => {
  const { profile } = useProfile();
  const { toast } = useToast();

  const [courses, setCourses] = useState<Course[]>([]);
  const [loading, setLoading] = useState(false);

  // Fetch courses assigned to this student - simple approach
  const fetchAssignedCourses = async () => {
    if (!profile || profile.role !== 'student') {
      console.log('No profile or not a student:', {
        profile,
        role: profile?.role,
      });
      return;
    }

    try {
      setLoading(true);
      console.log(
        'Fetching courses for student:',
        profile.id,
        profile.full_name
      );

      // Just fetch all courses - simple
      const { data: allCoursesData, error: allCoursesError } = await supabase
        .from('courses')
        .select('*')
        .order('name');

      if (allCoursesError) {
        console.error('Error fetching courses:', allCoursesError);
        toast({
          title: 'Error',
          description: 'Failed to fetch courses: ' + allCoursesError.message,
          variant: 'destructive',
        });
        return;
      }

      console.log('All courses fetched:', allCoursesData?.length || 0);
      console.log(
        'Student profile ID:',
        profile.id,
        'Type:',
        typeof profile.id
      );

      // Filter courses where this student is assigned
      const assignedCourses = (allCoursesData || []).filter(course => {
        console.log(
          'Course:',
          course.name,
          'assigned_student_ids:',
          course.assigned_student_ids
        );
        return (
          course.assigned_student_ids &&
          Array.isArray(course.assigned_student_ids) &&
          course.assigned_student_ids.some(id => {
            // Convert both to strings for comparison
            const studentIdStr = profile.id.toString();
            const assignedIdStr = id.toString();
            const matches = assignedIdStr === studentIdStr;
            console.log(
              'Comparing:',
              assignedIdStr,
              'with',
              studentIdStr,
              'matches:',
              matches
            );
            return matches;
          })
        );
      });

      console.log('Assigned courses:', assignedCourses);
      setCourses(assignedCourses);
    } catch (err) {
      console.error('Error fetching courses:', err);
    } finally {
      setLoading(false);
    }
  };

  // Load courses when profile is available
  useEffect(() => {
    if (profile) {
      fetchAssignedCourses();
    }
  }, [profile]);

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  return (
    <div className='min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-100 p-6'>
      <div className='max-w-7xl mx-auto'>
        {/* Header */}
        <div className='mb-8'>
          <div className='flex justify-between items-start'>
            <div>
              <h1 className='text-3xl font-bold text-gray-900 mb-2'>
                My Courses
              </h1>
              <p className='text-gray-600'>
                Courses assigned to you by your faculty mentors
              </p>
            </div>
            <button
              onClick={fetchAssignedCourses}
              disabled={loading}
              className='px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600 disabled:opacity-50'
            >
              {loading ? 'Refreshing...' : 'Refresh'}
            </button>
          </div>
        </div>

        {/* Courses Grid */}
        {loading ? (
          <div className='text-center py-12'>
            <div className='inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-primary'></div>
            <p className='mt-2 text-gray-600'>Loading courses...</p>
          </div>
        ) : courses.length === 0 ? (
          <Card>
            <CardContent className='text-center py-12'>
              <div className='mb-4'>
                <BookOpen className='h-16 w-16 mx-auto text-gray-400' />
              </div>
              <h3 className='text-xl font-semibold text-gray-900 mb-2'>
                No Courses Assigned
              </h3>
              <p className='text-gray-600'>
                You don't have any courses assigned yet. Contact your faculty
                mentor to get course assignments.
              </p>
            </CardContent>
          </Card>
        ) : (
          <div className='grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6'>
            {courses.map(course => (
              <Card
                key={course.id}
                className='hover:shadow-lg transition-all duration-300 group'
              >
                <CardHeader className='pb-3'>
                  <div className='flex items-start justify-between'>
                    <div className='flex-1'>
                      <CardTitle className='text-lg group-hover:text-primary transition-colors'>
                        {course.name}
                      </CardTitle>
                      <CardDescription className='text-sm'>
                        {course.course_code} ΓÇó {course.faculty_name}
                      </CardDescription>
                    </div>
                    {course.external_link && (
                      <a
                        href={course.external_link}
                        target='_blank'
                        rel='noopener noreferrer'
                        className='text-primary hover:text-primary/80 transition-colors'
                        title='Open course link'
                      >
                        <ExternalLink className='h-5 w-5' />
                      </a>
                    )}
                  </div>
                </CardHeader>

                <CardContent className='space-y-4'>
                  {/* Course Image */}
                  <div className='aspect-video bg-gray-100 rounded-lg overflow-hidden'>
                    {course.thumbnail_url ? (
                      <img
                        src={course.thumbnail_url}
                        alt={course.name}
                        className='w-full h-full object-cover group-hover:scale-105 transition-transform duration-300'
                      />
                    ) : (
                      <div className='w-full h-full flex items-center justify-center'>
                        <BookOpen className='h-12 w-12 text-gray-400' />
                      </div>
                    )}
                  </div>

                  {/* Description */}
                  {course.description && (
                    <p className='text-sm text-gray-600 line-clamp-3'>
                      {course.description}
                    </p>
                  )}

                  {/* Course Details */}
                  <div className='space-y-2'>
                    {course.credit_hours && (
                      <div className='flex items-center gap-2 text-sm text-gray-600'>
                        <Award className='h-4 w-4' />
                        <span>{course.credit_hours} credit hours</span>
                      </div>
                    )}

                    {course.deadline && (
                      <div className='flex items-center gap-2 text-sm text-gray-600'>
                        <Calendar className='h-4 w-4' />
                        <span>Deadline: {formatDate(course.deadline)}</span>
                      </div>
                    )}

                    <div className='flex items-center gap-2 text-sm text-gray-600'>
                      <Clock className='h-4 w-4' />
                      <span>Assigned: {formatDate(course.created_at)}</span>
                    </div>
                  </div>

                  {/* Tags */}
                  {course.tags && course.tags.length > 0 && (
                    <div className='flex flex-wrap gap-1'>
                      {course.tags.map((tag, index) => (
                        <Badge
                          key={index}
                          variant='secondary'
                          className='text-xs'
                        >
                          {tag}
                        </Badge>
                      ))}
                    </div>
                  )}

                  {/* Action Button */}
                  {course.external_link && (
                    <a
                      href={course.external_link}
                      target='_blank'
                      rel='noopener noreferrer'
                      className='w-full inline-flex items-center justify-center gap-2 px-4 py-2 bg-primary text-primary-foreground rounded-md hover:bg-primary/90 transition-colors'
                    >
                      <ExternalLink className='h-4 w-4' />
                      Open Course
                    </a>
                  )}
                </CardContent>
              </Card>
            ))}
          </div>
        )}

        {/* Summary */}
        {courses.length > 0 && (
          <div className='mt-8 text-center'>
            <p className='text-gray-600'>
              Showing {courses.length} assigned course
              {courses.length !== 1 ? 's' : ''}
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudentCourses;

import React, { useEffect, useMemo, useState } from 'react';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import GoalForm from '@/components/goals/GoalForm';
import GoalCard from '@/components/goals/GoalCard';
import GoalDetailPanel from '@/components/goals/GoalDetailPanel';
import type { Goal } from '@/components/goals/types';

const LOCAL_STORAGE_KEY = 'student_goals_v2';

function clamp(v: number, a: number, b: number) {
  return Math.max(a, Math.min(b, v));
}

const StudentGoals: React.FC = () => {
  const { toast } = useToast();
  const [goals, setGoals] = useState<Goal[]>([]);
  const [openForm, setOpenForm] = useState(false);
  const [editing, setEditing] = useState<Goal | null>(null);
  const [detail, setDetail] = useState<Goal | null>(null);

  useEffect(() => {
    try {
      const raw = localStorage.getItem(LOCAL_STORAGE_KEY);
      if (raw) setGoals(JSON.parse(raw));
    } catch (err) {
      /* ignore */
    }
  }, []);
  useEffect(() => {
    try {
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(goals));
    } catch (err) {
      /* ignore */
    }
  }, [goals]);

  const completionRate = useMemo(() => {
    if (!goals.length) return 0;
    const sum = goals.reduce(
      (a, g) => a + Math.round((g.progress / Math.max(1, g.target)) * 100),
      0
    );
    return Math.round(sum / goals.length);
  }, [goals]);

  const upsertGoal = (g: Goal) => {
    setGoals(prev => {
      const idx = prev.findIndex(x => x.id === g.id);
      const next =
        idx >= 0
          ? [...prev.slice(0, idx), g, ...prev.slice(idx + 1)]
          : [g, ...prev];
      return next;
    });
    toast({ title: editing ? 'Goal updated' : 'Goal saved' });
    setEditing(null);
  };

  const bump = (id: string, delta: number) => {
    setGoals(prev =>
      prev.map(g =>
        g.id === id
          ? {
              ...g,
              progress: clamp(g.progress + delta, 0, g.target),
              activity: [
                ...(g.activity || []),
                { t: Date.now(), v: clamp(g.progress + delta, 0, g.target) },
              ],
              updatedAt: Date.now(),
            }
          : g
      )
    );
  };
  const complete = (id: string) => {
    setGoals(prev =>
      prev.map(g =>
        g.id === id
          ? { ...g, progress: g.target, completed: true, updatedAt: Date.now() }
          : g
      )
    );
    toast({ title: 'Goal completed Γ£à' });
  };
  const togglePause = (id: string) => {
    setGoals(prev =>
      prev.map(g =>
        g.id === id
          ? {
              ...g,
              paused: !g.paused,
              syncStatus: !g.paused ? 'paused' : 'idle',
              updatedAt: Date.now(),
            }
          : g
      )
    );
  };
  const syncNow = (id: string) => {
    setGoals(prev =>
      prev.map(g => (g.id === id ? { ...g, syncStatus: 'syncing' } : g))
    );
    setTimeout(() => {
      setGoals(prev =>
        prev.map(g => {
          if (g.id !== id) return g;
          const inc = Math.max(0, Math.round(g.target * 0.02));
          const nextVal = clamp(g.progress + inc, 0, g.target);
          return {
            ...g,
            progress: nextVal,
            lastSyncAt: Date.now(),
            syncStatus: 'success',
            activity: [...(g.activity || []), { t: Date.now(), v: nextVal }],
            updatedAt: Date.now(),
            completed: nextVal >= g.target || g.completed,
          };
        })
      );
    }, 800);
  };

  return (
    <div className='min-h-[calc(100vh-4rem)] w-full bg-gradient-to-b from-sky-50 via-indigo-50 to-indigo-100/60'>
      <div className='container py-10'>
        <div className='rounded-3xl bg-gradient-to-r from-sky-400 via-indigo-500 to-indigo-600 p-[1px] shadow-xl'>
          <div className='rounded-3xl bg-white/80 backdrop-blur px-6 py-10 sm:px-10'>
            <div className='flex flex-col gap-6 sm:flex-row sm:items-end sm:justify-between'>
              <div>
                <h1 className='text-3xl sm:text-4xl font-extrabold tracking-tight text-gray-900'>
                  <span className='mr-2'>∩┐╜∩┐╜∩┐╜</span> My Goals
                </h1>
                <p className='mt-2 text-gray-600'>
                  Create time-bound goals linked to coding platforms. Track
                  progress and stay on pace.
                </p>
              </div>
              <div className='flex items-center gap-3 text-sm text-gray-700'>
                <div className='flex items-center gap-2 rounded-full bg-white/70 px-4 py-2 shadow-sm'>
                  <span className='text-indigo-600'>≡ƒÄ»</span>
                  <span>Total: {goals.length}</span>
                </div>
                <div className='flex items-center gap-2 rounded-full bg-white/70 px-4 py-2 shadow-sm'>
                  <span className='text-emerald-600'>Γ£à</span>
                  <span>Completion: {completionRate}%</span>
                </div>
              </div>
            </div>
            <div className='mt-6 flex flex-wrap gap-3'>
              <Button
                onClick={() => {
                  setEditing(null);
                  setOpenForm(true);
                }}
                className='h-11 rounded-full bg-indigo-600 hover:bg-indigo-600/90 shadow-lg'
              >
                Create Goal
              </Button>
              <Button variant='secondary' className='h-11 rounded-full' asChild>
                <a href='/integrations'>Integrations</a>
              </Button>
            </div>
          </div>
        </div>

        <div className='mt-10 grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3'>
          {goals.length === 0 && (
            <div className='col-span-full text-center text-sm text-muted-foreground'>
              No goals yet. Create your first goal.
            </div>
          )}
          {goals.map(g => (
            <GoalCard
              key={g.id}
              goal={g}
              onBump={bump}
              onComplete={complete}
              onTogglePause={togglePause}
              onEdit={gg => {
                setEditing(gg);
                setOpenForm(true);
              }}
              onOpenDetail={gg => setDetail(gg)}
            />
          ))}
        </div>

        <GoalForm
          open={openForm}
          onOpenChange={v => {
            setOpenForm(v);
            if (!v) setEditing(null);
          }}
          initial={editing ?? undefined}
          onSave={upsertGoal}
        />
        <GoalDetailPanel
          goal={detail}
          onOpenChange={v => {
            if (!v) setDetail(null);
          }}
          onSyncNow={syncNow}
        />
      </div>
    </div>
  );
};

