                <div className='grid grid-cols-1 md:grid-cols-2 gap-4'>
                  <div>
                    <p className='text-sm font-medium text-gray-700'>
                      Issuer Name
                    </p>
                    <p className='text-gray-900'>
                      {verificationResult.issuer.name}
