            {/* Errors */}
            {verificationResult.errors &&
              verificationResult.errors.length > 0 && (
                <div>
                  <h3 className='text-lg font-semibold text-red-900 mb-3 flex items-center'>
                    <AlertTriangle className='h-5 w-5 mr-2' />
                    Verification Errors
