    department?: string;
    status?: string;
    graduation_year?: number;
    limit?: number;
    offset?: number;
  }): Promise<StudentData[]> {
    try {
      let query = supabase.from('profiles').select('*').eq('role', 'student');

      if (filters?.department) {
        query = query.eq('department', filters.department);
      }
      if (filters?.status) {
