          );

          if (!existingCourse) {
            // Create new course in SIH2
            // This would need to be implemented in the service
            console.log('Would create course:', courseData);
          }

          success++;
        } catch (error) {
          console.error(`Failed to sync course ${course.shortname}:`, error);
          failed++;
        }
      }

      return { success, failed };
