}

// Env-configurable proxy base for platforms that require server-side fetching
const PLATFORM_API_BASE: string =
  (import.meta as any)?.env?.VITE_PLATFORM_API_BASE || '';

// Optional API keys (if your proxy expects them)
const API_KEY: string | undefined = (import.meta as any)?.env
  ?.VITE_PLATFORM_API_KEY;
const GFG_KEY: string | undefined = (import.meta as any)?.env?.VITE_GFG_API_KEY;
const HACKERRANK_KEY: string | undefined = (import.meta as any)?.env
  ?.VITE_HACKERRANK_API_KEY;
const HACKEREARTH_KEY: string | undefined = (import.meta as any)?.env
  ?.VITE_HACKEREARTH_API_KEY;
const CODECHEF_KEY: string | undefined = (import.meta as any)?.env
  ?.VITE_CODECHEF_API_KEY;

// Simple CORS bypass services
const CORS_BYPASS_SERVICES = [
  'https://api.allorigins.win/raw?url=',
  'https://cors-anywhere.herokuapp.com/',
  'https://api.codetabs.com/v1/proxy?quest=',
  'https://thingproxy.freeboard.io/fetch/',
];

function buildHeaders(extra?: Record<string, string>) {
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
  };
  if (API_KEY) headers['x-api-key'] = API_KEY;
  if (extra) Object.assign(headers, extra);
  return headers;
}

// Simple and effective CORS bypass function
async function scrapeProfile(url: string): Promise<string | null> {
  const proxies = [
    'https://api.allorigins.win/raw?url=',
    'https://cors-anywhere.herokuapp.com/',
    'https://api.codetabs.com/v1/proxy?quest=',
    'https://thingproxy.freeboard.io/fetch/',
  ];

  for (const proxy of proxies) {
    try {
      console.log(`Trying proxy: ${proxy}`);
      const response = await fetch(`${proxy}${encodeURIComponent(url)}`, {
        headers: {
          'User-Agent':
            'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        },
      });

      if (response.ok) {
        const html = await response.text();
        if (html && html.length > 100) {
          console.log(
            `Successfully scraped with ${proxy} - HTML length: ${html.length}`
          );
          return html;
        }
      }
    } catch (error) {
      console.log(`Proxy ${proxy} failed:`, error.message);
      continue;
    }
  }

  console.log('All CORS bypass methods failed');
  return null;
}

async function fetchFromProxy<T>(
  path: string,
  keyName?: 'gfg' | 'hackerrank' | 'hackerearth' | 'codechef'
): Promise<T> {
  if (!PLATFORM_API_BASE) {
    // No proxy configured
    throw new Error(
      'Platform proxy base is not configured (VITE_PLATFORM_API_BASE).'
    );
  }
  const keyHeader: Record<string, string> = {};
  if (keyName === 'gfg' && GFG_KEY) keyHeader['x-gfg-key'] = GFG_KEY;
  if (keyName === 'hackerrank' && HACKERRANK_KEY)
    keyHeader['x-hackerrank-key'] = HACKERRANK_KEY;
  if (keyName === 'hackerearth' && HACKEREARTH_KEY)
    keyHeader['x-hackerearth-key'] = HACKEREARTH_KEY;
  if (keyName === 'codechef' && CODECHEF_KEY)
    keyHeader['x-codechef-key'] = CODECHEF_KEY;

  const res = await fetch(`${PLATFORM_API_BASE}${path}`, {
    headers: buildHeaders(keyHeader),
    method: 'GET',
  });
  if (!res.ok) {
    const text = await res.text().catch(() => '');
    throw new Error(`Proxy ${path} responded ${res.status} ${text}`);
  }
  return res.json();
}

