      rank,
      score,
      languages: languages.length,
      totalAuthored,
      totalCompleted,
      leaderboardPosition: json.leaderboardPosition || 0,
    };
  } catch (err) {
    console.error('Network error fetching Codewars data for', studentId, err);
    return { solved: 0, hours: 0, courses: 0, contests: 0, rating: 0 };
  }
}

