  /**
   * Log an action to audit logs
   */
  private async logAction(
    action: string,
    userId: string | null,
    vcId: string | null,
    issuerId: string | null,
    details: any
  ): Promise<void> {
    try {
      // Only log if we have valid data
      if (!action) {
        console.warn('Cannot log action: action is required');
        return;
      }

      const logData: any = {
        action,
        details: details || {},
      };

      // Only include IDs if they are valid UUIDs and exist in their respective tables
      if (userId && this.isValidUUID(userId)) {
        // Check if user exists in profiles table
        const { data: userExists } = await supabase
          .from('profiles')
          .select('id')
          .eq('id', userId)
          .single();

        if (userExists) {
          logData.user_id = userId;
        }
      }
      if (vcId && this.isValidUUID(vcId)) {
        // Check if VC exists in verifiable_credentials table
        const { data: vcExists } = await supabase
          .from('verifiable_credentials')
          .select('id')
          .eq('id', vcId)
          .single();

        if (vcExists) {
          logData.vc_id = vcId;
        }
      }
      if (issuerId && this.isValidUUID(issuerId)) {
        // Check if issuer exists in issuers table
        const { data: issuerExists } = await supabase
          .from('issuers')
          .select('id')
          .eq('id', issuerId)
          .single();

        if (issuerExists) {
          logData.issuer_id = issuerId;
        }
      }

      const { error } = await supabase.from('audit_logs').insert(logData);

      if (error) {
        console.warn('Failed to insert audit log:', error);
        // Don't throw - this is non-critical
      }
    } catch (error) {
      console.warn('Error logging action (non-critical):', error);
      // Don't throw - this is non-critical
    }
  }

  /**
   * Check if a string is a valid UUID
   */
  private isValidUUID(str: string): boolean {
    const uuidRegex =
      /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
    return uuidRegex.test(str);
  }
}

